import React, { useContext, useState, useRef, useEffect } from 'react';
import { AppContext } from '../../contexts/AppContext';
import { useTranslation } from '../../contexts/I18nContext';
import { useUI } from '../../contexts/UIContext';
import { 
    XMarkIcon, 
    BoltIcon, 
    BanknotesIcon, 
    UserIcon, 
    TrashIcon,
    CheckCircleIcon,
    ArrowUturnLeftIcon,
    ArrowPathIcon,
    CloudArrowUpIcon,
    PlusCircleIcon,
    UploadIcon,
    EnvelopeIcon,
    EllipsisVerticalIcon
} from '../Icons';
import { FileUploader, FileUploaderHandle } from '../FileUploader';
import { GmailModal } from '../../features/gmail/GmailModal';
import { processFileContent } from '../../services/processingService';
import { consolidationService } from '../../services/ConsolidationService';
import { Transaction } from '../../types';
import { useAuth } from '../../contexts/AuthContext';

// --- SUB-COMPONENT: BANK ROW (LISTA VIVA MANAGER) ---

const BankRow: React.FC<{ 
    bank: any, 
    isUploaded: boolean, 
    handleStatementUpload: any, 
    setIsGmailModalOpen: any, 
    removeBankStatementFile: any,
    triggerUpdate: () => void 
}> = ({ bank, isUploaded, handleStatementUpload, setIsGmailModalOpen, removeBankStatementFile, triggerUpdate }) => {

    // CONTEXT ACCESS FOR APPEND LOGIC
    const { fileModels, effectiveIgnoreKeywords, bankStatementFile, setBankStatementFile } = useContext(AppContext);
    const { user } = useAuth();
    const { showToast } = useUI();

    const [menuOpen, setMenuOpen] = useState(false);
    const [isUploading, setIsUploading] = useState(false);
    const uploaderRef = useRef<FileUploaderHandle>(null);
    const menuRef = useRef<HTMLDivElement>(null);

    // Garante acesso à versão mais recente da função de update para evitar stale closures
    const triggerUpdateRef = useRef(triggerUpdate);
    useEffect(() => {
        triggerUpdateRef.current = triggerUpdate;
    }, [triggerUpdate]);

    // Controla o modo do upload: 'replace' (substituir) ou 'append' (adicionar)
    const uploadModeRef = useRef<'replace' | 'append'>('replace');

    // Fecha menu ao clicar fora
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setMenuOpen(false);
            }
        };
        if (menuOpen) document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [menuOpen]);

    const closeMenu = () => setMenuOpen(false);

    // LOGICA DE APPEND MANUAL (Sincronizada com DB)
    const handleAppend = async (content: string, fileName: string, rawFile: File) => {
        setIsUploading(true);
        try {
            // 1. Processa o novo arquivo
            const result = processFileContent(content, fileName, fileModels, effectiveIgnoreKeywords);
            const newTransactions = result.transactions;

            if (newTransactions.length === 0) {
                showToast("Nenhuma transação válida encontrada no arquivo.", "error");
                setIsUploading(false);
                return;
            }

            // 2. Persistência (Consolidação) - PRIORIDADE 1
            // Inserimos no banco PRIMEIRO para garantir que a lista viva (triggerUpdate) pegue os dados reais
            if (user) {
                const consolidationData = newTransactions.map(t => ({
                    transaction_date: t.date,
                    amount: t.amount,
                    description: t.description,
                    type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                    pix_key: null,
                    source: 'file' as 'file',
                    user_id: user.id
                }));

                // Aguarda a inserção para garantir integridade
                await consolidationService.addTransactions(consolidationData);
            }

            // 3. Atualiza Estado Global (Visual) - PRIORIDADE 2
            // Mesclamos localmente apenas para feedback imediato caso o triggerUpdate demore
            const currentTransactions = bankStatementFile?.processedTransactions || [];

            // Deduplicação visual simples
            const existingSignatures = new Set(currentTransactions.map(t => `${t.date}|${t.amount}|${t.description}`));
            const uniqueNewTransactions = newTransactions.filter(t => !existingSignatures.has(`${t.date}|${t.amount}|${t.description}`));

            const mergedTransactions = [...currentTransactions, ...uniqueNewTransactions];

            setBankStatementFile({
                bankId: bank.id,
                content: (bankStatementFile?.content || '') + '\n' + content,
                fileName: bankStatementFile?.fileName ? `${bankStatementFile.fileName} + ${fileName}` : fileName,
                rawFile: rawFile,
                processedTransactions: mergedTransactions
            });

            showToast(`${uniqueNewTransactions.length} novas transações adicionadas!`, "success");

            // 4. Dispara atualização da Lista Viva (Re-fetch do banco)
            setTimeout(() => {
                triggerUpdateRef.current();
            }, 800);

        } catch (e: any) {
            console.error(e);
            showToast("Erro ao adicionar arquivo: " + e.message, "error");
        } finally {
            setIsUploading(false);
        }
    };

    const handleFileUploadWrapper = async (content: string, fileName: string, rawFile: File) => {
        if (uploadModeRef.current === 'replace') {
            setIsUploading(true);
            handleStatementUpload(content, fileName, bank.id, rawFile);

            // Aguarda propagação do estado e banco antes de atualizar a lista visual
            setTimeout(() => {
                triggerUpdateRef.current();
                setIsUploading(false);
            }, 1000);
        } else {
            await handleAppend(content, fileName, rawFile);
        }
        closeMenu();
    };

    const triggerUpload = (mode: 'replace' | 'append') => {
        uploadModeRef.current = mode;
        uploaderRef.current?.open();
        closeMenu();
    };

    return (
        <div className={`p-3 rounded-2xl border transition-all duration-200 flex items-center justify-between gap-3 relative group ${isUploaded ? 'bg-emerald-50/50 border-emerald-200 dark:bg-emerald-900/10 dark:border-emerald-800' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700'}`}>

            {/* Hidden Uploader Component */}
            <div className="hidden">
                <FileUploader 
                    ref={uploaderRef}
                    id={`update-bank-${bank.id}`}
                    title="Upload Hidden"
                    onFileUpload={handleFileUploadWrapper}
                    isUploaded={false}
                    uploadedFileName={null}
                    onParsingStatusChange={setIsUploading}
                />
            </div>

            <div className="flex flex-col min-w-0">
                <span className="font-bold text-xs text-slate-800 dark:text-slate-200 truncate">{bank.name}</span>
                {isUploaded ? (
                    <span className="flex items-center gap-1 text-[10px] text-emerald-600 dark:text-emerald-400 font-medium">
                        <CheckCircleIcon className="w-3 h-3" /> Lista Viva Ativa
                    </span>
                ) : (
                    <span className="text-[10px] text-slate-400 italic">Nenhum extrato vinculado</span>
                )}
            </div>

            <div className="relative" ref={menuRef}>
                {isUploading ? (
                    <div className="p-2">
                        <svg className="animate-spin h-5 w-5 text-blue-500" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    </div>
                ) : (
                    <button 
                        onClick={() => setMenuOpen(!menuOpen)}
                        className={`
                            p-2 rounded-full transition-all duration-200 border relative z-10
                            ${menuOpen 
                                ? 'bg-blue-50 dark:bg-slate-700 text-brand-blue border-blue-200 dark:border-blue-700 shadow-md ring-2 ring-blue-100 dark:ring-blue-900/30' 
                                : 'bg-white dark:bg-slate-800 text-slate-400 hover:text-brand-blue border-slate-200 dark:border-slate-700 hover:border-blue-300 dark:hover:border-blue-600 hover:shadow-sm'
                            }
                        `}
                        title="Opções do Extrato"
                    >
                        {isUploaded ? <EllipsisVerticalIcon className="w-5 h-5 stroke-[1.5]" /> : <CloudArrowUpIcon className="w-5 h-5 stroke-[1.5]" />}
                    </button>
                )}

                {/* Context Menu (Dropdown) */}
                {menuOpen && (
                    <div className="absolute right-0 top-full mt-2 z-50 w-56 bg-white dark:bg-slate-800 rounded-xl shadow-xl border border-slate-100 dark:border-slate-700 overflow-hidden animate-scale-in origin-top-right ring-1 ring-black/5">
                        <div className="flex flex-col py-1">

                            {/* ADICIONAR (APPEND) */}
                            <button 
                                onClick={() => triggerUpload('append')}
                                className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700/50 w-full text-left transition-colors group/item"
                            >
                                <div className="p-1.5 bg-blue-50 dark:bg-blue-900/20 rounded-lg text-blue-500 group-hover/item:text-blue-600">
                                    <PlusCircleIcon className="w-3.5 h-3.5" />
                                </div>
                                <div>
                                    <span className="block">Adicionar arquivo</span>
                                    <span className="text-[9px] font-normal text-slate-400">Somar à lista atual</span>
                                </div>
                            </button>

                            {/* SUBSTITUIR (REPLACE) */}
                            <button 
                                onClick={() => triggerUpload('replace')}
                                className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700/50 w-full text-left transition-colors group/item"
                            >
                                <div className="p-1.5 bg-amber-50 dark:bg-amber-900/20 rounded-lg text-amber-500 group-hover/item:text-amber-600">
                                    <ArrowPathIcon className="w-3.5 h-3.5" />
                                </div>
                                <div>
                                    <span className="block">Substituir tudo</span>
                                    <span className="text-[9px] font-normal text-slate-400">Trocar lista atual</span>
                                </div>
                            </button>

                            {/* GMAIL */}
                            <button 
                                onClick={() => { setIsGmailModalOpen(true); closeMenu(); }}
                                className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700/50 w-full text-left transition-colors group/item"
                            >
                                <div className="p-1.5 bg-red-50 dark:bg-red-900/20 rounded-lg text-red-500 group-hover/item:text-red-600">
                                    <EnvelopeIcon className="w-3.5 h-3.5" />
                                </div>
                                <div>
                                    <span className="block">Importar Gmail</span>
                                    <span className="text-[9px] font-normal text-slate-400">Buscar comprovantes</span>
                                </div>
                            </button>

                            <div className="h-px bg-slate-100 dark:bg-slate-700 my-1 mx-4"></div>

                            {/* EXCLUIR */}
                            <button 
                                onClick={() => { if(isUploaded) removeBankStatementFile(); closeMenu(); }}
                                disabled={!isUploaded}
                                className={`flex items-center gap-3 px-4 py-2.5 text-xs font-bold w-full text-left transition-colors group/item ${!isUploaded ? 'opacity-50 cursor-not-allowed text-slate-400' : 'text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20'}`}
                            >
                                <div className={`p-1.5 rounded-lg ${!isUploaded ? 'bg-slate-100' : 'bg-red-50 dark:bg-red-900/20 text-red-500'}`}>
                                    <TrashIcon className="w-3.5 h-3.5" />
                                </div>
                                <span>Remover extrato</span>
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

export const UpdateReportFilesModal: React.FC = () => {
    const { 
        isUpdateFilesModalOpen, 
        closeUpdateFilesModal,
        banks, 
        churches,
        bankStatementFile,
        contributorFiles,
        handleStatementUpload,
        handleContributorsUpload,
        removeBankStatementFile,
        removeContributorFile,
        handleCompare
    } = useContext(AppContext);

    // Garante acesso à versão atualizada do handleCompare
    const handleCompareRef = useRef(handleCompare);
    useEffect(() => {
        handleCompareRef.current = handleCompare;
    }, [handleCompare]);

    const { t } = useTranslation();
    const { showToast } = useUI();
    const [isProcessing, setIsProcessing] = useState(false);
    const [isGmailModalOpen, setIsGmailModalOpen] = useState(false);

    if (!isUpdateFilesModalOpen) return null;

    const handleRun = async () => {
        setIsProcessing(true);
        try {
            await handleCompare();
            showToast("Relatório atualizado com os novos dados.", "success");
            closeUpdateFilesModal();
        } catch (error) {
            console.error(error);
        } finally {
            setIsProcessing(false);
        }
    };

    const handleGmailSuccess = (csvContent: string) => {
        // Para o Gmail, criamos um arquivo virtual
        const virtualFile = new File([csvContent], "gmail_import.csv", { type: "text/csv" });
        handleStatementUpload(
            csvContent, 
            `Gmail Import - ${new Date().toLocaleDateString()}`, 
            'gmail-virtual-bank', 
            virtualFile
        );

        // Atualiza lista viva após importação do Gmail
        setTimeout(() => {
            handleCompareRef.current();
        }, 1000);
    };

    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-50 flex items-center justify-center p-4 animate-fade-in">
            <div className="bg-white dark:bg-slate-800 rounded-[2rem] shadow-2xl w-full max-w-4xl border border-slate-200 dark:border-slate-700 animate-scale-in overflow-hidden flex flex-col max-h-[90vh]">

                {/* Header */}
                <div className="px-8 py-6 border-b border-slate-100 dark:border-slate-700 flex justify-between items-center bg-slate-50/50 dark:bg-slate-900/30">
                    <div className="flex items-center gap-3">
                        <div className="p-2.5 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-xl text-white shadow-lg shadow-purple-500/30">
                            <BoltIcon className="w-5 h-5" />
                        </div>
                        <div>
                            <h3 className="text-xl font-black text-slate-800 dark:text-white tracking-tight">Gerenciar Fontes de Dados</h3>
                            <p className="text-xs text-slate-500 dark:text-slate-400 font-medium">Adicione ou substitua arquivos para atualizar este relatório.</p>
                        </div>
                    </div>
                    <button type="button" onClick={closeUpdateFilesModal} className="p-2 rounded-full hover:bg-slate-100 dark:hover:bg-slate-700 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200 transition-colors">
                        <XMarkIcon className="w-5 h-5" />
                    </button>
                </div>

                {/* Body - Split View */}
                <div className="flex-1 overflow-hidden flex flex-col md:flex-row bg-slate-50/20 dark:bg-slate-900/10">

                    {/* Column 1: Bank Statement (Lista Viva) */}
                    <div className="flex-1 flex flex-col border-b md:border-b-0 md:border-r border-slate-100 dark:border-slate-700 p-6 overflow-y-auto custom-scrollbar">
                        <div className="flex items-center gap-2 mb-4 text-brand-blue dark:text-blue-400">
                            <BanknotesIcon className="w-5 h-5" />
                            <h4 className="font-bold text-sm uppercase tracking-wide">Banco (Lista Viva)</h4>
                        </div>

                        <div className="space-y-3">
                            {banks.length === 0 ? (
                                <p className="text-xs text-slate-400 italic">Nenhum banco cadastrado.</p>
                            ) : (
                                banks.map(bank => {
                                    const isUploaded = bankStatementFile?.bankId === bank.id;
                                    return (
                                        <BankRow 
                                            key={bank.id}
                                            bank={bank}
                                            isUploaded={isUploaded}
                                            handleStatementUpload={handleStatementUpload}
                                            setIsGmailModalOpen={setIsGmailModalOpen}
                                            removeBankStatementFile={removeBankStatementFile}
                                            triggerUpdate={handleCompare}
                                        />
                                    )
                                })
                            )}
                        </div>
                    </div>

                    {/* Column 2: Contributors (Listas de Membros) */}
                    <div className="flex-1 flex flex-col p-6 overflow-y-auto custom-scrollbar">
                        <div className="flex items-center gap-2 mb-4 text-brand-teal dark:text-teal-400">
                            <UserIcon className="w-5 h-5" />
                            <h4 className="font-bold text-sm uppercase tracking-wide">Listas de Membros</h4>
                        </div>

                        <div className="space-y-3">
                            {churches.length === 0 ? (
                                <p className="text-xs text-slate-400 italic">Nenhuma igreja cadastrada.</p>
                            ) : (
                                churches.map(church => {
                                    const uploadedFile = contributorFiles.find(f => f.churchId === church.id);
                                    const isUploaded = !!uploadedFile;

                                    return (
                                        <div key={church.id} className={`p-3 rounded-2xl border transition-all duration-200 flex items-center justify-between gap-3 ${isUploaded ? 'bg-indigo-50/50 border-indigo-200 dark:bg-indigo-900/10 dark:border-indigo-800' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700'}`}>
                                            <div className="flex items-center gap-2 min-w-0">
                                                {church.logoUrl && <img src={church.logoUrl} alt="" className="w-5 h-5 rounded object-cover shadow-sm" />}
                                                <div className="flex flex-col min-w-0">
                                                    <span className="font-bold text-xs text-slate-800 dark:text-slate-200 truncate">{church.name}</span>
                                                    {isUploaded && (
                                                        <span className="flex items-center gap-1 text-[10px] text-indigo-600 dark:text-indigo-400 font-medium">
                                                            <CheckCircleIcon className="w-3 h-3" /> Lista carregada
                                                        </span>
                                                    )}
                                                </div>
                                            </div>

                                            <div className="flex items-center gap-1.5 flex-shrink-0">
                                                <FileUploader 
                                                    id={`update-church-${church.id}`}
                                                    title={isUploaded ? "Trocar" : "Carregar"}
                                                    onFileUpload={(content, fileName, rawFile) => handleContributorsUpload(content, fileName, church.id, rawFile)}
                                                    isUploaded={false} // Force render button
                                                    uploadedFileName={null}
                                                />
                                                {isUploaded && (
                                                    <button 
                                                        onClick={() => removeContributorFile(church.id)} 
                                                        className="group flex items-center justify-center w-7 h-7 rounded-full bg-slate-100 hover:bg-red-50 border border-slate-200 hover:border-red-100 dark:bg-slate-700 dark:border-slate-600 text-slate-400 hover:text-red-500 transition-all active:scale-95"
                                                        title="Excluir lista"
                                                    >
                                                        <TrashIcon className="w-3.5 h-3.5" />
                                                    </button>
                                                )}
                                            </div>
                                        </div>
                                    )
                                })
                            )}
                        </div>
                    </div>
                </div>

                {/* Footer */}
                <div className="px-8 py-5 border-t border-slate-100 dark:border-slate-700 flex justify-end gap-3 bg-white dark:bg-slate-800">
                    <button type="button" onClick={closeUpdateFilesModal} className="px-6 py-2.5 text-xs font-bold rounded-full border border-slate-300 dark:border-slate-600 text-slate-600 dark:text-slate-300 hover:bg-white dark:hover:bg-slate-800 hover:shadow-sm transition-all uppercase tracking-wide">
                        {t('common.cancel')}
                    </button>
                    <button 
                        type="button" 
                        onClick={handleRun} 
                        disabled={isProcessing}
                        className="flex items-center gap-2 px-8 py-2.5 text-xs font-bold text-white bg-gradient-to-r from-emerald-600 to-teal-600 hover:from-emerald-700 hover:to-teal-700 rounded-full shadow-lg shadow-emerald-500/30 hover:-translate-y-0.5 transition-all uppercase tracking-wide disabled:opacity-70 disabled:cursor-not-allowed"
                    >
                        {isProcessing ? (
                            <>
                                <svg className="animate-spin h-3.5 w-3.5 text-white" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                                Processando...
                            </>
                        ) : (
                            <>
                                <ArrowUturnLeftIcon className="w-3.5 h-3.5" />
                                Processar Alterações
                            </>
                        )}
                    </button>
                </div>
            </div>

            {/* Gmail Sync Modal */}
            {isGmailModalOpen && (
                <GmailModal 
                    onClose={() => setIsGmailModalOpen(false)} 
                    onSuccess={handleGmailSuccess} 
                />
            )}
        </div>
    );
};

import { useState, useCallback, useMemo } from 'react';
import { usePersistentState } from './usePersistentState';
import { 
    Transaction, 
    Contributor, 
    MatchResult, 
    Church, 
    Bank, 
    FileModel, 
    GroupedReportData, 
    ComparisonType,
    ViewType,
    LearnedAssociation
} from '../types';
import { 
    matchTransactions, 
    groupResultsByChurch, 
    PLACEHOLDER_CHURCH,
    normalizeString,
    processFileContent
} from '../services/processingService';
import { User } from '@supabase/supabase-js';
import { consolidationService } from '../services/ConsolidationService';

interface UseReconciliationProps {
    user: User | null; // Adicionado User
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: LearnedAssociation[];
    showToast: (msg: string, type?: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: ViewType) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    // Cria um sufixo único baseado no ID do usuário para isolar os dados no LocalStorage/IndexedDB
    const userSuffix = user ? `-${user.id}` : '-guest';

    const [bankStatementFile, setBankStatementFile] = usePersistentState<{ 
        bankId: string, 
        content: string, 
        fileName: string, 
        rawFile?: File,
        processedTransactions?: Transaction[]
    } | null>(`identificapix-statement-v7${userSuffix}`, null, true);

    const [contributorFiles, setContributorFiles] = usePersistentState<{ churchId: string; content: string; fileName: string, contributors?: Contributor[] }[]>(`identificapix-contributors-v6${userSuffix}`, [], true);
    const [matchResults, setMatchResults] = usePersistentState<MatchResult[]>(`identificapix-results-v6${userSuffix}`, [], true);
    const [reportPreviewData, setReportPreviewData] = usePersistentState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(`identificapix-report-preview-v6${userSuffix}`, null, true);
    const [hasActiveSession, setHasActiveSession] = usePersistentState<boolean>(`identificapix-has-session-v6${userSuffix}`, false, false);
    // NOVO: Rastreia se estamos editando um relatório já salvo
    const [activeReportId, setActiveReportId] = usePersistentState<string | null>(`identificapix-active-report-id${userSuffix}`, null, false);

    const [comparisonType, setComparisonType] = useState<ComparisonType>('both');

    const [pendingTraining, setPendingTraining] = useState<{ content: string; fileName: string; type: 'statement' | 'contributor'; entityId: string, rawFile?: File } | null>(null);

    // Manual Identification State
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[] | null>(null);
    const [manualMatchState, setManualMatchState] = useState<{ record: MatchResult, suggestions: Transaction[] } | null>(null);
    const [divergenceConfirmation, setDivergenceConfirmation] = useState<MatchResult | null>(null);
    const [loadingAiId, setLoadingAiId] = useState<string | null>(null);
    const [aiSuggestion, setAiSuggestion] = useState<{ id: string, name: string } | null>(null);

    // --- LÓGICA DE LIMPEZA UNIFICADA ---
    // Combina palavras ignoradas globais com os Tipos de Contribuição.
    // Isso garante que "Dízimo", "Oferta", etc., sejam removidos da coluna NOME,
    // mas a detecção de TIPO (que ocorre no raw description) continua funcionando.
    const cleaningKeywords = useMemo(() => {
        return Array.from(new Set([...customIgnoreKeywords, ...contributionKeywords]));
    }, [customIgnoreKeywords, contributionKeywords]);

    const handleStatementUpload = useCallback((content: string, fileName: string, bankId: string, rawFile: File) => {
        setIsLoading(true);
        try {
            // ESTRATÉGIA DIRETA: Usa a lista combinada para limpar descrições
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            if (transactions.length > 0) {
                setBankStatementFile({ 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile,
                    processedTransactions: transactions 
                });

                if (result.appliedModel) {
                    showToast("Um modelo de arquivo foi identificado automaticamente e aplicado com sucesso.", "success");
                } else {
                    showToast(`Extrato carregado (${result.method}).`, 'success');
                }

                // --- INTEGRATION: Consolidation Service ---
                if (user) {
                    const consolidationData = transactions.map(t => ({
                        transaction_date: t.date,
                        amount: t.amount,
                        description: t.description, // Raw description preferred for audit
                        type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                        pix_key: null, // Basic file upload typically does not parse PIX key separately yet
                        source: 'file' as 'file',
                        user_id: user.id
                    }));

                    // Fire and forget - Silent error handling (Avoid blocking UI if table is missing)
                    consolidationService.addTransactions(consolidationData)
                        .catch(err => console.warn("[Consolidation] Background sync skipped (DB Error/Offline):", err));
                }
                // ------------------------------------------

            } else {
                showToast("Formato de arquivo não reconhecido pelo sistema automático. Verifique se é um arquivo suportado.", "error");
            }
        } catch (e: any) {
            console.error(e);
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [setBankStatementFile, showToast, setIsLoading, fileModels, cleaningKeywords, user]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string, rawFile?: File) => {
        setIsLoading(true);
        try {
            // ESTRATÉGIA DIRETA: Usa a lista combinada para limpar nomes de contribuintes
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            const contributors: Contributor[] = transactions.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            if (contributors.length > 0) {
                setContributorFiles(prev => {
                    const other = prev.filter(f => f.churchId !== churchId);
                    return [...other, { churchId, content, fileName, contributors }];
                });

                if (result.appliedModel) {
                    showToast("Um modelo de arquivo foi identificado automaticamente e aplicado com sucesso.", "success");
                } else {
                    showToast(`Lista carregada (${result.method}).`, 'success');
                }
            } else {
                showToast("Formato de lista não reconhecido. Use CSV ou Excel padronizado.", "error");
            }
        } catch (e: any) {
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [cleaningKeywords, setContributorFiles, showToast, setIsLoading, fileModels]);

    const handleTrainingSuccess = useCallback((model: FileModel, processedData: Transaction[]) => {
        if (!pendingTraining) return;

        const { type, entityId, content, fileName, rawFile } = pendingTraining;

        if (type === 'statement') {
            setBankStatementFile({ 
                bankId: entityId, 
                content, 
                fileName, 
                rawFile,
                processedTransactions: processedData 
            });
            showToast("Extrato processado e salvo!", "success");

            // --- INTEGRATION: Consolidation Service (Training Flow) ---
            if (user && processedData.length > 0) {
                const consolidationData = processedData.map(t => ({
                    transaction_date: t.date,
                    amount: t.amount,
                    description: t.description,
                    type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                    pix_key: null,
                    source: 'file' as 'file',
                    user_id: user.id
                }));
                consolidationService.addTransactions(consolidationData)
                    .catch(err => console.warn("[Consolidation] Background sync skipped:", err));
            }
            // ---------------------------------------------------------

        } else {
            const contributors: Contributor[] = processedData.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            setContributorFiles(prev => {
                const other = prev.filter(f => f.churchId !== entityId);
                return [...other, { churchId: entityId, content, fileName, contributors }];
            });
            showToast("Lista de contribuintes salva!", "success");
        }

        setPendingTraining(null);
    }, [pendingTraining, cleaningKeywords, setBankStatementFile, setContributorFiles, showToast, user]);

    const openLabManually = useCallback((targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => {
        if (targetFile) {
            setPendingTraining({
                content: targetFile.content,
                fileName: targetFile.fileName,
                type: targetFile.type,
                entityId: targetFile.id,
                rawFile: targetFile.rawFile
            });
        } else if (bankStatementFile) {
            setPendingTraining({
                content: bankStatementFile.content,
                fileName: bankStatementFile.fileName,
                type: 'statement',
                entityId: bankStatementFile.bankId,
                rawFile: bankStatementFile.rawFile
            });
        } else {
            showToast("Carregue um arquivo primeiro.", "error");
        }
    }, [bankStatementFile, showToast]);

    const removeBankStatementFile = useCallback(() => setBankStatementFile(null), [setBankStatementFile]);
    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, [setContributorFiles]);

    // Limpa apenas os arquivos (usado ao abrir um relatório salvo para evitar estado sujo)
    const clearFiles = useCallback(() => {
        setBankStatementFile(null);
        setContributorFiles([]);
    }, [setBankStatementFile, setContributorFiles]);

    // Função para limpar tudo e iniciar nova conciliação
    const resetReconciliation = useCallback(() => {
        setBankStatementFile(null);
        setContributorFiles([]);
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null); // Limpa o ID do relatório ativo
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
        setManualMatchState(null);
        setDivergenceConfirmation(null);
        setAiSuggestion(null);
        showToast("Ambiente limpo para nova conciliação.", "success");
    }, [setBankStatementFile, setContributorFiles, setMatchResults, setReportPreviewData, setHasActiveSession, showToast, setActiveReportId]);

    // --- RECONCILIATION ENGINE JIT (Just-In-Time) ---
    const handleCompare = useCallback(async () => {
        if (!bankStatementFile && !activeReportId) return; // Bloqueio padrão

        setIsLoading(true);

        try {
            let activeTransactions: Transaction[] = [];

            // CENÁRIO A: Novo Extrato Carregado -> Processamento Completo do Zero com Persistência
            if (bankStatementFile) {
                const stmtResult = processFileContent(bankStatementFile.content, bankStatementFile.fileName, fileModels, cleaningKeywords);
                const rawTransactions = stmtResult.transactions;

                if (rawTransactions.length === 0) {
                    throw new Error("O extrato não gerou transações válidas. Verifique o arquivo.");
                }

                if (user) {
                    // ROBUST SYNC: Tenta sincronizar com o banco, mas faz fallback para local se falhar
                    try {
                        // 1. Sincroniza com a Base Consolidada (Garante que existam)
                        const consolidationData = rawTransactions.map(t => ({
                            transaction_date: t.date,
                            amount: t.amount,
                            description: t.description,
                            type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                            pix_key: null,
                            source: 'file' as 'file',
                            user_id: user.id
                        }));
                        await consolidationService.addTransactions(consolidationData);

                        // 2. Busca da Lista Viva (Autoritativa)
                        const dbTransactions = await consolidationService.getPendingTransactions(user.id);

                        activeTransactions = dbTransactions.map(dbTx => ({
                            id: dbTx.id, // ID REAL DO SUPABASE
                            date: dbTx.transaction_date,
                            amount: dbTx.amount,
                            description: dbTx.description,
                            cleanedDescription: dbTx.description, // Re-limpar se necessário, mas raw é seguro
                            contributionType: dbTx.type,
                            originalAmount: String(dbTx.amount)
                        }));
                    } catch (dbError) {
                        console.error("[Reconciliation] Falha crítica na sincronização com o banco. Ativando modo local.", dbError);
                        // FALLBACK: Usa os dados do arquivo local se o banco falhar (ex: tabela 404)
                        activeTransactions = rawTransactions;
                        showToast("Aviso: Sincronização em nuvem indisponível. Usando dados locais.", "error");
                    }
                } else {
                    activeTransactions = rawTransactions; // Modo Visitante (Sem IDs persistentes)
                }

                // Atualiza o arquivo com as transações processadas (com IDs reais ou locais)
                setBankStatementFile(prev => prev ? { ...prev, processedTransactions: activeTransactions } : null);
            } 
            // CENÁRIO B: Modo Aditivo (Sem novo extrato, apenas novas listas para o relatório ativo)
            else if (activeReportId && contributorFiles.length > 0) {
                activeTransactions = matchResults
                    .filter(r => r.status === 'NÃO IDENTIFICADO')
                    .map(r => r.transaction);
            }

            let filteredTransactions = activeTransactions;
            if (comparisonType === 'income') filteredTransactions = activeTransactions.filter(t => t.amount > 0);
            else if (comparisonType === 'expenses') filteredTransactions = activeTransactions.filter(t => t.amount < 0);

            // 2. Processamento das Listas de Contribuintes (Recém carregadas)
            const contributorData = contributorFiles.map(cf => {
                const church = churches.find(c => c.id === cf.churchId) || PLACEHOLDER_CHURCH;

                const listResult = processFileContent(cf.content, cf.fileName, fileModels, cleaningKeywords);
                const currentContributors = listResult.transactions.map(t => ({
                    name: t.description,
                    cleanedName: t.cleanedDescription,
                    normalizedName: normalizeString(t.description, cleaningKeywords),
                    amount: t.amount,
                    date: t.date,
                    originalAmount: t.originalAmount,
                    contributionType: t.contributionType
                }));

                return {
                    church,
                    contributors: currentContributors
                };
            });

            // 3. EXECUTAR O MATCHING
            const newResults = matchTransactions(
                filteredTransactions, 
                contributorData, 
                { similarityThreshold: similarityLevel, dayTolerance }, 
                learnedAssociations, 
                churches, 
                cleaningKeywords
            );

            // 4. PERSISTÊNCIA DE MATCHES AUTOMÁTICOS (CRÍTICO)
            if (user) {
                const autoMatches = newResults.filter(r => r.status === 'IDENTIFICADO' && r.transaction.id && !r.transaction.id.startsWith('ghost-'));
                if (autoMatches.length > 0) {
                    // Fire and forget, mas com catch para não quebrar UI
                    const updatePromises = autoMatches.map(m => 
                        consolidationService.markAsIdentified(m.transaction.id)
                            .catch(e => console.warn(`Falha ao persistir match automático ${m.transaction.id}`, e))
                    );
                    Promise.all(updatePromises).then(() => console.log(`[Consolidation] ${autoMatches.length} matches automáticos persistidos.`));
                }
            }

            // 5. ATUALIZAÇÃO DE ESTADO
            if (!bankStatementFile && activeReportId) {
                // Modo Aditivo: Mescla
                setMatchResults(prevResults => {
                    const finalResults = [...prevResults];
                    newResults.forEach(newRes => {
                        if (newRes.transaction.id && !newRes.transaction.id.startsWith('ghost-')) {
                            const index = finalResults.findIndex(r => r.transaction.id === newRes.transaction.id);
                            if (index !== -1) {
                                if (newRes.status === 'IDENTIFICADO') {
                                    finalResults[index] = newRes;
                                } else if (newRes.suggestion && !finalResults[index].suggestion) {
                                    finalResults[index] = newRes;
                                }
                            }
                        } else {
                            finalResults.push(newRes);
                        }
                    });

                    setReportPreviewData({
                        income: groupResultsByChurch(finalResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                        expenses: { 'all_expenses_group': finalResults.filter(r => r.transaction.amount < 0) }
                    });
                    return finalResults;
                });
                showToast("Novas listas processadas e adicionadas ao relatório!", 'success');
            } else {
                // Modo Normal: Sobrescreve
                setMatchResults(newResults);
                setReportPreviewData({
                    income: groupResultsByChurch(newResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': newResults.filter(r => r.transaction.amount < 0) }
                });
                showToast("Conciliação finalizada!", 'success');
            }

            setHasActiveSession(true);
            setActiveView('reports');

        } catch (e: any) {
            console.error(e);
            showToast(e.message || "Erro ao processar dados.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [bankStatementFile, activeReportId, contributorFiles, churches, similarityLevel, dayTolerance, cleaningKeywords, learnedAssociations, setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, showToast, setIsLoading, comparisonType, setBankStatementFile, fileModels, matchResults, user]);

    const updateReportData = useCallback((updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => {
        // 1. Atualiza lista plana (MatchResults)
        setMatchResults(prev => {
            let next = prev;
            // Se tiver ID para remover (Transação Fantasma Pendente), remove antes
            if (idToRemove) {
                next = next.filter(r => r.transaction.id !== idToRemove);
            }
            return next.map(r => r.transaction.id === updatedRow.transaction.id ? updatedRow : r);
        });

        // 2. Atualiza dados agrupados (ReportPreview)
        setReportPreviewData(prev => {
            if (!prev) return null;
            const newPreview = JSON.parse(JSON.stringify(prev));
            const targetGroup = reportType === 'expenses' ? newPreview.expenses : newPreview.income;

            if (reportType === 'income') {
                // LÓGICA DE ENTRADAS (Income)
                // Remove o item de qualquer grupo onde ele esteja (tanto o ID real quanto o ID fantasma)
                // Isso evita duplicação ao mover de 'unidentified' ou 'pendente' para uma igreja específica
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].filter((r: MatchResult) => {
                        const isTarget = r.transaction.id === updatedRow.transaction.id;
                        const isGhost = idToRemove && r.transaction.id === idToRemove;
                        return !isTarget && !isGhost;
                    });
                });

                // Adiciona o item atualizado ao grupo correto
                const currentChurchId = updatedRow.church.id || 'unidentified';
                if (!newPreview.income[currentChurchId]) newPreview.income[currentChurchId] = [];
                newPreview.income[currentChurchId].push(updatedRow);

            } else {
                // LÓGICA DE SAÍDAS (Expenses) - Mantém comportamento padrão de atualização in-place
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].map((r: MatchResult) => 
                        r.transaction.id === updatedRow.transaction.id ? updatedRow : r
                    );
                });
            }

            return newPreview;
        });
    }, [setMatchResults, setReportPreviewData]);

    const discardCurrentReport = useCallback(() => {
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null);
        setActiveView('upload');
    }, [setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, setActiveReportId]);

    const closeManualIdentify = useCallback(() => {
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
    }, []);

    const openManualMatchModal = useCallback((record: MatchResult) => {
        const suggestions = matchResults.map(r => r.transaction); 
        setManualMatchState({ record, suggestions });
    }, [matchResults]);

    const closeManualMatchModal = useCallback(() => setManualMatchState(null), []);

    const confirmManualAssociation = useCallback((selectedTx: Transaction) => {
        if (!manualMatchState) return;
        const { record } = manualMatchState;

        // Se o registro original era PENDENTE, significa que era uma transação fantasma da lista.
        // Precisamos capturar esse ID para removê-lo, pois ele será substituído pela transação real do banco.
        const ghostIdToRemove = record.status === 'PENDENTE' ? record.transaction.id : undefined;

        const updatedResult: MatchResult = {
            ...record,
            transaction: selectedTx,
            status: 'IDENTIFICADO',
            matchMethod: 'MANUAL',
            similarity: 100
        };

        updateReportData(updatedResult, 'income', ghostIdToRemove);
        closeManualMatchModal();
        showToast("Associação manual aplicada.", "success");
    }, [manualMatchState, updateReportData, closeManualMatchModal, showToast]);

    const openDivergenceModal = useCallback((match: MatchResult) => setDivergenceConfirmation(match), []);
    const closeDivergenceModal = useCallback(() => setDivergenceConfirmation(null), []);

    const confirmDivergence = useCallback((divergentMatch: MatchResult) => {
        updateReportData({ ...divergentMatch, status: 'IDENTIFICADO' }, 'income');
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const rejectDivergence = useCallback((divergentMatch: MatchResult) => {
        if (divergentMatch.divergence?.expectedChurch) {
             const restored: MatchResult = {
                 ...divergentMatch,
                 church: divergentMatch.divergence.expectedChurch,
                 status: 'IDENTIFICADO'
             };
             updateReportData(restored, 'income');
        } else {
             updateReportData({ ...divergentMatch, status: 'NÃO IDENTIFICADO', church: PLACEHOLDER_CHURCH, contributor: null }, 'income');
        }
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const handleAnalyze = useCallback(async (transactionId: string) => {
        setLoadingAiId(transactionId);
        setTimeout(() => {
            setAiSuggestion({ id: transactionId, name: "Sugestão AI Simulada" });
            setLoadingAiId(null);
        }, 1500);
    }, []);

    return useMemo(() => ({
        bankStatementFile, contributorFiles, matchResults, setMatchResults, reportPreviewData, setReportPreviewData, hasActiveSession, setHasActiveSession,
        activeReportId, setActiveReportId, // EXPORTED
        pendingTraining, setPendingTraining, comparisonType, setComparisonType,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, clearFiles, // EXPORTED
        handleCompare, updateReportData, discardCurrentReport, openLabManually,
        handleTrainingSuccess, resetReconciliation,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        closeManualIdentify,
        manualMatchState, setManualMatchState,
        openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, setDivergenceConfirmation,
        openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, setLoadingAiId, aiSuggestion, setAiSuggestion, handleAnalyze,
        setBankStatementFile // EXPORTED
    }), [
        bankStatementFile, contributorFiles, matchResults, reportPreviewData, hasActiveSession, activeReportId, pendingTraining, comparisonType, 
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, clearFiles, handleCompare, updateReportData, discardCurrentReport, openLabManually, handleTrainingSuccess,
        setMatchResults, setReportPreviewData, setHasActiveSession, setActiveReportId, resetReconciliation,
        manualIdentificationTx, bulkIdentificationTxs, closeManualIdentify,
        manualMatchState, openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, aiSuggestion, handleAnalyze, setBankStatementFile
    ]);
};

import React, { useContext, useState, useRef, useEffect } from 'react';
import { AppContext } from '../../contexts/AppContext';
import { useTranslation } from '../../contexts/I18nContext';
import { useUI } from '../../contexts/UIContext';
import { 
    XMarkIcon, 
    BoltIcon, 
    BanknotesIcon, 
    UserIcon, 
    TrashIcon,
    CheckCircleIcon,
    ArrowUturnLeftIcon,
    ArrowPathIcon,
    CloudArrowUpIcon,
    PlusCircleIcon,
    UploadIcon,
    EnvelopeIcon,
    EllipsisVerticalIcon
} from '../Icons';
import { FileUploader, FileUploaderHandle } from '../FileUploader';
import { GmailModal } from '../../features/gmail/GmailModal';
import { processFileContent } from '../../services/processingService';
import { consolidationService } from '../../services/ConsolidationService';
import { Transaction } from '../../types';
import { useAuth } from '../../contexts/AuthContext';

// --- SUB-COMPONENT: BANK ROW (LISTA VIVA MANAGER) ---

const BankRow: React.FC<{ 
    bank: any, 
    isUploaded: boolean, 
    handleStatementUpload: any, 
    setIsGmailModalOpen: any, 
    removeBankStatementFile: any,
    triggerUpdate: () => void 
}> = ({ bank, isUploaded, handleStatementUpload, setIsGmailModalOpen, removeBankStatementFile, triggerUpdate }) => {

    // CONTEXT ACCESS FOR APPEND LOGIC
    const { fileModels, effectiveIgnoreKeywords, bankStatementFile, setBankStatementFile } = useContext(AppContext);
    const { user } = useAuth();
    const { showToast } = useUI();

    const [menuOpen, setMenuOpen] = useState(false);
    const [isUploading, setIsUploading] = useState(false);
    const uploaderRef = useRef<FileUploaderHandle>(null);
    const menuRef = useRef<HTMLDivElement>(null);

    // Garante acesso à versão mais recente da função de update para evitar stale closures
    const triggerUpdateRef = useRef(triggerUpdate);
    useEffect(() => {
        triggerUpdateRef.current = triggerUpdate;
    }, [triggerUpdate]);

    // Controla o modo do upload: 'replace' (substituir) ou 'append' (adicionar)
    const uploadModeRef = useRef<'replace' | 'append'>('replace');

    // Fecha menu ao clicar fora
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setMenuOpen(false);
            }
        };
        if (menuOpen) document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [menuOpen]);

    const closeMenu = () => setMenuOpen(false);

    // LOGICA DE APPEND MANUAL (Sincronizada com DB com Fallback)
    const handleAppend = async (content: string, fileName: string, rawFile: File) => {
        setIsUploading(true);
        try {
            // 1. Processa o novo arquivo
            const result = processFileContent(content, fileName, fileModels, effectiveIgnoreKeywords);
            const newTransactions = result.transactions;

            if (newTransactions.length === 0) {
                showToast("Nenhuma transação válida encontrada no arquivo.", "error");
                setIsUploading(false);
                return;
            }

            // 2. Persistência (Consolidação) - PRIORIDADE 1
            // Tenta inserir no banco PRIMEIRO, mas não trava se falhar (ex: tabela inexistente/offline)
            if (user) {
                try {
                    const consolidationData = newTransactions.map(t => ({
                        transaction_date: t.date,
                        amount: t.amount,
                        description: t.description,
                        type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                        pix_key: null,
                        source: 'file' as 'file',
                        user_id: user.id
                    }));

                    // Aguarda a inserção para garantir integridade, mas catch qualquer erro
                    await consolidationService.addTransactions(consolidationData);
                } catch (dbError) {
                    console.warn("[Append] Falha na persistência remota. Continuando com estado local.", dbError);
                    // Não exibimos toast de erro para não interromper o fluxo do usuário em caso de 404 da tabela
                }
            }

            // 3. Atualiza Estado Global (Visual) - PRIORIDADE 2
            // Mesclamos localmente para garantir feedback imediato
            const currentTransactions = bankStatementFile?.processedTransactions || [];

            // Deduplicação visual simples
            const existingSignatures = new Set(currentTransactions.map(t => `${t.date}|${t.amount}|${t.description}`));
            const uniqueNewTransactions = newTransactions.filter(t => !existingSignatures.has(`${t.date}|${t.amount}|${t.description}`));

            const mergedTransactions = [...currentTransactions, ...uniqueNewTransactions];

            setBankStatementFile({
                bankId: bank.id,
                content: (bankStatementFile?.content || '') + '\n' + content,
                fileName: bankStatementFile?.fileName ? `${bankStatementFile.fileName} + ${fileName}` : fileName,
                rawFile: rawFile,
                processedTransactions: mergedTransactions
            });

            showToast(`${uniqueNewTransactions.length} novas transações adicionadas!`, "success");

            // 4. Dispara atualização da Lista Viva
            setTimeout(() => {
                triggerUpdateRef.current();
            }, 800);

        } catch (e: any) {
            console.error(e);
            showToast("Erro ao adicionar arquivo: " + e.message, "error");
        } finally {
            setIsUploading(false);
        }
    };

    const handleFileUploadWrapper = async (content: string, fileName: string, rawFile: File) => {
        if (uploadModeRef.current === 'replace') {
            setIsUploading(true);
            handleStatementUpload(content, fileName, bank.id, rawFile);

            // Aguarda propagação do estado e banco antes de atualizar a lista visual
            setTimeout(() => {
                triggerUpdateRef.current();
                setIsUploading(false);
            }, 1000);
        } else {
            await handleAppend(content, fileName, rawFile);
        }
        closeMenu();
    };

    const triggerUpload = (mode: 'replace' | 'append') => {
        uploadModeRef.current = mode;
        uploaderRef.current?.open();
        closeMenu();
    };

    return (
        <div className={`p-3 rounded-2xl border transition-all duration-200 flex items-center justify-between gap-3 relative group ${isUploaded ? 'bg-emerald-50/50 border-emerald-200 dark:bg-emerald-900/10 dark:border-emerald-800' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700'}`}>

            {/* Hidden Uploader Component */}
            <div className="hidden">
                <FileUploader 
                    ref={uploaderRef}
                    id={`update-bank-${bank.id}`}
                    title="Upload Hidden"
                    onFileUpload={handleFileUploadWrapper}
                    isUploaded={false}
                    uploadedFileName={null}
                    onParsingStatusChange={setIsUploading}
                />
            </div>

            <div className="flex flex-col min-w-0">
                <span className="font-bold text-xs text-slate-800 dark:text-slate-200 truncate">{bank.name}</span>
                {isUploaded ? (
                    <span className="flex items-center gap-1 text-[10px] text-emerald-600 dark:text-emerald-400 font-medium">
                        <CheckCircleIcon className="w-3 h-3" /> Lista Viva Ativa
                    </span>
                ) : (
                    <span className="text-[10px] text-slate-400 italic">Nenhum extrato vinculado</span>
                )}
            </div>

            <div className="relative" ref={menuRef}>
                {isUploading ? (
                    <div className="p-2">
                        <svg className="animate-spin h-5 w-5 text-blue-500" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    </div>
                ) : (
                    <button 
                        onClick={() => setMenuOpen(!menuOpen)}
                        className={`
                            p-2 rounded-full transition-all duration-200 border relative z-10
                            ${menuOpen 
                                ? 'bg-blue-50 dark:bg-slate-700 text-brand-blue border-blue-200 dark:border-blue-700 shadow-md ring-2 ring-blue-100 dark:ring-blue-900/30' 
                                : 'bg-white dark:bg-slate-800 text-slate-400 hover:text-brand-blue border-slate-200 dark:border-slate-700 hover:border-blue-300 dark:hover:border-blue-600 hover:shadow-sm'
                            }
                        `}
                        title="Opções do Extrato"
                    >
                        {isUploaded ? <EllipsisVerticalIcon className="w-5 h-5 stroke-[1.5]" /> : <CloudArrowUpIcon className="w-5 h-5 stroke-[1.5]" />}
                    </button>
                )}

                {/* Context Menu (Dropdown) */}
                {menuOpen && (
                    <div className="absolute right-0 top-full mt-2 z-50 w-56 bg-white dark:bg-slate-800 rounded-xl shadow-xl border border-slate-100 dark:border-slate-700 overflow-hidden animate-scale-in origin-top-right ring-1 ring-black/5">
                        <div className="flex flex-col py-1">

                            {/* ADICIONAR (APPEND) */}
                            <button 
                                onClick={() => triggerUpload('append')}
                                className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700/50 w-full text-left transition-colors group/item"
                            >
                                <div className="p-1.5 bg-blue-50 dark:bg-blue-900/20 rounded-lg text-blue-500 group-hover/item:text-blue-600">
                                    <PlusCircleIcon className="w-3.5 h-3.5" />
                                </div>
                                <div>
                                    <span className="block">Adicionar arquivo</span>
                                    <span className="text-[9px] font-normal text-slate-400">Somar à lista atual</span>
                                </div>
                            </button>

                            {/* SUBSTITUIR (REPLACE) */}
                            <button 
                                onClick={() => triggerUpload('replace')}
                                className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700/50 w-full text-left transition-colors group/item"
                            >
                                <div className="p-1.5 bg-amber-50 dark:bg-amber-900/20 rounded-lg text-amber-500 group-hover/item:text-amber-600">
                                    <ArrowPathIcon className="w-3.5 h-3.5" />
                                </div>
                                <div>
                                    <span className="block">Substituir tudo</span>
                                    <span className="text-[9px] font-normal text-slate-400">Trocar lista atual</span>
                                </div>
                            </button>

                            {/* GMAIL */}
                            <button 
                                onClick={() => { setIsGmailModalOpen(true); closeMenu(); }}
                                className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700/50 w-full text-left transition-colors group/item"
                            >
                                <div className="p-1.5 bg-red-50 dark:bg-red-900/20 rounded-lg text-red-500 group-hover/item:text-red-600">
                                    <EnvelopeIcon className="w-3.5 h-3.5" />
                                </div>
                                <div>
                                    <span className="block">Importar Gmail</span>
                                    <span className="text-[9px] font-normal text-slate-400">Buscar comprovantes</span>
                                </div>
                            </button>

                            <div className="h-px bg-slate-100 dark:bg-slate-700 my-1 mx-4"></div>

                            {/* EXCLUIR */}
                            <button 
                                onClick={() => { if(isUploaded) removeBankStatementFile(); closeMenu(); }}
                                disabled={!isUploaded}
                                className={`flex items-center gap-3 px-4 py-2.5 text-xs font-bold w-full text-left transition-colors group/item ${!isUploaded ? 'opacity-50 cursor-not-allowed text-slate-400' : 'text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20'}`}
                            >
                                <div className={`p-1.5 rounded-lg ${!isUploaded ? 'bg-slate-100' : 'bg-red-50 dark:bg-red-900/20 text-red-500'}`}>
                                    <TrashIcon className="w-3.5 h-3.5" />
                                </div>
                                <span>Remover extrato</span>
                            </button>
                        </div>
                    </div>
                )}
            </div>
        </div>
    );
};

