import React, { useContext, useState, useRef, useEffect } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useTranslation } from '../contexts/I18nContext';
import { useAuth } from '../contexts/AuthContext';
import { useUI } from '../contexts/UIContext';
import { FileUploader, FileUploaderHandle } from '../components/FileUploader';
import { 
    BanknotesIcon, 
    UserIcon, 
    TrashIcon, 
    InformationCircleIcon, 
    ExclamationTriangleIcon,
    BoltIcon,
    WhatsAppIcon,
    EllipsisVerticalIcon,
    PlusCircleIcon,
    ArrowPathIcon,
    EnvelopeIcon,
    CheckCircleIcon
} from '../components/Icons';
import { GmailButton } from '../features/gmail/GmailButton';
import { GmailModal } from '../features/gmail/GmailModal';
import { InitialComparisonModal } from '../components/modals/InitialComparisonModal';
import { processFileContent } from '../services/processingService';
import { consolidationService } from '../services/ConsolidationService';

// --- SMART BANK CARD COMPONENT ---
// Gerencia a lógica de upload, append e replace localmente para cada banco
const SmartBankCard: React.FC<{ bank: any }> = ({ bank }) => {
    const { 
        bankStatementFile, 
        setBankStatementFile, 
        handleStatementUpload, 
        removeBankStatementFile,
        fileModels,
        effectiveIgnoreKeywords
    } = useContext(AppContext);

    const { user } = useAuth();
    const { showToast } = useUI();
    const { t } = useTranslation();

    const [isMenuOpen, setIsMenuOpen] = useState(false);
    const [isUploading, setIsUploading] = useState(false);
    const [isGmailModalOpen, setIsGmailModalOpen] = useState(false);

    const uploaderRef = useRef<FileUploaderHandle>(null);
    const menuRef = useRef<HTMLDivElement>(null);
    const uploadModeRef = useRef<'replace' | 'append'>('replace');

    const isUploaded = bankStatementFile?.bankId === bank.id;

    // Fecha menu ao clicar fora
    useEffect(() => {
        const handleClickOutside = (event: MouseEvent) => {
            if (menuRef.current && !menuRef.current.contains(event.target as Node)) {
                setIsMenuOpen(false);
            }
        };
        if (isMenuOpen) document.addEventListener('mousedown', handleClickOutside);
        return () => document.removeEventListener('mousedown', handleClickOutside);
    }, [isMenuOpen]);

    // --- LÓGICA DE APPEND (LISTA VIVA) ---
    const handleAppend = async (content: string, fileName: string, rawFile: File) => {
        setIsUploading(true);
        try {
            // 1. Processamento
            const result = processFileContent(content, fileName, fileModels, effectiveIgnoreKeywords);
            const newTransactions = result.transactions;

            if (newTransactions.length === 0) {
                showToast("Nenhuma transação válida encontrada.", "error");
                return;
            }

            // 2. Persistência (Supabase)
            if (user) {
                try {
                    const consolidationData = newTransactions.map(t => ({
                        transaction_date: t.date,
                        amount: t.amount,
                        description: t.description,
                        type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                        pix_key: null,
                        source: 'file' as 'file',
                        user_id: user.id
                    }));
                    await consolidationService.addTransactions(consolidationData);
                } catch (e) {
                    console.warn("Falha na persistência remota (Offline mode)", e);
                }
            }

            // 3. Atualização de Estado (Merge)
            setBankStatementFile(prev => {
                if (!prev) {
                    // Fallback se não existir (não deveria acontecer no modo append, mas por segurança)
                    return {
                        bankId: bank.id,
                        content,
                        fileName,
                        rawFile,
                        processedTransactions: newTransactions
                    };
                }

                const currentTransactions = prev.processedTransactions || [];
                const existingSignatures = new Set(currentTransactions.map(t => `${t.date}|${t.amount}|${t.description}`));
                const uniqueNew = newTransactions.filter(t => !existingSignatures.has(`${t.date}|${t.amount}|${t.description}`));

                if (uniqueNew.length === 0) {
                    showToast("Todas as transações já existem na lista.", "error");
                    return prev;
                }

                showToast(`${uniqueNew.length} novas transações adicionadas!`, "success");

                return {
                    ...prev,
                    content: prev.content + '\n' + content,
                    fileName: `${prev.fileName} + ${fileName}`,
                    processedTransactions: [...currentTransactions, ...uniqueNew]
                };
            });

        } catch (e: any) {
            console.error(e);
            showToast("Erro ao adicionar: " + e.message, "error");
        } finally {
            setIsUploading(false);
        }
    };

    // Handler genérico do Uploader
    const handleFileUploadWrapper = async (content: string, fileName: string, rawFile: File) => {
        if (uploadModeRef.current === 'replace') {
            setIsUploading(true);
            // Replace usa a função padrão do contexto que já trata tudo
            handleStatementUpload(content, fileName, bank.id, rawFile);
            setTimeout(() => setIsUploading(false), 500);
        } else {
            await handleAppend(content, fileName, rawFile);
        }
        setIsMenuOpen(false);
    };

    const triggerUpload = (mode: 'replace' | 'append') => {
        uploadModeRef.current = mode;
        uploaderRef.current?.open();
        setIsMenuOpen(false);
    };

    const handleGmailSuccess = (csvContent: string) => {
        const virtualFile = new File([csvContent], "gmail_import.csv", { type: "text/csv" });
        if (isUploaded) {
            handleAppend(csvContent, `Gmail - ${new Date().toLocaleDateString()}`, virtualFile);
        } else {
            handleStatementUpload(csvContent, `Gmail - ${new Date().toLocaleDateString()}`, bank.id, virtualFile);
        }
    };

    return (
        <div className={`p-4 rounded-2xl border transition-all duration-300 flex items-center justify-between gap-3 group relative ${isUploaded ? 'bg-emerald-50/50 border-emerald-200 dark:bg-emerald-900/10 dark:border-emerald-800' : 'bg-slate-50 dark:bg-slate-900/50 border-slate-100 dark:border-slate-700 hover:border-blue-200 dark:hover:border-blue-800'}`}>

            {/* Hidden Uploader */}
            <div className="hidden">
                <FileUploader 
                    ref={uploaderRef}
                    id={`bank-${bank.id}`}
                    title="Upload"
                    onFileUpload={handleFileUploadWrapper}
                    isUploaded={false}
                    uploadedFileName={null}
                    onParsingStatusChange={setIsUploading}
                />
            </div>

            {/* Info Section */}
            <div className="flex flex-col min-w-0">
                <span className="font-bold text-sm text-slate-800 dark:text-slate-200 truncate">{bank.name}</span>
                {isUploaded ? (
                    <span className="flex items-center gap-1.5 text-[10px] text-emerald-600 dark:text-emerald-400 font-bold uppercase tracking-wide mt-0.5">
                        <CheckCircleIcon className="w-3.5 h-3.5" /> Lista Viva Ativa
                    </span>
                ) : (
                    <span className="text-[10px] text-slate-400 italic mt-0.5">Nenhum arquivo</span>
                )}
            </div>

            {/* Actions Section */}
            <div className="flex items-center gap-2" ref={menuRef}>
                {isUploading ? (
                    <div className="p-2">
                        <svg className="animate-spin h-5 w-5 text-blue-500" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
                    </div>
                ) : !isUploaded ? (
                    // Botão Upload Inicial
                    <button 
                        onClick={() => triggerUpload('replace')}
                        className="px-4 py-2 bg-white dark:bg-slate-800 text-slate-600 dark:text-slate-300 border border-slate-200 dark:border-slate-600 hover:border-brand-blue hover:text-brand-blue rounded-lg text-xs font-bold uppercase tracking-wide shadow-sm transition-all"
                    >
                        {t('upload.statementButton')}
                    </button>
                ) : (
                    // Menu de Ações para Lista Viva
                    <div className="relative">
                        <button 
                            onClick={() => setIsMenuOpen(!isMenuOpen)}
                            className={`p-2 rounded-full transition-all border ${isMenuOpen ? 'bg-blue-50 border-blue-200 text-brand-blue' : 'bg-white dark:bg-slate-800 border-slate-200 dark:border-slate-700 text-slate-400 hover:text-slate-600 dark:hover:text-slate-200'}`}
                        >
                            <EllipsisVerticalIcon className="w-5 h-5" />
                        </button>

                        {isMenuOpen && (
                            <div className="absolute right-0 top-full mt-2 z-50 w-56 bg-white dark:bg-slate-800 rounded-xl shadow-xl border border-slate-100 dark:border-slate-700 overflow-hidden animate-scale-in origin-top-right ring-1 ring-black/5">
                                <div className="flex flex-col py-1">
                                    <button onClick={() => triggerUpload('append')} className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700/50 w-full text-left transition-colors group/item">
                                        <div className="p-1.5 bg-blue-50 dark:bg-blue-900/20 rounded-lg text-blue-500 group-hover/item:text-blue-600"><PlusCircleIcon className="w-3.5 h-3.5" /></div>
                                        <div><span className="block">Adicionar arquivo</span><span className="text-[9px] font-normal text-slate-400">Somar à lista atual</span></div>
                                    </button>
                                    <button onClick={() => triggerUpload('replace')} className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700/50 w-full text-left transition-colors group/item">
                                        <div className="p-1.5 bg-amber-50 dark:bg-amber-900/20 rounded-lg text-amber-500 group-hover/item:text-amber-600"><ArrowPathIcon className="w-3.5 h-3.5" /></div>
                                        <div><span className="block">Substituir tudo</span><span className="text-[9px] font-normal text-slate-400">Começar do zero</span></div>
                                    </button>
                                    <button onClick={() => { setIsGmailModalOpen(true); setIsMenuOpen(false); }} className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700/50 w-full text-left transition-colors group/item">
                                        <div className="p-1.5 bg-red-50 dark:bg-red-900/20 rounded-lg text-red-500 group-hover/item:text-red-600"><EnvelopeIcon className="w-3.5 h-3.5" /></div>
                                        <div><span className="block">Importar Gmail</span><span className="text-[9px] font-normal text-slate-400">Buscar comprovantes</span></div>
                                    </button>
                                    <div className="h-px bg-slate-100 dark:bg-slate-700 my-1 mx-4"></div>
                                    <button onClick={() => { removeBankStatementFile(); setIsMenuOpen(false); }} className="flex items-center gap-3 px-4 py-2.5 text-xs font-bold w-full text-left transition-colors group/item text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20">
                                        <div className="p-1.5 rounded-lg bg-red-50 dark:bg-red-900/20 text-red-500"><TrashIcon className="w-3.5 h-3.5" /></div>
                                        <span>Limpar dados</span>
                                    </button>
                                </div>
                            </div>
                        )}
                    </div>
                )}
            </div>

            {isGmailModalOpen && <GmailModal onClose={() => setIsGmailModalOpen(false)} onSuccess={handleGmailSuccess} />}
        </div>
    );
};

export const UploadView: React.FC = () => {
