import {
    Transaction, Contributor, MatchResult, Bank, Church, ChurchFormData,
    DeletingItem, ComparisonType, GroupedReportData, SearchFilters, SavedReport,
    SavingReportState, LearnedAssociation, MatchMethod, FileModel, SpreadsheetData
} from '../types';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';

import { supabase } from '../services/supabaseClient';
import { useTranslation } from './I18nContext';
import { LoadingSpinner } from '../components/shared/LoadingSpinner';
import { RecompareModal } from '../components/modals/RecompareModal';
import { consolidationService } from '../services/ConsolidationService';

interface AppContextType {
    // Data State (from useReferenceData)
    banks: Bank[];
    churches: Church[];
    fileModels: FileModel[];
    fetchModels: () => Promise<void>;
    setBanks: React.Dispatch<React.SetStateAction<Bank[]>>;
    setChurches: React.Dispatch<React.SetStateAction<Church[]>>;
    similarityLevel: number;
    setSimilarityLevel: React.Dispatch<React.SetStateAction<number>>;
    dayTolerance: number;
    setDayTolerance: React.Dispatch<React.SetStateAction<number>>;
    customIgnoreKeywords: string[]; 
    effectiveIgnoreKeywords: string[]; 
    addIgnoreKeyword: (keyword: string) => void;
    removeIgnoreKeyword: (keyword: string) => void;
    contributionKeywords: string[];
    addContributionKeyword: (keyword: string) => void;
    removeContributionKeyword: (keyword: string) => void;
    learnedAssociations: LearnedAssociation[];

    // Edit States
    editingBank: Bank | null;
    editingChurch: Church | null;
    openEditBank: (bank: Bank) => void;
    closeEditBank: () => void;
    updateBank: (bankId: string, name: string) => void;
    addBank: (name: string) => Promise<boolean>;
    openEditChurch: (church: Church) => void;
    closeEditChurch: () => void;
    updateChurch: (churchId: string, data: ChurchFormData) => void;
    addChurch: (data: ChurchFormData) => Promise<boolean>;

    // Reconciliation State (from useReconciliation)
    bankStatementFile: { bankId: string, content: string, fileName: string, rawFile?: File } | null;
    contributorFiles: { churchId: string; content: string; fileName: string; contributors?: Contributor[] }[];
    matchResults: MatchResult[];
    setMatchResults: React.Dispatch<React.SetStateAction<MatchResult[]>>;
    reportPreviewData: { income: GroupedReportData; expenses: GroupedReportData } | null;
    setReportPreviewData: React.Dispatch<React.SetStateAction<{ income: GroupedReportData; expenses: GroupedReportData } | null>>;
    comparisonType: ComparisonType;
    setComparisonType: React.Dispatch<React.SetStateAction<ComparisonType>>;
    hasActiveSession: boolean;
    setHasActiveSession: React.Dispatch<React.SetStateAction<boolean>>;
    isCompareDisabled: boolean;
    pendingTraining: any;
    setPendingTraining: (val: any) => void;
    activeReportId: string | null;
    setActiveReportId: React.Dispatch<React.SetStateAction<string | null>>;
    activeSpreadsheetData: SpreadsheetData | null;

    // Reconciliation Actions
    openLabManually: (targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => void;
    handleStatementUpload: (content: string, fileName: string, bankId: string, rawFile: File) => void;
    handleContributorsUpload: (content: string, fileName: string, churchId: string, rawFile?: File) => void;
    handleTrainingSuccess: (model: FileModel, data: Transaction[]) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (churchId: string) => void;
    handleCompare: () => void;
    handleBackToSettings: () => void;
    updateReportData: (updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => void;
    discardCurrentReport: () => void;
    resetReconciliation: () => void; 
    handleGmailSyncSuccess: (transactions: Transaction[]) => void; 

    // Manual Operations State & Handlers
    manualIdentificationTx: Transaction | null;
    setManualIdentificationTx: React.Dispatch<React.SetStateAction<Transaction | null>>;
    bulkIdentificationTxs: Transaction[] | null;
    setBulkIdentificationTxs: React.Dispatch<React.SetStateAction<Transaction[] | null>>;

    openManualIdentify: (transactionId: string) => void;
    openBulkManualIdentify: (transactions: Transaction[]) => void;
    closeManualIdentify: () => void;
    confirmManualIdentification: (transactionId: string, churchId: string) => Promise<void>;
    confirmBulkManualIdentification: (transactionIds: string[], churchId: string) => Promise<void>;

    manualMatchState: { record: MatchResult, suggestions: Transaction[] } | null;
    setManualMatchState: React.Dispatch<React.SetStateAction<{ record: MatchResult, suggestions: Transaction[] } | null>>;
    openManualMatchModal: (recordToMatch: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (selectedTx: Transaction) => void;

    // Smart Edit
    smartEditTarget: MatchResult | null;
    openSmartEdit: (match: MatchResult) => void;
    closeSmartEdit: () => void;
    saveSmartEdit: (updatedMatch: MatchResult) => void;

    divergenceConfirmation: MatchResult | null;
    setDivergenceConfirmation: React.Dispatch<React.SetStateAction<MatchResult | null>>;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (divergentMatch: MatchResult) => void;
    rejectDivergence: (divergentMatch: MatchResult) => void;

    undoIdentification: (transactionId: string) => Promise<void>;

    learnAssociation: (matchResult: MatchResult) => Promise<void>;
    findMatchResult: (transactionId: string) => MatchResult | undefined;

    // AI
    loadingAiId: string | null;
    aiSuggestion: { id: string, name: string } | null;
    handleAnalyze: (transaction: Transaction, candidates: Contributor[]) => void;

    // Recompare Modal
    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    // Update Files Modal
    isUpdateFilesModalOpen: boolean;
    openUpdateFilesModal: () => void;
    closeUpdateFilesModal: () => void;

    // Reports & Search (from useReportManager)
    savedReports: SavedReport[];
    maxSavedReports: number;
    searchFilters: SearchFilters;
    setSearchFilters: React.Dispatch<React.SetStateAction<SearchFilters>>;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    clearSearchFilters: () => void;
    allHistoricalResults: MatchResult[];

    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => void;
    viewSavedReport: (reportId: string) => void;
    updateSavedReportName: (reportId: string, newName: string) => void;
    saveFilteredReport: (results: MatchResult[]) => void;
    saveCurrentReportChanges: () => void;
    overwriteSavedReport: (reportId: string, results: MatchResult[], spreadsheetData?: SpreadsheetData) => Promise<void>;
    deleteOldReports: (dateThreshold: Date) => Promise<void>;

    // Global
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;
    initialDataLoaded: boolean;
    isSyncing: boolean;
    summary: {
        autoConfirmed: { count: number; value: number; };
        manualConfirmed: { count: number; value: number; };
        pending: { count: number; value: number; };
        identifiedCount: number;
        unidentifiedCount: number;
        totalValue: number;
        valuePerChurch: [string, number][];
        isHistorical: boolean;
        methodBreakdown: Record<MatchMethod, number>;
    };
    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, systemSettings, incrementAiUsage } = useAuth();
    const { t } = useTranslation();
    const { showToast, setIsLoading, setActiveView } = useUI();

    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    const effectiveIgnoreKeywords = useMemo(() => {
        return systemSettings.globalIgnoreKeywords || [];
    }, [systemSettings.globalIgnoreKeywords]);

    const reconciliation = useReconciliation({
        user, 
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: [],
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: effectiveIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast, setIsLoading, setActiveView
    });

    const [initialDataLoaded, setInitialDataLoaded] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false); 

    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);
    const [isUpdateFilesModalOpen, setIsUpdateFilesModalOpen] = useState(false);

    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);
    const [activeSpreadsheetData, setActiveSpreadsheetData] = useState<SpreadsheetData | null>(null);

    const userSuffix = user ? `-${user.id}` : '-guest';
    const [summary, setSummary] = usePersistentState(`identificapix-dashboard-summary-v6${userSuffix}`, {
        autoConfirmed: { count: 0, value: 0 },
        manualConfirmed: { count: 0, value: 0 },
        pending: { count: 0, value: 0 },
        identifiedCount: 0, unidentifiedCount: 0, totalValue: 0, valuePerChurch: [], isHistorical: false,
        methodBreakdown: { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 }
    }, false);

    // Fetch de Dados e Lista Viva de Pendências
    useEffect(() => {
        if (!user) {
            setInitialDataLoaded(true);
            return;
        }

        const fetchData = async () => {
            setIsSyncing(true);
            try {
                // 1. Dados de Referência
                const [churchesRes, banksRes, reportsRes] = await Promise.all([
                    supabase.from('churches').select('*').order('name'),
                    supabase.from('banks').select('*').order('name'),
                    supabase.from('saved_reports')
                        .select('id, name, created_at, record_count, user_id') 
                        .eq('user_id', user.id)
                        .order('created_at', { ascending: false }),
                ]);

                // Update References
                if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
                const loadedBanks = banksRes.data as Bank[] || [];
                if (banksRes.data) referenceData.setBanks(loadedBanks);

                if (reportsRes.data) {
                    reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null 
                    })));
                }

                // 2. Lista Viva de Pendências (Consolidated Transactions)
                const pendingTxs = await consolidationService.getPendingTransactions(user.id);

                if (pendingTxs && pendingTxs.length > 0) {
                    // Mapeia para transações da aplicação
                    const liveTransactions = pendingTxs.map(dbTx => ({
                        id: dbTx.id,
                        date: dbTx.transaction_date,
                        amount: dbTx.amount,
                        description: dbTx.description,
                        cleanedDescription: dbTx.description, // Re-limpar se necessário
                        contributionType: dbTx.type,
                        originalAmount: String(dbTx.amount)
                    }));

                    // --- RECONSTITUIÇÃO DO ESTADO DE ARQUIVO (AUTO-LOAD) ---
                    // Se não houver arquivo carregado na sessão atual (LocalStorage), mas houver dados no banco,
                    // reconstruímos o "bankStatementFile" para que a UI reflita que há dados ativos.
                    // Isso satisfaz o requisito de "Lista Viva Automática" entre sessões/devices.
                    if (!reconciliation.bankStatementFile) {
                        const virtualContent = liveTransactions
                            .map(t => `${t.date};${t.description};${t.amount};${t.contributionType}`)
                            .join('\n');

                        // Associa ao primeiro banco disponível como fallback visual, ou cria um genérico
                        const targetBankId = loadedBanks.length > 0 ? loadedBanks[0].id : 'active-session-bank';

                        reconciliation.setBankStatementFile({
                            bankId: targetBankId,
                            content: virtualContent,
                            fileName: 'Sessão Ativa (Nuvem)',
                            processedTransactions: liveTransactions as Transaction[]
                        });
                    }

                    // Popula resultados de conciliação
                    const mappedResults: MatchResult[] = liveTransactions.map(tx => ({
                        transaction: tx as Transaction,
                        contributor: null,
                        status: 'NÃO IDENTIFICADO',
                        church: PLACEHOLDER_CHURCH,
                        matchMethod: undefined,
                        similarity: 0
                    }));

                    reconciliation.setMatchResults(mappedResults);
                    reconciliation.setReportPreviewData({
                        income: groupResultsByChurch(mappedResults),
                        expenses: { 'all_expenses_group': [] }
                    });

                    // Sinaliza sessão ativa
                    reconciliation.setHasActiveSession(true);
                }

            } catch (err) { 
                console.error('Background sync failed', err); 
            } finally { 
                setIsSyncing(false); 
                setInitialDataLoaded(true); 
            }
        };

        fetchData();
    }, [user?.id]);

    // Resumo do Dashboard (Efeito já existente)
    const resultsHash = JSON.stringify(reconciliation.matchResults.map(r => r.transaction.id + r.status));
    const reportsHash = reportManager.savedReports.length;

    useEffect(() => {
        const timer = setTimeout(() => {
            let resultsToProcess = reconciliation.matchResults;
            let isHistorical = false;

            if (resultsToProcess.length === 0 && reportManager.savedReports.length > 0) {
                resultsToProcess = reportManager.savedReports.flatMap(report => report.data?.results || []);
                isHistorical = true;
            }
            const autoConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod));
            const manualConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
            const pending = resultsToProcess.filter(r => r.status === 'NÃO IDENTIFICADO');
            const valuePerChurch = new Map<string, number>();
            const methodBreakdown: Record<MatchMethod, number> = { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 };
            resultsToProcess.forEach(r => {
                if (r.status === 'IDENTIFICADO') {
                    if (r.church && r.church.name !== '---' && r.transaction.amount > 0) {
                        const current = valuePerChurch.get(r.church.name) || 0;
                        valuePerChurch.set(r.church.name, current + r.transaction.amount);
                    }
                    const method = r.matchMethod || 'AUTOMATIC';
                    if (methodBreakdown[method] !== undefined) methodBreakdown[method]++;
                }
            });
            const newTotal = resultsToProcess.reduce((sum, r) => sum + r.transaction.amount, 0);
            setSummary(prev => ({
                autoConfirmed: { count: autoConfirmed.length, value: autoConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                manualConfirmed: { count: manualConfirmed.length, value: manualConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                pending: { count: pending.length, value: pending.reduce((sum, r) => sum + r.transaction.amount, 0) },
                identifiedCount: autoConfirmed.length + manualConfirmed.length,
                unidentifiedCount: pending.length, totalValue: newTotal,
                valuePerChurch: Array.from(valuePerChurch.entries()).sort((a, b) => b[1] - a[1]),
                isHistorical, methodBreakdown
            }));
        }, 300);
        return () => clearTimeout(timer);
    }, [resultsHash, reportsHash]);

    const handleBackToSettings = useCallback(() => setActiveView('upload'), [setActiveView]);
    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);

    const unifiedResetReconciliation = useCallback(() => {
        reconciliation.resetReconciliation();
        setActiveSpreadsheetData(null);
    }, [reconciliation]);

    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;
        if (deletingItem.type === 'report-row') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 Object.keys(targetGroup).forEach(key => { targetGroup[key] = targetGroup[key].filter(r => r.transaction.id !== deletingItem.id); });
                 return newPreview;
             });
             reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
        } else if (deletingItem.type === 'report-group') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 if (targetGroup[deletingItem.id]) {
                     const idsToRemove = targetGroup[deletingItem.id].map(r => r.transaction.id);
                     delete targetGroup[deletingItem.id];
                     reconciliation.setMatchResults(prev => prev.filter(r => !idsToRemove.includes(r.transaction.id)));
                 }
                 return newPreview;
             });
        } else if (deletingItem.type === 'bank') {
            referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
            await supabase.from('banks').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'church') {
            referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
            await supabase.from('churches').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'report-saved') {
            reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
            await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'uploaded-files') { reconciliation.removeBankStatementFile(); }
        closeDeleteConfirmation();
        showToast("Ação realizada com sucesso.");
    }, [deletingItem, user, referenceData, reportManager, reconciliation, showToast, closeDeleteConfirmation]);

    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            let report = reportManager.savedReports.find(r => r.id === reportId);
            if (!report) return;

            if (!report.data) {
                const { data: reportContent, error } = await supabase
                    .from('saved_reports')
                    .select('data')
                    .eq('id', reportId)
                    .single();

                if (error) throw error;

                if (reportContent) {
                    const parsedData = typeof reportContent.data === 'string' 
                        ? JSON.parse(reportContent.data) 
                        : reportContent.data;

                    report = { ...report, data: parsedData };
                    reportManager.setSavedReports(prev => prev.map(r => r.id === reportId ? report! : r));
                }
            }

            if (!report.data) throw new Error("Conteúdo do relatório vazio.");

            reconciliation.clearFiles();
            setActiveSpreadsheetData(null);

            if (report.data.spreadsheet) {
                setActiveSpreadsheetData(report.data.spreadsheet);
                reconciliation.setActiveReportId(reportId);
                setActiveView('smart_analysis');
                showToast(`Planilha "${report.name}" carregada.`, "success");
            } else {
                const validResults = report.data.results.map((r: any) => ({ ...r, church: r.church || PLACEHOLDER_CHURCH }));
                reconciliation.setMatchResults(validResults);
                reconciliation.setReportPreviewData({
                    income: groupResultsByChurch(validResults.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': validResults.filter((r: any) => r.transaction.amount < 0) }
                });
                reconciliation.setHasActiveSession(true); 
                reconciliation.setActiveReportId(reportId); 
                setActiveView('reports'); 
                showToast(`Relatório "${report.name}" carregado.`, "success");
            }

        } catch (error: any) {
            console.error(error);
            showToast("Erro ao abrir relatório: " + error.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, reconciliation, setActiveView, setIsLoading, showToast]);

    const saveCurrentReportChanges = useCallback(() => {
        const reportId = reconciliation.activeReportId;
        if (!reportId) {
            showToast("Nenhum relatório salvo ativo para atualizar.", "error");
            return;
        }
        reportManager.overwriteSavedReport(reportId, reconciliation.matchResults);
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager, showToast]);

    const findMatchResult = useCallback((transactionId: string) => reconciliation.matchResults.find(r => r.transaction.id === transactionId) || reportManager.allHistoricalResults.find(r => r.transaction.id === transactionId), [reconciliation.matchResults, reportManager.allHistoricalResults]);

    const openManualIdentify = useCallback((transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result) reconciliation.setManualIdentificationTx(result.transaction);
    }, [findMatchResult, reconciliation]);

    const openBulkManualIdentify = useCallback((transactions: Transaction[]) => { reconciliation.setBulkIdentificationTxs(transactions); }, [reconciliation]);

    // --- INTEGRATED IDENTIFICATION FLOW ---
    const confirmManualIdentification = useCallback(async (transactionId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        const result = findMatchResult(transactionId);

        if (church && result) {
            const updated: MatchResult = { ...result, status: 'IDENTIFICADO', church, contributor: { id: `manual-${transactionId}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, matchMethod: 'MANUAL', similarity: 100, contributorAmount: result.transaction.amount };

            // 1. Update UI first (Optimistic)
            if (reconciliation.matchResults.some(r => r.transaction.id === transactionId)) reconciliation.updateReportData(updated, 'income');
            else reportManager.updateSavedReportTransaction(transactionId, updated);

            reconciliation.closeManualIdentify(); 
            showToast('Identificação realizada.', 'success');

            // 2. Update Database (Lista Viva)
            try {
                await consolidationService.markAsIdentified(transactionId);
            } catch (e) {
                console.error("Falha ao atualizar status no banco", e);
                // Não revertemos a UI para não travar o fluxo, mas logamos o erro
            }
        }
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const confirmBulkManualIdentification = useCallback(async (transactionIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        const updates: Promise<void>[] = [];

        transactionIds.forEach(id => {
            const result = findMatchResult(id);
            if (result) {
                const updated: MatchResult = { 
                    ...result, 
                    status: 'IDENTIFICADO', 
                    church, 
                    contributor: { id: `manual-${id}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, 
                    matchMethod: 'MANUAL', 
                    similarity: 100, 
                    contributorAmount: result.transaction.amount 
                };

                // 1. Update UI
                if (reconciliation.matchResults.some(r => r.transaction.id === id)) reconciliation.updateReportData(updated, 'income');
                else reportManager.updateSavedReportTransaction(id, updated);

                // 2. Queue DB Update
                updates.push(consolidationService.markAsIdentified(id));
            }
        });

        reconciliation.closeManualIdentify();
        showToast(`${transactionIds.length} transações identificadas.`, 'success');

        // 3. Execute DB Updates
        try {
            await Promise.all(updates);
        } catch (e) {
            console.error("Falha na atualização em massa do banco", e);
        }

    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const openSmartEdit = useCallback((match: MatchResult) => {
        setSmartEditTarget(match);
    }, []);

    const closeSmartEdit = useCallback(() => {
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);
    }, [reconciliation]);

    const saveSmartEdit = useCallback((updatedMatch: MatchResult) => {
        // UI Update
        if (reconciliation.matchResults.some(r => r.transaction.id === updatedMatch.transaction.id)) {
            const ghostId = smartEditTarget?.status === 'PENDENTE' ? smartEditTarget.transaction.id : undefined;
            reconciliation.updateReportData(updatedMatch, 'income', ghostId);
        } else {
            reportManager.updateSavedReportTransaction(updatedMatch.transaction.id, updatedMatch);
        }

        showToast("Edição aplicada na tabela.", "success");
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);

        // DB Update (if identified)
        if (updatedMatch.status === 'IDENTIFICADO') {
            consolidationService.markAsIdentified(updatedMatch.transaction.id).catch(console.error);
        }

    }, [reconciliation, reportManager, showToast, smartEditTarget]);

    const undoIdentification = useCallback(async (transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result) {
            const reverted: MatchResult = {
                ...result,
                status: 'NÃO IDENTIFICADO',
                contributor: null,
                matchMethod: undefined,
                similarity: undefined,
                contributorAmount: undefined,
                divergence: undefined,
                suggestion: undefined 
            };

            // 1. Update UI
            if (reconciliation.matchResults.some(r => r.transaction.id === transactionId)) {
                reconciliation.updateReportData(reverted, 'income');
            } else {
                reportManager.updateSavedReportTransaction(transactionId, reverted);
            }

            showToast('Identificação revertida.', 'success');

            // 2. Update DB
            try {
                await consolidationService.markAsPending(transactionId);
            } catch (e) {
                console.error("Falha ao reverter status no banco", e);
            }
        }
    }, [findMatchResult, reconciliation, reportManager, showToast]);

    const handleAnalyze = useCallback(async (transaction: Transaction, candidates: Contributor[]) => {
        reconciliation.setLoadingAiId(transaction.id);
        try {
            const candidateNames = candidates.slice(0, 50).map(c => c.name);
            const response = await fetch('/api/ai/suggestion', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    transactionDescription: transaction.description,
                    contributorNames: candidateNames
                })
            });

            if (!response.ok) throw new Error('Falha na API de IA');
            const data = await response.json();
            const suggestionText = data.text;

            if (suggestionText && !suggestionText.includes("Nenhuma sugestão clara")) {
                reconciliation.setAiSuggestion({ id: transaction.id, name: suggestionText });
                incrementAiUsage(); 
            } else {
                reconciliation.setAiSuggestion(null);
            }
        } catch (error) {
            console.error("Erro na análise IA:", error);
            showToast("Não foi possível obter sugestão da IA.", "error");
        } finally {
            reconciliation.setLoadingAiId(null);
        }
    }, [incrementAiUsage, showToast, reconciliation]);

    const handleGmailSyncSuccess = useCallback(async (transactions: Transaction[]) => {
        if (transactions.length === 0) return;

        // 1. CONSOLIDATION (DB PERSISTENCE)
        if (user) {
            const consolidationData = transactions.map(t => ({
                transaction_date: t.date,
                amount: t.amount,
                description: t.description,
                type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                pix_key: null,
                source: 'gmail' as 'gmail',
                user_id: user.id
            }));
            await consolidationService.addTransactions(consolidationData);
        }

        // 2. STATE UPDATE
        if (reconciliation.activeReportId) {
            // --- INSIDE REPORT FLOW ---
            reconciliation.setMatchResults(prev => {
                const existingIds = new Set(prev.map(r => r.transaction.id));

                const newMatches: MatchResult[] = transactions
                    .filter(t => !existingIds.has(t.id)) // Deduplicate against current view
                    .map(t => ({
                        transaction: t,
                        contributor: null,
                        status: 'NÃO IDENTIFICADO',
                        church: PLACEHOLDER_CHURCH,
                        matchMethod: undefined,
                        similarity: 0
                    }));

                if (newMatches.length === 0) {
                    showToast("Nenhuma transação nova encontrada.", "error");
                    return prev;
                }

                // Append new results
                const nextResults = [...prev, ...newMatches];

                // Update Preview Data (Visual Groups)
                reconciliation.setReportPreviewData(currentPreview => {
                    if (!currentPreview) return null;
                    const nextPreview = { ...currentPreview };

                    // Add income/expenses to respective unidentified groups
                    const newIncome = newMatches.filter(r => r.transaction.amount > 0);
                    const newExpenses = newMatches.filter(r => r.transaction.amount < 0);

                    if (newIncome.length > 0) {
                        nextPreview.income['unidentified'] = [
                            ...(nextPreview.income['unidentified'] || []),
                            ...newIncome
                        ];
                    }
                    if (newExpenses.length > 0) {
                        nextPreview.expenses['all_expenses_group'] = [
                            ...(nextPreview.expenses['all_expenses_group'] || []),
                            ...newExpenses
                        ];
                    }
                    return nextPreview;
                });

                showToast(`${newMatches.length} novas transações adicionadas ao relatório.`, 'success');
                return nextResults;
            });

        } else {
            // --- OUTSIDE REPORT FLOW (Original + Enhanced) ---
            const virtualFileName = `Importação Gmail - ${new Date().toLocaleDateString()}`;

            reconciliation.setBankStatementFile(prev => {
                const existingTxs = prev?.processedTransactions || [];
                // Deduplicate against the virtual file being viewed
                const newTxs = transactions.filter(nt => !existingTxs.some(et => et.id === nt.id));

                if (newTxs.length === 0 && existingTxs.length > 0) {
                     showToast("Nenhuma transação nova.", "error");
                     return prev;
                }

                const merged = [...existingTxs, ...newTxs];

                // Also update the live match results if we are viewing the live list
                if (reconciliation.hasActiveSession) {
                     const newMatches: MatchResult[] = newTxs.map(t => ({
                        transaction: t,
                        contributor: null,
                        status: 'NÃO IDENTIFICADO',
                        church: PLACEHOLDER_CHURCH,
                        matchMethod: undefined,
                        similarity: 0
                    }));

                    reconciliation.setMatchResults(prevResults => [...prevResults, ...newMatches]);
                    reconciliation.setReportPreviewData(prevPreview => {
                        if (!prevPreview) return null;
                        const nextPreview = { ...prevPreview };
                        const newIncome = newMatches.filter(r => r.transaction.amount > 0);
                        const newExpenses = newMatches.filter(r => r.transaction.amount < 0);

                        if (newIncome.length > 0) nextPreview.income['unidentified'] = [...(nextPreview.income['unidentified']||[]), ...newIncome];
                        if (newExpenses.length > 0) nextPreview.expenses['all_expenses_group'] = [...(nextPreview.expenses['all_expenses_group']||[]), ...newExpenses];

                        return nextPreview;
                    });
                }

                return {
                    bankId: prev?.bankId || 'gmail-bank',
                    content: prev?.content || 'GMAIL_VIRTUAL_CONTENT',
                    fileName: prev?.fileName || virtualFileName,
                    processedTransactions: merged
                };
            });

            if (!reconciliation.activeReportId) {
                 showToast(`${transactions.length} transações sincronizadas.`, 'success');
            }
        }

    }, [reconciliation, showToast, user]);

    const value = useMemo(() => ({
        ...referenceData, ...reconciliation, isCompareDisabled: !reconciliation.bankStatementFile,
        effectiveIgnoreKeywords, 
        openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult,
        ...reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation,
        closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true), closePaymentModal: () => setIsPaymentModalOpen(false),
        isRecompareModalOpen, openRecompareModal: () => setIsRecompareModalOpen(true), closeRecompareModal: () => setIsRecompareModalOpen(false),
        smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze,
        saveCurrentReportChanges,
        handleGmailSyncSuccess,
        resetReconciliation: unifiedResetReconciliation,
        activeSpreadsheetData,
        isUpdateFilesModalOpen, 
        openUpdateFilesModal: () => setIsUpdateFilesModalOpen(true), 
        closeUpdateFilesModal: () => setIsUpdateFilesModalOpen(false),
        undoIdentification
    }), [referenceData, reconciliation, effectiveIgnoreKeywords, reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation, closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen, isRecompareModalOpen, openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult, smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze, saveCurrentReportChanges, handleGmailSyncSuccess, unifiedResetReconciliation, activeSpreadsheetData, isUpdateFilesModalOpen, undoIdentification]);

    return <AppContext.Provider value={value}>{children}<RecompareModal /></AppContext.Provider>;
};

import React, { createContext, useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReconciliation } from '../hooks/useReconciliation';
import { useReportManager } from '../hooks/useReportManager';
import { usePersistentState } from '../hooks/usePersistentState';
import {
    Transaction, Contributor, MatchResult, Bank, Church, ChurchFormData,
    DeletingItem, ComparisonType, GroupedReportData, SearchFilters, SavedReport,
    SavingReportState, LearnedAssociation, MatchMethod, FileModel, SpreadsheetData
} from '../types';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';

import { supabase } from '../services/supabaseClient';
import { useTranslation } from './I18nContext';
import { LoadingSpinner } from '../components/shared/LoadingSpinner';
import { RecompareModal } from '../components/modals/RecompareModal';
import { consolidationService } from '../services/ConsolidationService';

interface AppContextType {
    // Data State (from useReferenceData)
    banks: Bank[];
    churches: Church[];
    fileModels: FileModel[];
    fetchModels: () => Promise<void>;
    setBanks: React.Dispatch<React.SetStateAction<Bank[]>>;
    setChurches: React.Dispatch<React.SetStateAction<Church[]>>;
    similarityLevel: number;
    setSimilarityLevel: React.Dispatch<React.SetStateAction<number>>;
    dayTolerance: number;
    setDayTolerance: React.Dispatch<React.SetStateAction<number>>;
    customIgnoreKeywords: string[]; 
    effectiveIgnoreKeywords: string[]; 
    addIgnoreKeyword: (keyword: string) => void;
    removeIgnoreKeyword: (keyword: string) => void;
    contributionKeywords: string[];
    addContributionKeyword: (keyword: string) => void;
    removeContributionKeyword: (keyword: string) => void;
    learnedAssociations: LearnedAssociation[];

    // Edit States
    editingBank: Bank | null;
    editingChurch: Church | null;
    openEditBank: (bank: Bank) => void;
    closeEditBank: () => void;
    updateBank: (bankId: string, name: string) => void;
    addBank: (name: string) => Promise<boolean>;
    openEditChurch: (church: Church) => void;
    closeEditChurch: () => void;
    updateChurch: (churchId: string, data: ChurchFormData) => void;
    addChurch: (data: ChurchFormData) => Promise<boolean>;

    // Reconciliation State (from useReconciliation)
    bankStatementFile: { bankId: string, content: string, fileName: string, rawFile?: File } | null;
    contributorFiles: { churchId: string; content: string; fileName: string; contributors?: Contributor[] }[];
    matchResults: MatchResult[];
    setMatchResults: React.Dispatch<React.SetStateAction<MatchResult[]>>;
    reportPreviewData: { income: GroupedReportData; expenses: GroupedReportData } | null;
    setReportPreviewData: React.Dispatch<React.SetStateAction<{ income: GroupedReportData; expenses: GroupedReportData } | null>>;
    comparisonType: ComparisonType;
    setComparisonType: React.Dispatch<React.SetStateAction<ComparisonType>>;
    hasActiveSession: boolean;
    setHasActiveSession: React.Dispatch<React.SetStateAction<boolean>>;
    isCompareDisabled: boolean;
    pendingTraining: any;
    setPendingTraining: (val: any) => void;
    activeReportId: string | null;
    setActiveReportId: React.Dispatch<React.SetStateAction<string | null>>;
    activeSpreadsheetData: SpreadsheetData | null;

    // Reconciliation Actions
    openLabManually: (targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => void;
    handleStatementUpload: (content: string, fileName: string, bankId: string, rawFile: File) => void;
    handleContributorsUpload: (content: string, fileName: string, churchId: string, rawFile?: File) => void;
    handleTrainingSuccess: (model: FileModel, data: Transaction[]) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (churchId: string) => void;
    handleCompare: () => void;
    handleBackToSettings: () => void;
    updateReportData: (updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => void;
    discardCurrentReport: () => void;
    resetReconciliation: () => void; 
    handleGmailSyncSuccess: (transactions: Transaction[]) => void; 

    // Manual Operations State & Handlers
    manualIdentificationTx: Transaction | null;
    setManualIdentificationTx: React.Dispatch<React.SetStateAction<Transaction | null>>;
    bulkIdentificationTxs: Transaction[] | null;
    setBulkIdentificationTxs: React.Dispatch<React.SetStateAction<Transaction[] | null>>;

    openManualIdentify: (transactionId: string) => void;
    openBulkManualIdentify: (transactions: Transaction[]) => void;
    closeManualIdentify: () => void;
    confirmManualIdentification: (transactionId: string, churchId: string) => Promise<void>;
    confirmBulkManualIdentification: (transactionIds: string[], churchId: string) => Promise<void>;

    manualMatchState: { record: MatchResult, suggestions: Transaction[] } | null;
    setManualMatchState: React.Dispatch<React.SetStateAction<{ record: MatchResult, suggestions: Transaction[] } | null>>;
    openManualMatchModal: (recordToMatch: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (selectedTx: Transaction) => void;

    // Smart Edit
    smartEditTarget: MatchResult | null;
    openSmartEdit: (match: MatchResult) => void;
    closeSmartEdit: () => void;
    saveSmartEdit: (updatedMatch: MatchResult) => void;

    divergenceConfirmation: MatchResult | null;
    setDivergenceConfirmation: React.Dispatch<React.SetStateAction<MatchResult | null>>;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (divergentMatch: MatchResult) => void;
    rejectDivergence: (divergentMatch: MatchResult) => void;

    undoIdentification: (transactionId: string) => Promise<void>;

    learnAssociation: (matchResult: MatchResult) => Promise<void>;
    findMatchResult: (transactionId: string) => MatchResult | undefined;

    // AI
    loadingAiId: string | null;
    aiSuggestion: { id: string, name: string } | null;
    handleAnalyze: (transaction: Transaction, candidates: Contributor[]) => void;

    // Recompare Modal
    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    // Update Files Modal
    isUpdateFilesModalOpen: boolean;
    openUpdateFilesModal: () => void;
    closeUpdateFilesModal: () => void;

    // Reports & Search (from useReportManager)
    savedReports: SavedReport[];
    maxSavedReports: number;
    searchFilters: SearchFilters;
    setSearchFilters: React.Dispatch<React.SetStateAction<SearchFilters>>;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    clearSearchFilters: () => void;
    allHistoricalResults: MatchResult[];

    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => void;
    viewSavedReport: (reportId: string) => void;
    updateSavedReportName: (reportId: string, newName: string) => void;
    saveFilteredReport: (results: MatchResult[]) => void;
    saveCurrentReportChanges: () => void;
    overwriteSavedReport: (reportId: string, results: MatchResult[], spreadsheetData?: SpreadsheetData) => Promise<void>;
    deleteOldReports: (dateThreshold: Date) => Promise<void>;

    // Global
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;
    initialDataLoaded: boolean;
    isSyncing: boolean;
    summary: {
        autoConfirmed: { count: number; value: number; };
        manualConfirmed: { count: number; value: number; };
        pending: { count: number; value: number; };
        identifiedCount: number;
        unidentifiedCount: number;
        totalValue: number;
        valuePerChurch: [string, number][];
        isHistorical: boolean;
        methodBreakdown: Record<MatchMethod, number>;
    };
    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, systemSettings, incrementAiUsage } = useAuth();
    const { t } = useTranslation();
    const { showToast, setIsLoading, setActiveView } = useUI();

    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    const effectiveIgnoreKeywords = useMemo(() => {
        return systemSettings.globalIgnoreKeywords || [];
    }, [systemSettings.globalIgnoreKeywords]);

    const reconciliation = useReconciliation({
        user, 
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: [],
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: effectiveIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast, setIsLoading, setActiveView
    });

    const [initialDataLoaded, setInitialDataLoaded] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false); 

    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);
    const [isUpdateFilesModalOpen, setIsUpdateFilesModalOpen] = useState(false);

    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);
    const [activeSpreadsheetData, setActiveSpreadsheetData] = useState<SpreadsheetData | null>(null);

    const userSuffix = user ? `-${user.id}` : '-guest';
    const [summary, setSummary] = usePersistentState(`identificapix-dashboard-summary-v6${userSuffix}`, {
        autoConfirmed: { count: 0, value: 0 },
        manualConfirmed: { count: 0, value: 0 },
        pending: { count: 0, value: 0 },
        identifiedCount: 0, unidentifiedCount: 0, totalValue: 0, valuePerChurch: [], isHistorical: false,
        methodBreakdown: { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 }
    }, false);

    // --- FETCH DE DADOS E HIDRATAÇÃO DA LISTA VIVA ---
    useEffect(() => {
        if (!user) {
            setInitialDataLoaded(true);
            return;
        }

        const fetchData = async () => {
            setIsSyncing(true);
            try {
                // 1. Dados de Referência Básicos
                const [churchesRes, banksRes, reportsRes] = await Promise.all([
                    supabase.from('churches').select('*').order('name'),
                    supabase.from('banks').select('*').order('name'),
                    supabase.from('saved_reports')
                        .select('id, name, created_at, record_count, user_id') 
                        .eq('user_id', user.id)
                        .order('created_at', { ascending: false }),
                ]);

                // Atualiza referências
                if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
                const loadedBanks = banksRes.data as Bank[] || [];
                if (banksRes.data) referenceData.setBanks(loadedBanks);

                if (reportsRes.data) {
                    reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null 
                    })));
                }

                // 2. RECUPERAÇÃO DA LISTA VIVA (PERSISTÊNCIA)
                // Busca transações pendentes no banco para restaurar o estado "em andamento"
                const pendingTxs = await consolidationService.getPendingTransactions(user.id);

                if (pendingTxs && pendingTxs.length > 0) {
                    console.log(`[Hydration] Recuperando ${pendingTxs.length} transações vivas do banco.`);

                    // Mapeia para o formato interno de Transação
                    const liveTransactions = pendingTxs.map(dbTx => ({
                        id: dbTx.id,
                        date: dbTx.transaction_date,
                        amount: dbTx.amount,
                        description: dbTx.description,
                        cleanedDescription: dbTx.description, 
                        contributionType: dbTx.type,
                        originalAmount: String(dbTx.amount) // Importante para UI
                    }));

                    // Cria um conteúdo de arquivo virtual para exibição
                    const virtualContent = liveTransactions
                        .map(t => `${t.date};${t.description};${t.amount};${t.contributionType}`)
                        .join('\n');

                    // Define banco alvo (tenta usar o primeiro cadastrado ou um genérico)
                    const targetBankId = loadedBanks.length > 0 ? loadedBanks[0].id : 'active-session-bank';

                    // --- FORÇA A ATUALIZAÇÃO DO ESTADO DA LISTA VIVA ---
                    // Isso garante que ao mudar de tela ou recarregar, os dados voltem.
                    reconciliation.setBankStatementFile({
                        bankId: targetBankId,
                        content: virtualContent,
                        fileName: 'Sessão Ativa (Nuvem)',
                        processedTransactions: liveTransactions as Transaction[],
                        rawFile: undefined // Arquivo original não existe na nuvem, usamos virtual
                    });

                    // Popula resultados de conciliação iniciais (para exibir na tabela imediatamente)
                    if (reconciliation.matchResults.length === 0) {
                        const mappedResults: MatchResult[] = liveTransactions.map(tx => ({
                            transaction: tx as Transaction,
                            contributor: null,
                            status: 'NÃO IDENTIFICADO',
                            church: PLACEHOLDER_CHURCH,
                            matchMethod: undefined,
                            similarity: 0
                        }));

                        reconciliation.setMatchResults(mappedResults);
                        reconciliation.setReportPreviewData({
                            income: groupResultsByChurch(mappedResults),
                            expenses: { 'all_expenses_group': [] }
                        });

                        reconciliation.setHasActiveSession(true);
                    }
                }

            } catch (err) { 
                console.error('Background sync failed', err); 
            } finally { 
                setIsSyncing(false); 
                setInitialDataLoaded(true); 
            }
        };

        fetchData();
    }, [user?.id]);

    // Resumo do Dashboard (Efeito já existente)
    const resultsHash = JSON.stringify(reconciliation.matchResults.map(r => r.transaction.id + r.status));
    const reportsHash = reportManager.savedReports.length;

    useEffect(() => {
        const timer = setTimeout(() => {
            let resultsToProcess = reconciliation.matchResults;
            let isHistorical = false;

            if (resultsToProcess.length === 0 && reportManager.savedReports.length > 0) {
                resultsToProcess = reportManager.savedReports.flatMap(report => report.data?.results || []);
                isHistorical = true;
            }
            const autoConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod));
            const manualConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
            const pending = resultsToProcess.filter(r => r.status === 'NÃO IDENTIFICADO');
            const valuePerChurch = new Map<string, number>();
            const methodBreakdown: Record<MatchMethod, number> = { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 };
            resultsToProcess.forEach(r => {
                if (r.status === 'IDENTIFICADO') {
                    if (r.church && r.church.name !== '---' && r.transaction.amount > 0) {
                        const current = valuePerChurch.get(r.church.name) || 0;
                        valuePerChurch.set(r.church.name, current + r.transaction.amount);
                    }
                    const method = r.matchMethod || 'AUTOMATIC';
                    if (methodBreakdown[method] !== undefined) methodBreakdown[method]++;
                }
            });
            const newTotal = resultsToProcess.reduce((sum, r) => sum + r.transaction.amount, 0);
            setSummary(prev => ({
                autoConfirmed: { count: autoConfirmed.length, value: autoConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                manualConfirmed: { count: manualConfirmed.length, value: manualConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                pending: { count: pending.length, value: pending.reduce((sum, r) => sum + r.transaction.amount, 0) },
                identifiedCount: autoConfirmed.length + manualConfirmed.length,
                unidentifiedCount: pending.length, totalValue: newTotal,
                valuePerChurch: Array.from(valuePerChurch.entries()).sort((a, b) => b[1] - a[1]),
                isHistorical, methodBreakdown
            }));
        }, 300);
        return () => clearTimeout(timer);
    }, [resultsHash, reportsHash]);

    const handleBackToSettings = useCallback(() => setActiveView('upload'), [setActiveView]);
    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);

    const unifiedResetReconciliation = useCallback(() => {
        reconciliation.resetReconciliation();
        setActiveSpreadsheetData(null);
    }, [reconciliation]);

    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;
        if (deletingItem.type === 'report-row') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 Object.keys(targetGroup).forEach(key => { targetGroup[key] = targetGroup[key].filter(r => r.transaction.id !== deletingItem.id); });
                 return newPreview;
             });
             reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
        } else if (deletingItem.type === 'report-group') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 if (targetGroup[deletingItem.id]) {
                     const idsToRemove = targetGroup[deletingItem.id].map(r => r.transaction.id);
                     delete targetGroup[deletingItem.id];
                     reconciliation.setMatchResults(prev => prev.filter(r => !idsToRemove.includes(r.transaction.id)));
                 }
                 return newPreview;
             });
        } else if (deletingItem.type === 'bank') {
            referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
            await supabase.from('banks').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'church') {
            referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
            await supabase.from('churches').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'report-saved') {
            reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
            await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'uploaded-files') { reconciliation.removeBankStatementFile(); }
        closeDeleteConfirmation();
        showToast("Ação realizada com sucesso.");
    }, [deletingItem, user, referenceData, reportManager, reconciliation, showToast, closeDeleteConfirmation]);

    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            let report = reportManager.savedReports.find(r => r.id === reportId);
            if (!report) return;

            if (!report.data) {
                const { data: reportContent, error } = await supabase
                    .from('saved_reports')
                    .select('data')
                    .eq('id', reportId)
                    .single();

                if (error) throw error;

                if (reportContent) {
                    const parsedData = typeof reportContent.data === 'string' 
                        ? JSON.parse(reportContent.data) 
                        : reportContent.data;

                    report = { ...report, data: parsedData };
                    reportManager.setSavedReports(prev => prev.map(r => r.id === reportId ? report! : r));
                }
            }

            if (!report.data) throw new Error("Conteúdo do relatório vazio.");

            reconciliation.clearFiles();
            setActiveSpreadsheetData(null);

            if (report.data.spreadsheet) {
                setActiveSpreadsheetData(report.data.spreadsheet);
                reconciliation.setActiveReportId(reportId);
                setActiveView('smart_analysis');
                showToast(`Planilha "${report.name}" carregada.`, "success");
            } else {
                const validResults = report.data.results.map((r: any) => ({ ...r, church: r.church || PLACEHOLDER_CHURCH }));
                reconciliation.setMatchResults(validResults);
                reconciliation.setReportPreviewData({
                    income: groupResultsByChurch(validResults.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': validResults.filter((r: any) => r.transaction.amount < 0) }
                });
                reconciliation.setHasActiveSession(true); 
                reconciliation.setActiveReportId(reportId); 
                setActiveView('reports'); 
                showToast(`Relatório "${report.name}" carregado.`, "success");
            }

        } catch (error: any) {
            console.error(error);
            showToast("Erro ao abrir relatório: " + error.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, reconciliation, setActiveView, setIsLoading, showToast]);

    const saveCurrentReportChanges = useCallback(() => {
        const reportId = reconciliation.activeReportId;
        if (!reportId) {
            showToast("Nenhum relatório salvo ativo para atualizar.", "error");
            return;
        }
        reportManager.overwriteSavedReport(reportId, reconciliation.matchResults);
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager, showToast]);

    const findMatchResult = useCallback((transactionId: string) => reconciliation.matchResults.find(r => r.transaction.id === transactionId) || reportManager.allHistoricalResults.find(r => r.transaction.id === transactionId), [reconciliation.matchResults, reportManager.allHistoricalResults]);

    const openManualIdentify = useCallback((transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result) reconciliation.setManualIdentificationTx(result.transaction);
    }, [findMatchResult, reconciliation]);

    const openBulkManualIdentify = useCallback((transactions: Transaction[]) => { reconciliation.setBulkIdentificationTxs(transactions); }, [reconciliation]);

    // --- INTEGRATED IDENTIFICATION FLOW ---
    const confirmManualIdentification = useCallback(async (transactionId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        const result = findMatchResult(transactionId);

        if (church && result) {
            const updated: MatchResult = { ...result, status: 'IDENTIFICADO', church, contributor: { id: `manual-${transactionId}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, matchMethod: 'MANUAL', similarity: 100, contributorAmount: result.transaction.amount };

            // 1. Update UI first (Optimistic)
            if (reconciliation.matchResults.some(r => r.transaction.id === transactionId)) reconciliation.updateReportData(updated, 'income');
            else reportManager.updateSavedReportTransaction(transactionId, updated);

            reconciliation.closeManualIdentify(); 
            showToast('Identificação realizada.', 'success');

            // 2. Update Database (Lista Viva)
            try {
                await consolidationService.markAsIdentified(transactionId);
            } catch (e) {
                console.error("Falha ao atualizar status no banco", e);
                // Não revertemos a UI para não travar o fluxo, mas logamos o erro
            }
        }
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const confirmBulkManualIdentification = useCallback(async (transactionIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        const updates: Promise<void>[] = [];

        transactionIds.forEach(id => {
            const result = findMatchResult(id);
            if (result) {
                const updated: MatchResult = { 
                    ...result, 
                    status: 'IDENTIFICADO', 
                    church, 
                    contributor: { id: `manual-${id}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, 
                    matchMethod: 'MANUAL', 
                    similarity: 100, 
                    contributorAmount: result.transaction.amount 
                };

                // 1. Update UI
                if (reconciliation.matchResults.some(r => r.transaction.id === id)) reconciliation.updateReportData(updated, 'income');
                else reportManager.updateSavedReportTransaction(id, updated);

                // 2. Queue DB Update
                updates.push(consolidationService.markAsIdentified(id));
            }
        });

        reconciliation.closeManualIdentify();
        showToast(`${transactionIds.length} transações identificadas.`, 'success');

        // 3. Execute DB Updates
        try {
            await Promise.all(updates);
        } catch (e) {
            console.error("Falha na atualização em massa do banco", e);
        }

    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const openSmartEdit = useCallback((match: MatchResult) => {
        setSmartEditTarget(match);
    }, []);

    const closeSmartEdit = useCallback(() => {
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);
    }, [reconciliation]);

    const saveSmartEdit = useCallback((updatedMatch: MatchResult) => {
        // UI Update
        if (reconciliation.matchResults.some(r => r.transaction.id === updatedMatch.transaction.id)) {
            const ghostId = smartEditTarget?.status === 'PENDENTE' ? smartEditTarget.transaction.id : undefined;
            reconciliation.updateReportData(updatedMatch, 'income', ghostId);
        } else {
            reportManager.updateSavedReportTransaction(updatedMatch.transaction.id, updatedMatch);
        }

        showToast("Edição aplicada na tabela.", "success");
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);

        // DB Update (if identified)
        if (updatedMatch.status === 'IDENTIFICADO') {
            consolidationService.markAsIdentified(updatedMatch.transaction.id).catch(console.error);
        }

    }, [reconciliation, reportManager, showToast, smartEditTarget]);

    const undoIdentification = useCallback(async (transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result) {
            const reverted: MatchResult = {
                ...result,
                status: 'NÃO IDENTIFICADO',
                contributor: null,
                matchMethod: undefined,
                similarity: undefined,
                contributorAmount: undefined,
                divergence: undefined,
                suggestion: undefined 
            };

            // 1. Update UI
            if (reconciliation.matchResults.some(r => r.transaction.id === transactionId)) {
                reconciliation.updateReportData(reverted, 'income');
            } else {
                reportManager.updateSavedReportTransaction(transactionId, reverted);
            }

            showToast('Identificação revertida.', 'success');

            // 2. Update DB
            try {
                await consolidationService.markAsPending(transactionId);
            } catch (e) {
                console.error("Falha ao reverter status no banco", e);
            }
        }
    }, [findMatchResult, reconciliation, reportManager, showToast]);

    const handleAnalyze = useCallback(async (transaction: Transaction, candidates: Contributor[]) => {
        reconciliation.setLoadingAiId(transaction.id);
        try {
            const candidateNames = candidates.slice(0, 50).map(c => c.name);
            const response = await fetch('/api/ai/suggestion', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    transactionDescription: transaction.description,
                    contributorNames: candidateNames
                })
            });

            if (!response.ok) throw new Error('Falha na API de IA');
            const data = await response.json();
            const suggestionText = data.text;

            if (suggestionText && !suggestionText.includes("Nenhuma sugestão clara")) {
                reconciliation.setAiSuggestion({ id: transaction.id, name: suggestionText });
                incrementAiUsage(); 
            } else {
                reconciliation.setAiSuggestion(null);
            }
        } catch (error) {
            console.error("Erro na análise IA:", error);
            showToast("Não foi possível obter sugestão da IA.", "error");
        } finally {
            reconciliation.setLoadingAiId(null);
        }
    }, [incrementAiUsage, showToast, reconciliation]);

    const handleGmailSyncSuccess = useCallback(async (transactions: Transaction[]) => {
        if (transactions.length === 0) return;

        // 1. CONSOLIDATION (DB PERSISTENCE)
        if (user) {
            const consolidationData = transactions.map(t => ({
                transaction_date: t.date,
                amount: t.amount,
                description: t.description,
                type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                pix_key: null,
                source: 'gmail' as 'gmail',
                user_id: user.id
            }));
            await consolidationService.addTransactions(consolidationData);
        }

        // 2. STATE UPDATE
        if (reconciliation.activeReportId) {
            // --- INSIDE REPORT FLOW ---
            reconciliation.setMatchResults(prev => {
                const existingIds = new Set(prev.map(r => r.transaction.id));

                const newMatches: MatchResult[] = transactions
                    .filter(t => !existingIds.has(t.id)) // Deduplicate against current view
                    .map(t => ({
                        transaction: t,
                        contributor: null,
                        status: 'NÃO IDENTIFICADO',
                        church: PLACEHOLDER_CHURCH,
                        matchMethod: undefined,
                        similarity: 0
                    }));

                if (newMatches.length === 0) {
                    showToast("Nenhuma transação nova encontrada.", "error");
                    return prev;
                }

                // Append new results
                const nextResults = [...prev, ...newMatches];

                // Update Preview Data (Visual Groups)
                reconciliation.setReportPreviewData(currentPreview => {
                    if (!currentPreview) return null;
                    const nextPreview = { ...currentPreview };

                    // Add income/expenses to respective unidentified groups
                    const newIncome = newMatches.filter(r => r.transaction.amount > 0);
                    const newExpenses = newMatches.filter(r => r.transaction.amount < 0);

                    if (newIncome.length > 0) {
                        nextPreview.income['unidentified'] = [
                            ...(nextPreview.income['unidentified'] || []),
                            ...newIncome
                        ];
                    }
                    if (newExpenses.length > 0) {
                        nextPreview.expenses['all_expenses_group'] = [
                            ...(nextPreview.expenses['all_expenses_group'] || []),
                            ...newExpenses
                        ];
                    }
                    return nextPreview;
                });

                showToast(`${newMatches.length} novas transações adicionadas ao relatório.`, 'success');
                return nextResults;
            });

        } else {
            // --- OUTSIDE REPORT FLOW (Original + Enhanced) ---
            const virtualFileName = `Importação Gmail - ${new Date().toLocaleDateString()}`;

            reconciliation.setBankStatementFile(prev => {
                const existingTxs = prev?.processedTransactions || [];
                // Deduplicate against the virtual file being viewed
                const newTxs = transactions.filter(nt => !existingTxs.some(et => et.id === nt.id));

                if (newTxs.length === 0 && existingTxs.length > 0) {
                     showToast("Nenhuma transação nova.", "error");
                     return prev;
                }

                const merged = [...existingTxs, ...newTxs];

                // Also update the live match results if we are viewing the live list
                if (reconciliation.hasActiveSession) {
                     const newMatches: MatchResult[] = newTxs.map(t => ({
                        transaction: t,
                        contributor: null,
                        status: 'NÃO IDENTIFICADO',
                        church: PLACEHOLDER_CHURCH,
                        matchMethod: undefined,
                        similarity: 0
                    }));

                    reconciliation.setMatchResults(prevResults => [...prevResults, ...newMatches]);
                    reconciliation.setReportPreviewData(prevPreview => {
                        if (!prevPreview) return null;
                        const nextPreview = { ...prevPreview };
                        const newIncome = newMatches.filter(r => r.transaction.amount > 0);
                        const newExpenses = newMatches.filter(r => r.transaction.amount < 0);

                        if (newIncome.length > 0) nextPreview.income['unidentified'] = [...(nextPreview.income['unidentified']||[]), ...newIncome];
                        if (newExpenses.length > 0) nextPreview.expenses['all_expenses_group'] = [...(nextPreview.expenses['all_expenses_group']||[]), ...newExpenses];

                        return nextPreview;
                    });
                }

                return {
                    bankId: prev?.bankId || 'gmail-bank',
                    content: prev?.content || 'GMAIL_VIRTUAL_CONTENT',
                    fileName: prev?.fileName || virtualFileName,
                    processedTransactions: merged
                };
            });

            if (!reconciliation.activeReportId) {
                 showToast(`${transactions.length} transações sincronizadas.`, 'success');
            }
        }

    }, [reconciliation, showToast, user]);

    const value = useMemo(() => ({
        ...referenceData, ...reconciliation, isCompareDisabled: !reconciliation.bankStatementFile,
        effectiveIgnoreKeywords, 
        openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult,
        ...reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation,
        closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true), closePaymentModal: () => setIsPaymentModalOpen(false),
        isRecompareModalOpen, openRecompareModal: () => setIsRecompareModalOpen(true), closeRecompareModal: () => setIsRecompareModalOpen(false),
        smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze,
        saveCurrentReportChanges,
        handleGmailSyncSuccess,
        resetReconciliation: unifiedResetReconciliation,
        activeSpreadsheetData,
        isUpdateFilesModalOpen, 
        openUpdateFilesModal: () => setIsUpdateFilesModalOpen(true), 
        closeUpdateFilesModal: () => setIsUpdateFilesModalOpen(false),
        undoIdentification
    }), [referenceData, reconciliation, effectiveIgnoreKeywords, reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation, closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen, isRecompareModalOpen, openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult, smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze, saveCurrentReportChanges, handleGmailSyncSuccess, unifiedResetReconciliation, activeSpreadsheetData, isUpdateFilesModalOpen, undoIdentification]);

    return <AppContext.Provider value={value}>{children}<RecompareModal /></AppContext.Provider>;
};

import React, { createContext, useState, useMemo, useCallback, useEffect, useRef } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReconciliation } from '../hooks/useReconciliation';
import { useReportManager } from '../hooks/useReportManager';
import { usePersistentState } from '../hooks/usePersistentState';
import {
    Transaction, Contributor, MatchResult, Bank, Church, ChurchFormData,
    DeletingItem, ComparisonType, GroupedReportData, SearchFilters, SavedReport,
    SavingReportState, LearnedAssociation, MatchMethod, FileModel, SpreadsheetData
} from '../types';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';

import { supabase } from '../services/supabaseClient';
import { useTranslation } from './I18nContext';
import { LoadingSpinner } from '../components/shared/LoadingSpinner';
import { RecompareModal } from '../components/modals/RecompareModal';
import { consolidationService } from '../services/ConsolidationService';

interface AppContextType {
    // Data State (from useReferenceData)
    banks: Bank[];
    churches: Church[];
    fileModels: FileModel[];
    fetchModels: () => Promise<void>;
    setBanks: React.Dispatch<React.SetStateAction<Bank[]>>;
    setChurches: React.Dispatch<React.SetStateAction<Church[]>>;
    similarityLevel: number;
    setSimilarityLevel: React.Dispatch<React.SetStateAction<number>>;
    dayTolerance: number;
    setDayTolerance: React.Dispatch<React.SetStateAction<number>>;
    customIgnoreKeywords: string[]; 
    effectiveIgnoreKeywords: string[]; 
    addIgnoreKeyword: (keyword: string) => void;
    removeIgnoreKeyword: (keyword: string) => void;
    contributionKeywords: string[];
    addContributionKeyword: (keyword: string) => void;
    removeContributionKeyword: (keyword: string) => void;
    learnedAssociations: LearnedAssociation[];

    // Edit States
    editingBank: Bank | null;
    editingChurch: Church | null;
    openEditBank: (bank: Bank) => void;
    closeEditBank: () => void;
    updateBank: (bankId: string, name: string) => void;
    addBank: (name: string) => Promise<boolean>;
    openEditChurch: (church: Church) => void;
    closeEditChurch: () => void;
    updateChurch: (churchId: string, data: ChurchFormData) => void;
    addChurch: (data: ChurchFormData) => Promise<boolean>;

    // Reconciliation State (from useReconciliation)
    bankStatementFile: { bankId: string, content: string, fileName: string, rawFile?: File } | null;
    contributorFiles: { churchId: string; content: string; fileName: string; contributors?: Contributor[] }[];
    matchResults: MatchResult[];
    setMatchResults: React.Dispatch<React.SetStateAction<MatchResult[]>>;
    reportPreviewData: { income: GroupedReportData; expenses: GroupedReportData } | null;
    setReportPreviewData: React.Dispatch<React.SetStateAction<{ income: GroupedReportData; expenses: GroupedReportData } | null>>;
    comparisonType: ComparisonType;
    setComparisonType: React.Dispatch<React.SetStateAction<ComparisonType>>;
    hasActiveSession: boolean;
    setHasActiveSession: React.Dispatch<React.SetStateAction<boolean>>;
    isCompareDisabled: boolean;
    pendingTraining: any;
    setPendingTraining: (val: any) => void;
    activeReportId: string | null;
    setActiveReportId: React.Dispatch<React.SetStateAction<string | null>>;
    activeSpreadsheetData: SpreadsheetData | null;

    // Reconciliation Actions
    openLabManually: (targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => void;
    handleStatementUpload: (content: string, fileName: string, bankId: string, rawFile: File) => void;
    handleContributorsUpload: (content: string, fileName: string, churchId: string, rawFile?: File) => void;
    handleTrainingSuccess: (model: FileModel, data: Transaction[]) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (churchId: string) => void;
    handleCompare: () => void;
    handleBackToSettings: () => void;
    updateReportData: (updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => void;
    discardCurrentReport: () => void;
    resetReconciliation: () => void; 
    handleGmailSyncSuccess: (transactions: Transaction[]) => void; 

    // Manual Operations State & Handlers
    manualIdentificationTx: Transaction | null;
    setManualIdentificationTx: React.Dispatch<React.SetStateAction<Transaction | null>>;
    bulkIdentificationTxs: Transaction[] | null;
    setBulkIdentificationTxs: React.Dispatch<React.SetStateAction<Transaction[] | null>>;

    openManualIdentify: (transactionId: string) => void;
    openBulkManualIdentify: (transactions: Transaction[]) => void;
    closeManualIdentify: () => void;
    confirmManualIdentification: (transactionId: string, churchId: string) => Promise<void>;
    confirmBulkManualIdentification: (transactionIds: string[], churchId: string) => Promise<void>;

    manualMatchState: { record: MatchResult, suggestions: Transaction[] } | null;
    setManualMatchState: React.Dispatch<React.SetStateAction<{ record: MatchResult, suggestions: Transaction[] } | null>>;
    openManualMatchModal: (recordToMatch: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (selectedTx: Transaction) => void;

    // Smart Edit
    smartEditTarget: MatchResult | null;
    openSmartEdit: (match: MatchResult) => void;
    closeSmartEdit: () => void;
    saveSmartEdit: (updatedMatch: MatchResult) => void;

    divergenceConfirmation: MatchResult | null;
    setDivergenceConfirmation: React.Dispatch<React.SetStateAction<MatchResult | null>>;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (divergentMatch: MatchResult) => void;
    rejectDivergence: (divergentMatch: MatchResult) => void;

    undoIdentification: (transactionId: string) => Promise<void>;

    learnAssociation: (matchResult: MatchResult) => Promise<void>;
    findMatchResult: (transactionId: string) => MatchResult | undefined;

    // AI
    loadingAiId: string | null;
    aiSuggestion: { id: string, name: string } | null;
    handleAnalyze: (transaction: Transaction, candidates: Contributor[]) => void;

    // Recompare Modal
    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    // Update Files Modal
    isUpdateFilesModalOpen: boolean;
    openUpdateFilesModal: () => void;
    closeUpdateFilesModal: () => void;

    // Reports & Search (from useReportManager)
    savedReports: SavedReport[];
    maxSavedReports: number;
    searchFilters: SearchFilters;
    setSearchFilters: React.Dispatch<React.SetStateAction<SearchFilters>>;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    clearSearchFilters: () => void;
    allHistoricalResults: MatchResult[];

    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => void;
    viewSavedReport: (reportId: string) => void;
    updateSavedReportName: (reportId: string, newName: string) => void;
    saveFilteredReport: (results: MatchResult[]) => void;
    saveCurrentReportChanges: () => void;
    overwriteSavedReport: (reportId: string, results: MatchResult[], spreadsheetData?: SpreadsheetData) => Promise<void>;
    deleteOldReports: (dateThreshold: Date) => Promise<void>;

    // Global
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;
    initialDataLoaded: boolean;
    isSyncing: boolean;
    summary: {
        autoConfirmed: { count: number; value: number; };
        manualConfirmed: { count: number; value: number; };
        pending: { count: number; value: number; };
        identifiedCount: number;
        unidentifiedCount: number;
        totalValue: number;
        valuePerChurch: [string, number][];
        isHistorical: boolean;
        methodBreakdown: Record<MatchMethod, number>;
    };
    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, systemSettings, incrementAiUsage } = useAuth();
    const { t } = useTranslation();
    const { showToast, setIsLoading, setActiveView } = useUI();

    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    const effectiveIgnoreKeywords = useMemo(() => {
        return systemSettings.globalIgnoreKeywords || [];
    }, [systemSettings.globalIgnoreKeywords]);

    const reconciliation = useReconciliation({
        user, 
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: [],
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: effectiveIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast, setIsLoading, setActiveView
    });

    const [initialDataLoaded, setInitialDataLoaded] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false); 

    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);
    const [isUpdateFilesModalOpen, setIsUpdateFilesModalOpen] = useState(false);

    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);
    const [activeSpreadsheetData, setActiveSpreadsheetData] = useState<SpreadsheetData | null>(null);

    const userSuffix = user ? `-${user.id}` : '-guest';
    const [summary, setSummary] = usePersistentState(`identificapix-dashboard-summary-v6${userSuffix}`, {
        autoConfirmed: { count: 0, value: 0 },
        manualConfirmed: { count: 0, value: 0 },
        pending: { count: 0, value: 0 },
        identifiedCount: 0, unidentifiedCount: 0, totalValue: 0, valuePerChurch: [], isHistorical: false,
        methodBreakdown: { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 }
    }, false);

    // --- FETCH DE DADOS E HIDRATAÇÃO DA LISTA VIVA ---
    useEffect(() => {
        if (!user) {
            setInitialDataLoaded(true);
            return;
        }

        const fetchData = async () => {
            setIsSyncing(true);
            try {
                // 1. Dados de Referência Básicos
                const [churchesRes, banksRes, reportsRes] = await Promise.all([
                    supabase.from('churches').select('*').order('name'),
                    supabase.from('banks').select('*').order('name'),
                    supabase.from('saved_reports')
                        .select('id, name, created_at, record_count, user_id') 
                        .eq('user_id', user.id)
                        .order('created_at', { ascending: false }),
                ]);

                // Atualiza referências
                if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
                const loadedBanks = banksRes.data as Bank[] || [];
                if (banksRes.data) referenceData.setBanks(loadedBanks);

                if (reportsRes.data) {
                    reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null 
                    })));
                }

                // 2. RECUPERAÇÃO DA LISTA VIVA (PERSISTÊNCIA)
                // Busca transações pendentes no banco para restaurar o estado "em andamento"
                const pendingTxs = await consolidationService.getPendingTransactions(user.id);

                if (pendingTxs && pendingTxs.length > 0) {
                    console.log(`[Hydration] Recuperando ${pendingTxs.length} transações vivas do banco.`);

                    // Mapeia para o formato interno de Transação
                    const liveTransactions = pendingTxs.map(dbTx => ({
                        id: dbTx.id,
                        date: dbTx.transaction_date,
                        amount: dbTx.amount,
                        description: dbTx.description,
                        cleanedDescription: dbTx.description, 
                        contributionType: dbTx.type,
                        originalAmount: String(dbTx.amount) // Importante para UI
                    }));

                    // Cria um conteúdo de arquivo virtual para exibição
                    const virtualContent = liveTransactions
                        .map(t => `${t.date};${t.description};${t.amount};${t.contributionType}`)
                        .join('\n');

                    // Define banco alvo (tenta usar o primeiro cadastrado ou um genérico)
                    const targetBankId = loadedBanks.length > 0 ? loadedBanks[0].id : 'active-session-bank';

                    // --- FORÇA A ATUALIZAÇÃO DO ESTADO DA LISTA VIVA ---
                    // Isso garante que ao mudar de tela ou recarregar, os dados voltem.
                    reconciliation.setBankStatementFile({
                        bankId: targetBankId,
                        content: virtualContent,
                        fileName: 'Sessão Ativa (Nuvem)',
                        processedTransactions: liveTransactions as Transaction[],
                        rawFile: undefined // Arquivo original não existe na nuvem, usamos virtual
                    });

                    // Popula resultados de conciliação iniciais (para exibir na tabela imediatamente)
                    if (reconciliation.matchResults.length === 0) {
                        const mappedResults: MatchResult[] = liveTransactions.map(tx => ({
                            transaction: tx as Transaction,
                            contributor: null,
                            status: 'NÃO IDENTIFICADO',
                            church: PLACEHOLDER_CHURCH,
                            matchMethod: undefined,
                            similarity: 0
                        }));

                        reconciliation.setMatchResults(mappedResults);
                        reconciliation.setReportPreviewData({
                            income: groupResultsByChurch(mappedResults),
                            expenses: { 'all_expenses_group': [] }
                        });

                        reconciliation.setHasActiveSession(true);
                    }
                }

            } catch (err) { 
                console.error('Background sync failed', err); 
            } finally { 
                setIsSyncing(false); 
                setInitialDataLoaded(true); 
            }
        };

        fetchData();
    }, [user?.id]);

    // Resumo do Dashboard (Efeito já existente)
    const resultsHash = JSON.stringify(reconciliation.matchResults.map(r => r.transaction.id + r.status));
    const reportsHash = reportManager.savedReports.length;

    useEffect(() => {
        const timer = setTimeout(() => {
            let resultsToProcess = reconciliation.matchResults;
            let isHistorical = false;

            if (resultsToProcess.length === 0 && reportManager.savedReports.length > 0) {
                resultsToProcess = reportManager.savedReports.flatMap(report => report.data?.results || []);
                isHistorical = true;
            }
            const autoConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'AUTOMATIC' || r.matchMethod === 'LEARNED' || !r.matchMethod));
            const manualConfirmed = resultsToProcess.filter(r => r.status === 'IDENTIFICADO' && (r.matchMethod === 'MANUAL' || r.matchMethod === 'AI'));
            const pending = resultsToProcess.filter(r => r.status === 'NÃO IDENTIFICADO');
            const valuePerChurch = new Map<string, number>();
            const methodBreakdown: Record<MatchMethod, number> = { 'AUTOMATIC': 0, 'MANUAL': 0, 'LEARNED': 0, 'AI': 0, 'TEMPLATE': 0 };
            resultsToProcess.forEach(r => {
                if (r.status === 'IDENTIFICADO') {
                    if (r.church && r.church.name !== '---' && r.transaction.amount > 0) {
                        const current = valuePerChurch.get(r.church.name) || 0;
                        valuePerChurch.set(r.church.name, current + r.transaction.amount);
                    }
                    const method = r.matchMethod || 'AUTOMATIC';
                    if (methodBreakdown[method] !== undefined) methodBreakdown[method]++;
                }
            });
            const newTotal = resultsToProcess.reduce((sum, r) => sum + r.transaction.amount, 0);
            setSummary(prev => ({
                autoConfirmed: { count: autoConfirmed.length, value: autoConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                manualConfirmed: { count: manualConfirmed.length, value: manualConfirmed.reduce((sum, r) => sum + r.transaction.amount, 0) },
                pending: { count: pending.length, value: pending.reduce((sum, r) => sum + r.transaction.amount, 0) },
                identifiedCount: autoConfirmed.length + manualConfirmed.length,
                unidentifiedCount: pending.length, totalValue: newTotal,
                valuePerChurch: Array.from(valuePerChurch.entries()).sort((a, b) => b[1] - a[1]),
                isHistorical, methodBreakdown
            }));
        }, 300);
        return () => clearTimeout(timer);
    }, [resultsHash, reportsHash]);

    const handleBackToSettings = useCallback(() => setActiveView('upload'), [setActiveView]);
    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);

    const unifiedResetReconciliation = useCallback(() => {
        reconciliation.resetReconciliation();
        setActiveSpreadsheetData(null);
    }, [reconciliation]);

    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;
        if (deletingItem.type === 'report-row') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 Object.keys(targetGroup).forEach(key => { targetGroup[key] = targetGroup[key].filter(r => r.transaction.id !== deletingItem.id); });
                 return newPreview;
             });
             reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
        } else if (deletingItem.type === 'report-group') {
             reconciliation.setReportPreviewData(prev => {
                 if (!prev) return null;
                 const newPreview = { ...prev };
                 const targetGroup = deletingItem.meta?.reportType === 'expenses' ? newPreview.expenses : newPreview.income;
                 if (targetGroup[deletingItem.id]) {
                     const idsToRemove = targetGroup[deletingItem.id].map(r => r.transaction.id);
                     delete targetGroup[deletingItem.id];
                     reconciliation.setMatchResults(prev => prev.filter(r => !idsToRemove.includes(r.transaction.id)));
                 }
                 return newPreview;
             });
        } else if (deletingItem.type === 'bank') {
            referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
            await supabase.from('banks').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'church') {
            referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
            await supabase.from('churches').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'report-saved') {
            reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
            await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
        } else if (deletingItem.type === 'uploaded-files') { reconciliation.removeBankStatementFile(); }
        closeDeleteConfirmation();
        showToast("Ação realizada com sucesso.");
    }, [deletingItem, user, referenceData, reportManager, reconciliation, showToast, closeDeleteConfirmation]);

    // --- VIEW SAVED REPORT (LÓGICA HÍBRIDA) ---
    // Mescla dados identificados (histórico do relatório) com dados pendentes (lista viva global)
    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            // 1. Localiza o relatório salvo (pode ser necessário fetch detalhado se estiver apenas com resumo)
            let report = reportManager.savedReports.find(r => r.id === reportId);

            if (!report) {
                // Fallback para buscar diretamente se não estiver na lista (ex: link direto)
                const { data: dbReport, error } = await supabase.from('saved_reports').select('*').eq('id', reportId).single();
                if (error || !dbReport) throw new Error("Relatório não encontrado.");

                const parsedData = typeof dbReport.data === 'string' ? JSON.parse(dbReport.data as string) : dbReport.data;
                report = {
                    id: dbReport.id,
                    name: dbReport.name,
                    createdAt: dbReport.created_at,
                    recordCount: dbReport.record_count,
                    user_id: dbReport.user_id,
                    data: parsedData
                };
            } else if (!report.data) {
                // Hidratação sob demanda se o conteúdo não estiver carregado
                const { data: reportContent, error } = await supabase
                    .from('saved_reports')
                    .select('data')
                    .eq('id', reportId)
                    .single();

                if (error) throw error;

                if (reportContent) {
                    const parsedData = typeof reportContent.data === 'string' 
                        ? JSON.parse(reportContent.data) 
                        : reportContent.data;

                    report = { ...report, data: parsedData };
                    // Atualiza cache local
                    reportManager.setSavedReports(prev => prev.map(r => r.id === reportId ? report! : r));
                }
            }

            if (!report || !report.data) throw new Error("Conteúdo do relatório vazio.");

            reconciliation.clearFiles();
            setActiveSpreadsheetData(null);

            if (report.data.spreadsheet) {
                setActiveSpreadsheetData(report.data.spreadsheet);
                reconciliation.setActiveReportId(reportId);
                setActiveView('smart_analysis');
                showToast(`Planilha "${report.name}" carregada.`, "success");
            } else {
                // 2. RECUPERA LISTA VIVA (Global Pending) DO BANCO
                // Isso garante que a aba "Pendentes" mostre o estado atual do trabalho, não o estado antigo
                let livePendingTransactions: Transaction[] = [];
                if (user) {
                    const pendingDb = await consolidationService.getPendingTransactions(user.id);
                    livePendingTransactions = pendingDb.map(tx => ({
                        id: tx.id,
                        date: tx.transaction_date,
                        amount: tx.amount,
                        description: tx.description,
                        cleanedDescription: tx.description,
                        contributionType: tx.type,
                        originalAmount: String(tx.amount)
                    }));
                }

                // 3. FILTRA APENAS OS IDENTIFICADOS DO RELATÓRIO SALVO
                // Ignora os pendentes que foram salvos no JSON, pois eles podem estar obsoletos
                const savedIdentifiedResults = report.data.results
                    .filter((r: any) => r.status === 'IDENTIFICADO' || r.status === 'RESOLVED')
                    .map((r: any) => ({ 
                        ...r, 
                        // Garante que o objeto church esteja presente (hidratação)
                        church: r.church || referenceData.churches.find(c => c.id === r._churchId) || PLACEHOLDER_CHURCH 
                    }));

                // 4. PREPARA OS PENDENTES VIVOS (Live List)
                const livePendingResults: MatchResult[] = livePendingTransactions.map(tx => ({
                    transaction: tx,
                    contributor: null,
                    status: 'NÃO IDENTIFICADO',
                    church: PLACEHOLDER_CHURCH,
                    matchMethod: undefined,
                    similarity: 0
                }));

                // 5. COMBINA (Identificados Históricos + Pendentes Atuais)
                const combinedResults = [...savedIdentifiedResults, ...livePendingResults];

                reconciliation.setMatchResults(combinedResults);
                reconciliation.setReportPreviewData({
                    income: groupResultsByChurch(combinedResults.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': combinedResults.filter((r: any) => r.transaction.amount < 0) }
                });

                reconciliation.setHasActiveSession(true); 
                reconciliation.setActiveReportId(reportId); 
                setActiveView('reports'); 
                showToast(`Relatório "${report.name}" carregado com Lista Viva atualizada.`, "success");
            }

        } catch (error: any) {
            console.error(error);
            showToast("Erro ao abrir relatório: " + error.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, reconciliation, setActiveView, setIsLoading, showToast, user, referenceData.churches]);

    const saveCurrentReportChanges = useCallback(() => {
        const reportId = reconciliation.activeReportId;
        if (!reportId) {
            showToast("Nenhum relatório salvo ativo para atualizar.", "error");
            return;
        }
        reportManager.overwriteSavedReport(reportId, reconciliation.matchResults);
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager, showToast]);

    const findMatchResult = useCallback((transactionId: string) => reconciliation.matchResults.find(r => r.transaction.id === transactionId) || reportManager.allHistoricalResults.find(r => r.transaction.id === transactionId), [reconciliation.matchResults, reportManager.allHistoricalResults]);

    const openManualIdentify = useCallback((transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result) reconciliation.setManualIdentificationTx(result.transaction);
    }, [findMatchResult, reconciliation]);

    const openBulkManualIdentify = useCallback((transactions: Transaction[]) => { reconciliation.setBulkIdentificationTxs(transactions); }, [reconciliation]);

    // --- INTEGRATED IDENTIFICATION FLOW ---
    const confirmManualIdentification = useCallback(async (transactionId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        const result = findMatchResult(transactionId);

        if (church && result) {
            const updated: MatchResult = { ...result, status: 'IDENTIFICADO', church, contributor: { id: `manual-${transactionId}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, matchMethod: 'MANUAL', similarity: 100, contributorAmount: result.transaction.amount };

            // 1. Update UI first (Optimistic)
            if (reconciliation.matchResults.some(r => r.transaction.id === transactionId)) reconciliation.updateReportData(updated, 'income');
            else reportManager.updateSavedReportTransaction(transactionId, updated);

            reconciliation.closeManualIdentify(); 
            showToast('Identificação realizada.', 'success');

            // 2. Update Database (Lista Viva)
            try {
                await consolidationService.markAsIdentified(transactionId);
            } catch (e) {
                console.error("Falha ao atualizar status no banco", e);
                // Não revertemos a UI para não travar o fluxo, mas logamos o erro
            }
        }
    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const confirmBulkManualIdentification = useCallback(async (transactionIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        const updates: Promise<void>[] = [];

        transactionIds.forEach(id => {
            const result = findMatchResult(id);
            if (result) {
                const updated: MatchResult = { 
                    ...result, 
                    status: 'IDENTIFICADO', 
                    church, 
                    contributor: { id: `manual-${id}`, name: result.transaction.cleanedDescription || result.transaction.description, amount: result.transaction.amount }, 
                    matchMethod: 'MANUAL', 
                    similarity: 100, 
                    contributorAmount: result.transaction.amount 
                };

                // 1. Update UI
                if (reconciliation.matchResults.some(r => r.transaction.id === id)) reconciliation.updateReportData(updated, 'income');
                else reportManager.updateSavedReportTransaction(id, updated);

                // 2. Queue DB Update
                updates.push(consolidationService.markAsIdentified(id));
            }
        });

        reconciliation.closeManualIdentify();
        showToast(`${transactionIds.length} transações identificadas.`, 'success');

        // 3. Execute DB Updates
        try {
            await Promise.all(updates);
        } catch (e) {
            console.error("Falha na atualização em massa do banco", e);
        }

    }, [referenceData.churches, findMatchResult, reconciliation, reportManager, showToast]);

    const openSmartEdit = useCallback((match: MatchResult) => {
        setSmartEditTarget(match);
    }, []);

    const closeSmartEdit = useCallback(() => {
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);
    }, [reconciliation]);

    const saveSmartEdit = useCallback((updatedMatch: MatchResult) => {
        // UI Update
        if (reconciliation.matchResults.some(r => r.transaction.id === updatedMatch.transaction.id)) {
            const ghostId = smartEditTarget?.status === 'PENDENTE' ? smartEditTarget.transaction.id : undefined;
            reconciliation.updateReportData(updatedMatch, 'income', ghostId);
        } else {
            reportManager.updateSavedReportTransaction(updatedMatch.transaction.id, updatedMatch);
        }

        showToast("Edição aplicada na tabela.", "success");
        setSmartEditTarget(null);
        reconciliation.setAiSuggestion(null);

        // DB Update (if identified)
        if (updatedMatch.status === 'IDENTIFICADO') {
            consolidationService.markAsIdentified(updatedMatch.transaction.id).catch(console.error);
        }

    }, [reconciliation, reportManager, showToast, smartEditTarget]);

    const undoIdentification = useCallback(async (transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result) {
            const reverted: MatchResult = {
                ...result,
                status: 'NÃO IDENTIFICADO',
                contributor: null,
                matchMethod: undefined,
                similarity: undefined,
                contributorAmount: undefined,
                divergence: undefined,
                suggestion: undefined 
            };

            // 1. Update UI
            if (reconciliation.matchResults.some(r => r.transaction.id === transactionId)) {
                reconciliation.updateReportData(reverted, 'income');
            } else {
                reportManager.updateSavedReportTransaction(transactionId, reverted);
            }

            showToast('Identificação revertida.', 'success');

            // 2. Update DB
            try {
                await consolidationService.markAsPending(transactionId);
            } catch (e) {
                console.error("Falha ao reverter status no banco", e);
            }
        }
    }, [findMatchResult, reconciliation, reportManager, showToast]);

    const handleAnalyze = useCallback(async (transaction: Transaction, candidates: Contributor[]) => {
        reconciliation.setLoadingAiId(transaction.id);
        try {
            const candidateNames = candidates.slice(0, 50).map(c => c.name);
            const response = await fetch('/api/ai/suggestion', {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    transactionDescription: transaction.description,
                    contributorNames: candidateNames
                })
            });

            if (!response.ok) throw new Error('Falha na API de IA');
            const data = await response.json();
            const suggestionText = data.text;

            if (suggestionText && !suggestionText.includes("Nenhuma sugestão clara")) {
                reconciliation.setAiSuggestion({ id: transaction.id, name: suggestionText });
                incrementAiUsage(); 
            } else {
                reconciliation.setAiSuggestion(null);
            }
        } catch (error) {
            console.error("Erro na análise IA:", error);
            showToast("Não foi possível obter sugestão da IA.", "error");
        } finally {
            reconciliation.setLoadingAiId(null);
        }
    }, [incrementAiUsage, showToast, reconciliation]);

    const handleGmailSyncSuccess = useCallback(async (transactions: Transaction[]) => {
        if (transactions.length === 0) return;

        // 1. CONSOLIDATION (DB PERSISTENCE)
        if (user) {
            const consolidationData = transactions.map(t => ({
                transaction_date: t.date,
                amount: t.amount,
                description: t.description,
                type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                pix_key: null,
                source: 'gmail' as 'gmail',
                user_id: user.id
            }));
            await consolidationService.addTransactions(consolidationData);
        }

        // 2. STATE UPDATE
        if (reconciliation.activeReportId) {
            // --- INSIDE REPORT FLOW ---
            reconciliation.setMatchResults(prev => {
                const existingIds = new Set(prev.map(r => r.transaction.id));

                const newMatches: MatchResult[] = transactions
                    .filter(t => !existingIds.has(t.id)) // Deduplicate against current view
                    .map(t => ({
                        transaction: t,
                        contributor: null,
                        status: 'NÃO IDENTIFICADO',
                        church: PLACEHOLDER_CHURCH,
                        matchMethod: undefined,
                        similarity: 0
                    }));

                if (newMatches.length === 0) {
                    showToast("Nenhuma transação nova encontrada.", "error");
                    return prev;
                }

                // Append new results
                const nextResults = [...prev, ...newMatches];

                // Update Preview Data (Visual Groups)
                reconciliation.setReportPreviewData(currentPreview => {
                    if (!currentPreview) return null;
                    const nextPreview = { ...currentPreview };

                    // Add income/expenses to respective unidentified groups
                    const newIncome = newMatches.filter(r => r.transaction.amount > 0);
                    const newExpenses = newMatches.filter(r => r.transaction.amount < 0);

                    if (newIncome.length > 0) {
                        nextPreview.income['unidentified'] = [
                            ...(nextPreview.income['unidentified'] || []),
                            ...newIncome
                        ];
                    }
                    if (newExpenses.length > 0) {
                        nextPreview.expenses['all_expenses_group'] = [
                            ...(nextPreview.expenses['all_expenses_group'] || []),
                            ...newExpenses
                        ];
                    }
                    return nextPreview;
                });

                showToast(`${newMatches.length} novas transações adicionadas ao relatório.`, 'success');
                return nextResults;
            });

        } else {
            // --- OUTSIDE REPORT FLOW (Original + Enhanced) ---
            const virtualFileName = `Importação Gmail - ${new Date().toLocaleDateString()}`;

            reconciliation.setBankStatementFile(prev => {
                const existingTxs = prev?.processedTransactions || [];
                // Deduplicate against the virtual file being viewed
                const newTxs = transactions.filter(nt => !existingTxs.some(et => et.id === nt.id));

                if (newTxs.length === 0 && existingTxs.length > 0) {
                     showToast("Nenhuma transação nova.", "error");
                     return prev;
                }

                const merged = [...existingTxs, ...newTxs];

                // Also update the live match results if we are viewing the live list
                if (reconciliation.hasActiveSession) {
                     const newMatches: MatchResult[] = newTxs.map(t => ({
                        transaction: t,
                        contributor: null,
                        status: 'NÃO IDENTIFICADO',
                        church: PLACEHOLDER_CHURCH,
                        matchMethod: undefined,
                        similarity: 0
                    }));

                    reconciliation.setMatchResults(prevResults => [...prevResults, ...newMatches]);
                    reconciliation.setReportPreviewData(prevPreview => {
                        if (!prevPreview) return null;
                        const nextPreview = { ...prevPreview };
                        const newIncome = newMatches.filter(r => r.transaction.amount > 0);
                        const newExpenses = newMatches.filter(r => r.transaction.amount < 0);

                        if (newIncome.length > 0) nextPreview.income['unidentified'] = [...(nextPreview.income['unidentified']||[]), ...newIncome];
                        if (newExpenses.length > 0) nextPreview.expenses['all_expenses_group'] = [...(nextPreview.expenses['all_expenses_group']||[]), ...newExpenses];

                        return nextPreview;
                    });
                }

                return {
                    bankId: prev?.bankId || 'gmail-bank',
                    content: prev?.content || 'GMAIL_VIRTUAL_CONTENT',
                    fileName: prev?.fileName || virtualFileName,
                    processedTransactions: merged
                };
            });

            if (!reconciliation.activeReportId) {
                 showToast(`${transactions.length} transações sincronizadas.`, 'success');
            }
        }

    }, [reconciliation, showToast, user]);

    const value = useMemo(() => ({
        ...referenceData, ...reconciliation, isCompareDisabled: !reconciliation.bankStatementFile,
        effectiveIgnoreKeywords, 
        openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult,
        ...reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation,
        closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true), closePaymentModal: () => setIsPaymentModalOpen(false),
        isRecompareModalOpen, openRecompareModal: () => setIsRecompareModalOpen(true), closeRecompareModal: () => setIsRecompareModalOpen(false),
        smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze,
        saveCurrentReportChanges,
        handleGmailSyncSuccess,
        resetReconciliation: unifiedResetReconciliation,
        activeSpreadsheetData,
        isUpdateFilesModalOpen, 
        openUpdateFilesModal: () => setIsUpdateFilesModalOpen(true), 
        closeUpdateFilesModal: () => setIsUpdateFilesModalOpen(false),
        undoIdentification
    }), [referenceData, reconciliation, effectiveIgnoreKeywords, reportManager, viewSavedReport, handleBackToSettings, deletingItem, openDeleteConfirmation, closeDeleteConfirmation, confirmDeletion, initialDataLoaded, isSyncing, summary, isPaymentModalOpen, isRecompareModalOpen, openManualIdentify, openBulkManualIdentify, confirmManualIdentification, confirmBulkManualIdentification, findMatchResult, smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit, handleAnalyze, saveCurrentReportChanges, handleGmailSyncSuccess, unifiedResetReconciliation, activeSpreadsheetData, isUpdateFilesModalOpen, undoIdentification]);

    return <AppContext.Provider value={value}>{children}<RecompareModal /></AppContext.Provider>;
};

// --- VIEW SAVED REPORT (LÓGICA HÍBRIDA) ---
// Mescla dados identificados (histórico do relatório) com dados pendentes (lista viva global)
const viewSavedReport = useCallback(async (reportId: string) => {
    setIsLoading(true);
    try {
        // 1. Localiza o relatório salvo (pode ser necessário fetch detalhado se estiver apenas com resumo)
        let report = reportManager.savedReports.find(r => r.id === reportId);

        if (!report) {
            // Fallback para buscar diretamente se não estiver na lista (ex: link direto)
            const { data: dbReport, error } = await supabase.from('saved_reports').select('*').eq('id', reportId).single();
            if (error || !dbReport) throw new Error("Relatório não encontrado.");

            const parsedData = typeof dbReport.data === 'string' ? JSON.parse(dbReport.data as string) : dbReport.data;
            report = {
                id: dbReport.id,
                name: dbReport.name,
                createdAt: dbReport.created_at,
                recordCount: dbReport.record_count,
                user_id: dbReport.user_id,
                data: parsedData
            };
        } else if (!report.data) {
            // Hidratação sob demanda se o conteúdo não estiver carregado
            const { data: reportContent, error } = await supabase
                .from('saved_reports')
                .select('data')
                .eq('id', reportId)
                .single();

            if (error) throw error;

            if (reportContent) {
                const parsedData = typeof reportContent.data === 'string' 
                    ? JSON.parse(reportContent.data) 
                    : reportContent.data;

                report = { ...report, data: parsedData };
                // Atualiza cache local
                reportManager.setSavedReports(prev => prev.map(r => r.id === reportId ? report! : r));
            }
        }

        if (!report || !report.data) throw new Error("Conteúdo do relatório vazio.");

        reconciliation.clearFiles();
        setActiveSpreadsheetData(null);

        if (report.data.spreadsheet) {
            setActiveSpreadsheetData(report.data.spreadsheet);
            reconciliation.setActiveReportId(reportId);
            setActiveView('smart_analysis');
            showToast(`Planilha "${report.name}" carregada.`, "success");
        } else {
            // 2. RECUPERA LISTA VIVA (Global Pending) DO BANCO
            // Isso garante que a aba "Pendentes" mostre o estado atual do trabalho, não o estado antigo
            let livePendingTransactions: Transaction[] = [];
            if (user) {
                try {
                    const pendingDb = await consolidationService.getPendingTransactions(user.id);
                    if (pendingDb) {
                        livePendingTransactions = pendingDb.map(tx => ({
                            id: tx.id,
                            date: tx.transaction_date,
                            amount: tx.amount,
                            description: tx.description,
                            cleanedDescription: tx.description,
                            contributionType: tx.type,
                            originalAmount: String(tx.amount)
                        }));
                    }
                } catch (dbError) {
                    // Silencia erro de tabela não existente (404) para não impedir abertura do relatório
                    console.warn("[ViewReport] Falha ao buscar Lista Viva (Offline ou Tabela Inexistente):", dbError);
                }
            }

            // 3. FILTRA APENAS OS IDENTIFICADOS DO RELATÓRIO SALVO
            // Ignora os pendentes que foram salvos no JSON, pois eles podem estar obsoletos
            const savedIdentifiedResults = report.data.results
                .filter((r: any) => r.status === 'IDENTIFICADO' || r.status === 'RESOLVED')
                .map((r: any) => ({ 
                    ...r, 
                    // Garante que o objeto church esteja presente (hidratação)
                    church: r.church || referenceData.churches.find(c => c.id === r._churchId) || PLACEHOLDER_CHURCH 
                }));

            // 4. PREPARA OS PENDENTES VIVOS (Live List)
            const livePendingResults: MatchResult[] = livePendingTransactions.map(tx => ({
                transaction: tx,
                contributor: null,
                status: 'NÃO IDENTIFICADO',
                church: PLACEHOLDER_CHURCH,
                matchMethod: undefined,
                similarity: 0
            }));

            // 5. COMBINA (Identificados Históricos + Pendentes Atuais)
            const combinedResults = [...savedIdentifiedResults, ...livePendingResults];

            reconciliation.setMatchResults(combinedResults);
            reconciliation.setReportPreviewData({
                income: groupResultsByChurch(combinedResults.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                expenses: { 'all_expenses_group': combinedResults.filter((r: any) => r.transaction.amount < 0) }
            });

            reconciliation.setHasActiveSession(true); 
            reconciliation.setActiveReportId(reportId); 
            setActiveView('reports'); 

            if (livePendingTransactions.length > 0) {
                showToast(`Relatório "${report.name}" carregado com Lista Viva atualizada.`, "success");
            } else {
                showToast(`Relatório "${report.name}" carregado (Histórico).`, "success");
            }
        }

    } catch (error: any) {
        console.error(error);
        showToast("Erro ao abrir relatório: " + error.message, "error");
    } finally {
        setIsLoading(false);
    }
}, [reportManager.savedReports, reconciliation, setActiveView, setIsLoading, showToast, user, referenceData.churches]);

import React, { createContext, useState, useEffect, useMemo, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReportManager } from '../hooks/useReportManager';
import { useReconciliation } from '../hooks/useReconciliation';
import { 
    Bank, Church, MatchResult, Transaction, 
    DeletingItem, SpreadsheetData, SavingReportState 
} from '../types';
import { supabase } from '../services/supabaseClient';
import { consolidationService } from '../services/ConsolidationService';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';

interface AppContextType {
    // Reference Data
    banks: Bank[];
    churches: Church[];
    fileModels: any[];
    similarityLevel: number;
    setSimilarityLevel: (val: number) => void;
    dayTolerance: number;
    setDayTolerance: (val: number) => void;
    customIgnoreKeywords: string[];
    addIgnoreKeyword: (k: string) => void;
    removeIgnoreKeyword: (k: string) => void;
    contributionKeywords: string[];
    addContributionKeyword: (k: string) => void;
    removeContributionKeyword: (k: string) => void;
    learnedAssociations: any[];
    learnAssociation: (match: MatchResult) => Promise<void>;

    editingBank: Bank | null;
    openEditBank: (b: Bank) => void;
    closeEditBank: () => void;
    updateBank: (id: string, name: string) => Promise<void>;
    addBank: (name: string) => Promise<boolean>;

    editingChurch: Church | null;
    openEditChurch: (c: Church) => void;
    closeEditChurch: () => void;
    updateChurch: (id: string, data: any) => Promise<void>;
    addChurch: (data: any) => Promise<boolean>;

    fetchModels: () => Promise<void>;

    // Report Manager
    savedReports: any[];
    maxSavedReports: number;
    searchFilters: any;
    setSearchFilters: (filters: any) => void;
    clearSearchFilters: () => void;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => Promise<void>;
    updateSavedReportName: (id: string, name: string) => Promise<void>;
    saveFilteredReport: (results: MatchResult[]) => void;
    overwriteSavedReport: (id: string, results: MatchResult[], spreadsheet?: SpreadsheetData) => Promise<void>;
    deleteOldReports: (date: Date) => Promise<void>;
    allHistoricalResults: MatchResult[];

    // Reconciliation
    bankStatementFile: any;
    setBankStatementFile: (file: any) => void;
    contributorFiles: any[];
    matchResults: MatchResult[];
    setMatchResults: (results: MatchResult[]) => void;
    reportPreviewData: any;
    setReportPreviewData: (data: any) => void;
    hasActiveSession: boolean;
    setHasActiveSession: (active: boolean) => void;
    activeReportId: string | null;
    setActiveReportId: (id: string | null) => void;

    handleStatementUpload: (content: string, name: string, id: string, file: File) => void;
    handleContributorsUpload: (content: string, name: string, id: string, file?: File) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (id: string) => void;
    handleCompare: () => Promise<void>;
    updateReportData: (row: MatchResult, type: 'income' | 'expenses', idToRemove?: string) => void;
    resetReconciliation: () => void;
    isCompareDisabled: boolean;
    comparisonType: any;
    setComparisonType: (type: any) => void;

    // Manual Identification / Modals
    manualIdentificationTx: Transaction | null;
    bulkIdentificationTxs: Transaction[] | null;
    openManualIdentify: (id: string) => void;
    closeManualIdentify: () => void;
    confirmManualIdentification: (txId: string, churchId: string) => void;
    confirmBulkManualIdentification: (txIds: string[], churchId: string) => void;

    manualMatchState: any;
    openManualMatchModal: (record: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (tx: Transaction) => void;

    divergenceConfirmation: any;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (match: MatchResult) => void;
    rejectDivergence: (match: MatchResult) => void;

    // UI States
    initialDataLoaded: boolean;
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;

    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;

    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    pendingTraining: any;
    setPendingTraining: (val: any) => void;
    handleTrainingSuccess: (model: any, data: any) => void;
    openLabManually: (file?: any) => void;

    smartEditTarget: MatchResult | null;
    openSmartEdit: (target: MatchResult) => void;
    closeSmartEdit: () => void;
    saveSmartEdit: (updated: MatchResult) => void;

    isUpdateFilesModalOpen: boolean;
    openUpdateFilesModal: () => void;
    closeUpdateFilesModal: () => void;

    isSyncing: boolean;

    // View Saved Report
    viewSavedReport: (id: string) => Promise<void>;
    activeSpreadsheetData: SpreadsheetData | null;
    setActiveSpreadsheetData: (data: SpreadsheetData | null) => void;

    summary: any;

    loadingAiId: string | null;
    handleAnalyze: (tx: Transaction, contributors: any[]) => void;
    aiSuggestion: any;

    handleGmailSyncSuccess: (transactions: Transaction[]) => void;

    effectiveIgnoreKeywords: string[];
    saveCurrentReportChanges: () => void;

    undoIdentification: (transactionId: string) => void;
    findMatchResult: (transactionId: string) => MatchResult | undefined;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user } = useAuth();
    const { showToast, setIsLoading, setActiveView } = useUI();
    const [initialDataLoaded, setInitialDataLoaded] = useState(false);

    // UI State for Modals
    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);
    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);
    const [isUpdateFilesModalOpen, setIsUpdateFilesModalOpen] = useState(false);
    const [activeSpreadsheetData, setActiveSpreadsheetData] = useState<SpreadsheetData | null>(null);
    const [isSyncing, setIsSyncing] = useState(false);

    // --- Hooks ---
    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    const reconciliation = useReconciliation({
        user,
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: referenceData.fileModels,
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: referenceData.customIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast,
        setIsLoading,
        setActiveView
    });

    // --- Derived State ---
    const effectiveIgnoreKeywords = useMemo(() => referenceData.customIgnoreKeywords, [referenceData.customIgnoreKeywords]);

    // Initial Load
    useEffect(() => {
        if (user) {
            setInitialDataLoaded(true);
        } else {
            // Allow guest mode with delay
             setTimeout(() => setInitialDataLoaded(true), 500);
        }
    }, [user]);

    // --- Actions ---

    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);

    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;

        try {
            switch(deletingItem.type) {
                case 'bank':
                    referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
                    if (user) await supabase.from('banks').delete().eq('id', deletingItem.id);
                    break;
                case 'church':
                    referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
                    if (user) await supabase.from('churches').delete().eq('id', deletingItem.id);
                    break;
                case 'report-saved':
                    reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
                    if (user) await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
                    break;
                case 'report-row':
                    reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
                    const newResults = reconciliation.matchResults.filter(r => r.transaction.id !== deletingItem.id);
                    reconciliation.setReportPreviewData({
                        income: groupResultsByChurch(newResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                        expenses: { 'all_expenses_group': newResults.filter(r => r.transaction.amount < 0) }
                    });
                    break;
                case 'uploaded-files':
                    reconciliation.clearFiles();
                    break;
                case 'match-results':
                    reconciliation.setMatchResults([]);
                    reconciliation.setReportPreviewData(null);
                    reconciliation.setHasActiveSession(false);
                    reconciliation.setActiveReportId(null);
                    break;
                case 'learned-associations':
                    referenceData.setLearnedAssociations([]);
                    if (user) await supabase.from('learned_associations').delete().eq('user_id', user.id);
                    break;
                case 'all-data':
                    // Reset everything
                    referenceData.setBanks([]);
                    referenceData.setChurches([]);
                    referenceData.setLearnedAssociations([]);
                    reconciliation.resetReconciliation();
                    if (user) {
                        await supabase.from('banks').delete().eq('user_id', user.id);
                        await supabase.from('churches').delete().eq('user_id', user.id);
                        await supabase.from('learned_associations').delete().eq('user_id', user.id);
                    }
                    break;
            }
            showToast("Item excluído com sucesso.", "success");
        } catch (e) {
            console.error(e);
            showToast("Erro ao excluir item.", "error");
        } finally {
            setDeletingItem(null);
        }
    }, [deletingItem, referenceData, reportManager, reconciliation, user, showToast]);

    // Manual Identification
    const openManualIdentify = useCallback((id: string) => {
        const result = reconciliation.matchResults.find(r => r.transaction.id === id);
        if (result) {
            reconciliation.setManualIdentificationTx(result.transaction);
        }
    }, [reconciliation.matchResults, reconciliation.setManualIdentificationTx]);

    const confirmManualIdentification = useCallback(async (txId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        const result = reconciliation.matchResults.find(r => r.transaction.id === txId);
        if (result) {
            const updated: MatchResult = {
                ...result,
                status: 'IDENTIFICADO',
                church,
                matchMethod: 'MANUAL',
                similarity: 100
            };
            reconciliation.updateReportData(updated, 'income');

            // Learn association
            await referenceData.learnAssociation(updated);

            reconciliation.setManualIdentificationTx(null);
            showToast("Identificação manual realizada e aprendida.", "success");
        }
    }, [reconciliation, referenceData, showToast]);

    const confirmBulkManualIdentification = useCallback((txIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        txIds.forEach(id => {
            const result = reconciliation.matchResults.find(r => r.transaction.id === id);
            if (result) {
                const updated: MatchResult = {
                    ...result,
                    status: 'IDENTIFICADO',
                    church,
                    matchMethod: 'MANUAL',
                    similarity: 100
                };
                reconciliation.updateReportData(updated, 'income');
                referenceData.learnAssociation(updated);
            }
        });

        reconciliation.setBulkIdentificationTxs(null);
        showToast(`${txIds.length} transações identificadas em massa.`, "success");
    }, [reconciliation, referenceData, showToast]);

    const saveCurrentReportChanges = useCallback(() => {
        if (reconciliation.activeReportId) {
            reportManager.overwriteSavedReport(reconciliation.activeReportId, reconciliation.matchResults);
        }
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager]);

    // View Saved Report Logic
    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            let report = reportManager.savedReports.find(r => r.id === reportId);

            if (!report) {
                const { data: dbReport, error } = await supabase.from('saved_reports').select('*').eq('id', reportId).single();
                if (error || !dbReport) throw new Error("Relatório não encontrado.");

                const parsedData = typeof dbReport.data === 'string' ? JSON.parse(dbReport.data as string) : dbReport.data;
                report = {
                    id: dbReport.id,
                    name: dbReport.name,
                    createdAt: dbReport.created_at,
                    recordCount: dbReport.record_count,
                    user_id: dbReport.user_id,
                    data: parsedData
                };
            } else if (!report.data) {
                const { data: reportContent, error } = await supabase
                    .from('saved_reports')
                    .select('data')
                    .eq('id', reportId)
                    .single();

                if (error) throw error;

                if (reportContent) {
                    const parsedData = typeof reportContent.data === 'string' 
                        ? JSON.parse(reportContent.data) 
                        : reportContent.data;

                    report = { ...report, data: parsedData };
                    reportManager.setSavedReports(prev => prev.map(r => r.id === reportId ? report! : r));
                }
            }

            if (!report || !report.data) throw new Error("Conteúdo do relatório vazio.");

            reconciliation.clearFiles();
            setActiveSpreadsheetData(null);

            if (report.data.spreadsheet) {
                setActiveSpreadsheetData(report.data.spreadsheet);
                reconciliation.setActiveReportId(reportId);
                setActiveView('smart_analysis');
                showToast(`Planilha "${report.name}" carregada.`, "success");
            } else {
                // Live List Logic
                let livePendingTransactions: Transaction[] = [];
                if (user) {
                    try {
                        const pendingDb = await consolidationService.getPendingTransactions(user.id);
                        if (pendingDb) {
                            livePendingTransactions = pendingDb.map(tx => ({
                                id: tx.id,
                                date: tx.transaction_date,
                                amount: tx.amount,
                                description: tx.description,
                                cleanedDescription: tx.description,
                                contributionType: tx.type,
                                originalAmount: String(tx.amount)
                            }));
                        }
                    } catch (dbError) {
                        console.warn("Offline or DB Error getting live pending transactions:", dbError);
                    }
                }

                const savedIdentifiedResults = report.data.results
                    .filter((r: any) => r.status === 'IDENTIFICADO' || r.status === 'RESOLVED')
                    .map((r: any) => ({ 
                        ...r, 
                        church: r.church || referenceData.churches.find(c => c.id === r._churchId) || PLACEHOLDER_CHURCH 
                    }));

                const livePendingResults: MatchResult[] = livePendingTransactions.map(tx => ({
                    transaction: tx,
                    contributor: null,
                    status: 'NÃO IDENTIFICADO',
                    church: PLACEHOLDER_CHURCH,
                    matchMethod: undefined,
                    similarity: 0
                }));

                const combinedResults = [...savedIdentifiedResults, ...livePendingResults];

                reconciliation.setMatchResults(combinedResults);
                reconciliation.setReportPreviewData({
                    income: groupResultsByChurch(combinedResults.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': combinedResults.filter((r: any) => r.transaction.amount < 0) }
                });

                reconciliation.setHasActiveSession(true); 
                reconciliation.setActiveReportId(reportId); 
                setActiveView('reports'); 

                if (livePendingTransactions.length > 0) {
                    showToast(`Relatório "${report.name}" carregado com Lista Viva atualizada.`, "success");
                } else {
                    showToast(`Relatório "${report.name}" carregado (Histórico).`, "success");
                }
            }

        } catch (error: any) {
            console.error(error);
            showToast("Erro ao abrir relatório: " + error.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager, reconciliation, setActiveView, setIsLoading, showToast, user, referenceData.churches]);

    const handleGmailSyncSuccess = useCallback((transactions: Transaction[]) => {
        if (reconciliation.bankStatementFile) {
            reconciliation.setBankStatementFile(prev => {
                if (!prev) return null;
                return {
                    ...prev,
                    processedTransactions: [...(prev.processedTransactions || []), ...transactions]
                };
            });
            setTimeout(() => reconciliation.handleCompare(), 500);
        } else {
            const csvContent = ""; 
            const virtualFile = new File([csvContent], "gmail_import.csv", { type: "text/csv" });
            reconciliation.setBankStatementFile({
                bankId: 'gmail',
                content: csvContent,
                fileName: 'Importação Gmail',
                rawFile: virtualFile,
                processedTransactions: transactions
            });
            setTimeout(() => reconciliation.handleCompare(), 500);
        }
    }, [reconciliation]);

    const undoIdentification = useCallback((transactionId: string) => {
        const result = reconciliation.matchResults.find(r => r.transaction.id === transactionId);
        if (result && result.status === 'IDENTIFICADO') {
            reconciliation.updateReportData({
                ...result,
                status: 'NÃO IDENTIFICADO',
                church: PLACEHOLDER_CHURCH,
                contributor: null,
                matchMethod: undefined,
                similarity: 0
            }, 'income');
            showToast("Identificação desfeita.", "success");
        }
    }, [reconciliation, showToast]);

    const findMatchResult = useCallback((id: string) => {
        return reconciliation.matchResults.find(r => r.transaction.id === id);
    }, [reconciliation.matchResults]);

    const summary = useMemo(() => {
        const total = reconciliation.matchResults.length;
        const identifiedCount = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO').length;
        const unidentifiedCount = reconciliation.matchResults.filter(r => r.status === 'NÃO IDENTIFICADO' || r.status === 'PENDENTE').length;

        const auto = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod !== 'MANUAL');
        const manual = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod === 'MANUAL');
        const pending = reconciliation.matchResults.filter(r => r.status === 'NÃO IDENTIFICADO' || r.status === 'PENDENTE');

        const totalValue = reconciliation.matchResults.reduce((acc, r) => acc + (r.transaction.amount || 0), 0);

        const churchMap = new Map<string, number>();
        reconciliation.matchResults.forEach(r => {
            if (r.status === 'IDENTIFICADO' && r.church && r.church.id !== 'unidentified') {
                const current = churchMap.get(r.church.name) || 0;
                churchMap.set(r.church.name, current + (r.contributorAmount || r.transaction.amount));
            }
        });
        const valuePerChurch = Array.from(churchMap.entries()).sort((a, b) => b[1] - a[1]).slice(0, 5);

        const methodBreakdown = {
            AUTOMATIC: reconciliation.matchResults.filter(r => r.matchMethod === 'AUTOMATIC').length,
            MANUAL: reconciliation.matchResults.filter(r => r.matchMethod === 'MANUAL').length,
            LEARNED: reconciliation.matchResults.filter(r => r.matchMethod === 'LEARNED').length,
            AI: reconciliation.matchResults.filter(r => r.matchMethod === 'AI').length
        };

        return {
            total,
            identifiedCount,
            unidentifiedCount,
            autoConfirmed: { count: auto.length, value: auto.reduce((s, r) => s + (r.transaction.amount || 0), 0) },
            manualConfirmed: { count: manual.length, value: manual.reduce((s, r) => s + (r.transaction.amount || 0), 0) },
            pending: { count: pending.length, value: pending.reduce((s, r) => s + (r.transaction.amount || 0), 0) },
            totalValue,
            valuePerChurch,
            methodBreakdown,
            isHistorical: !!reconciliation.activeReportId
        };
    }, [reconciliation.matchResults, reconciliation.activeReportId]);

    const openSmartEdit = useCallback((target: MatchResult) => setSmartEditTarget(target), []);
    const closeSmartEdit = useCallback(() => setSmartEditTarget(null), []);
    const saveSmartEdit = useCallback(async (updated: MatchResult) => {
        reconciliation.updateReportData(updated, 'income');
        if (updated.status === 'IDENTIFICADO') {
            await referenceData.learnAssociation(updated);
        }
        setSmartEditTarget(null);
        showToast("Registro atualizado com sucesso.", "success");
    }, [reconciliation, referenceData, showToast]);

    const contextValue: AppContextType = {
        ...referenceData,
        ...reportManager,
        ...reconciliation,

        initialDataLoaded,
        deletingItem,
        openDeleteConfirmation,
        closeDeleteConfirmation,
        confirmDeletion,

        isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true),
        closePaymentModal: () => setIsPaymentModalOpen(false),

        isRecompareModalOpen,
        openRecompareModal: () => setIsRecompareModalOpen(true),
        closeRecompareModal: () => setIsRecompareModalOpen(false),

        manualIdentificationTx: reconciliation.manualIdentificationTx,
        bulkIdentificationTxs: reconciliation.bulkIdentificationTxs,
        openManualIdentify, 
        closeManualIdentify: reconciliation.closeManualIdentify,
        confirmManualIdentification,
        confirmBulkManualIdentification,

        smartEditTarget,
        openSmartEdit,
        closeSmartEdit,
        saveSmartEdit,

        isUpdateFilesModalOpen,
        openUpdateFilesModal: () => setIsUpdateFilesModalOpen(true),
        closeUpdateFilesModal: () => setIsUpdateFilesModalOpen(false),

        isSyncing,
        viewSavedReport,
        activeSpreadsheetData,
        setActiveSpreadsheetData,
        summary,
        effectiveIgnoreKeywords,
        saveCurrentReportChanges,
        handleGmailSyncSuccess,
        undoIdentification,
        findMatchResult
    };

    return (
        <AppContext.Provider value={contextValue}>
            {children}
        </AppContext.Provider>
    );
};

import React, { createContext, useState, useEffect, useMemo, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReportManager } from '../hooks/useReportManager';
import { useReconciliation } from '../hooks/useReconciliation';
import { 
    Bank, Church, MatchResult, Transaction, 
    DeletingItem, SpreadsheetData, SavingReportState 
} from '../types';
import { supabase } from '../services/supabaseClient';
import { consolidationService } from '../services/ConsolidationService';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';

interface AppContextType {
    // Reference Data
    banks: Bank[];
    churches: Church[];
    fileModels: any[];
    similarityLevel: number;
    setSimilarityLevel: (val: number) => void;
    dayTolerance: number;
    setDayTolerance: (val: number) => void;
    customIgnoreKeywords: string[];
    addIgnoreKeyword: (k: string) => void;
    removeIgnoreKeyword: (k: string) => void;
    contributionKeywords: string[];
    addContributionKeyword: (k: string) => void;
    removeContributionKeyword: (k: string) => void;
    learnedAssociations: any[];
    learnAssociation: (match: MatchResult) => Promise<void>;

    editingBank: Bank | null;
    openEditBank: (b: Bank) => void;
    closeEditBank: () => void;
    updateBank: (id: string, name: string) => Promise<void>;
    addBank: (name: string) => Promise<boolean>;

    editingChurch: Church | null;
    openEditChurch: (c: Church) => void;
    closeEditChurch: () => void;
    updateChurch: (id: string, data: any) => Promise<void>;
    addChurch: (data: any) => Promise<boolean>;

    fetchModels: () => Promise<void>;

    // Report Manager
    savedReports: any[];
    maxSavedReports: number;
    searchFilters: any;
    setSearchFilters: (filters: any) => void;
    clearSearchFilters: () => void;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => Promise<void>;
    updateSavedReportName: (id: string, name: string) => Promise<void>;
    saveFilteredReport: (results: MatchResult[]) => void;
    overwriteSavedReport: (id: string, results: MatchResult[], spreadsheet?: SpreadsheetData) => Promise<void>;
    deleteOldReports: (date: Date) => Promise<void>;
    allHistoricalResults: MatchResult[];

    // Reconciliation
    bankStatementFile: any;
    setBankStatementFile: (file: any) => void;
    contributorFiles: any[];
    matchResults: MatchResult[];
    setMatchResults: (results: MatchResult[]) => void;
    reportPreviewData: any;
    setReportPreviewData: (data: any) => void;
    hasActiveSession: boolean;
    setHasActiveSession: (active: boolean) => void;
    activeReportId: string | null;
    setActiveReportId: (id: string | null) => void;

    handleStatementUpload: (content: string, name: string, id: string, file: File) => void;
    handleContributorsUpload: (content: string, name: string, id: string, file?: File) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (id: string) => void;
    handleCompare: () => Promise<void>;
    updateReportData: (row: MatchResult, type: 'income' | 'expenses', idToRemove?: string) => void;
    resetReconciliation: () => void;
    isCompareDisabled: boolean;
    comparisonType: any;
    setComparisonType: (type: any) => void;

    // Manual Identification / Modals
    manualIdentificationTx: Transaction | null;
    bulkIdentificationTxs: Transaction[] | null;
    openManualIdentify: (id: string) => void;
    closeManualIdentify: () => void;
    confirmManualIdentification: (txId: string, churchId: string) => void;
    confirmBulkManualIdentification: (txIds: string[], churchId: string) => void;

    manualMatchState: any;
    openManualMatchModal: (record: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (tx: Transaction) => void;

    divergenceConfirmation: any;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (match: MatchResult) => void;
    rejectDivergence: (match: MatchResult) => void;

    // UI States
    initialDataLoaded: boolean;
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;

    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;

    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    pendingTraining: any;
    setPendingTraining: (val: any) => void;
    handleTrainingSuccess: (model: any, data: any) => void;
    openLabManually: (file?: any) => void;

    smartEditTarget: MatchResult | null;
    openSmartEdit: (target: MatchResult) => void;
    closeSmartEdit: () => void;
    saveSmartEdit: (updated: MatchResult) => void;

    isUpdateFilesModalOpen: boolean;
    openUpdateFilesModal: () => void;
    closeUpdateFilesModal: () => void;

    isSyncing: boolean;

    // View Saved Report
    viewSavedReport: (id: string) => Promise<void>;
    activeSpreadsheetData: SpreadsheetData | null;
    setActiveSpreadsheetData: (data: SpreadsheetData | null) => void;

    summary: any;

    loadingAiId: string | null;
    handleAnalyze: (tx: Transaction, contributors: any[]) => void;
    aiSuggestion: any;

    handleGmailSyncSuccess: (transactions: Transaction[]) => void;

    effectiveIgnoreKeywords: string[];
    saveCurrentReportChanges: () => void;

    undoIdentification: (transactionId: string) => void;
    findMatchResult: (transactionId: string) => MatchResult | undefined;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user } = useAuth();
    const { showToast, setIsLoading, setActiveView } = useUI();
    const [initialDataLoaded, setInitialDataLoaded] = useState(false);

    // UI State for Modals
    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);
    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);
    const [isUpdateFilesModalOpen, setIsUpdateFilesModalOpen] = useState(false);
    const [activeSpreadsheetData, setActiveSpreadsheetData] = useState<SpreadsheetData | null>(null);
    const [isSyncing, setIsSyncing] = useState(false);

    // --- Hooks ---
    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    const reconciliation = useReconciliation({
        user,
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: referenceData.fileModels,
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: referenceData.customIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast,
        setIsLoading,
        setActiveView
    });

    // --- Derived State ---
    const effectiveIgnoreKeywords = useMemo(() => referenceData.customIgnoreKeywords, [referenceData.customIgnoreKeywords]);

    // --- FETCH DE DADOS E HIDRATAÇÃO ---
    // Estratégia de "Fail-Safe": Carrega o essencial primeiro. Se a Lista Viva falhar (tabela não existe), não quebra o resto.
    useEffect(() => {
        if (!user) {
            setInitialDataLoaded(true);
            return;
        }

        const fetchData = async () => {
            setIsSyncing(true);
            try {
                // 1. DADOS ESSENCIAIS (Bancos, Igrejas, Relatórios)
                // Usamos Promise.allSettled para que falha em um não trave os outros
                const [churchesRes, banksRes, reportsRes] = await Promise.all([
                    supabase.from('churches').select('*').order('name'),
                    supabase.from('banks').select('*').order('name'),
                    supabase.from('saved_reports')
                        .select('id, name, created_at, record_count, user_id') 
                        .eq('user_id', user.id)
                        .order('created_at', { ascending: false }),
                ]);

                // Aplica dados que vieram com sucesso
                if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
                if (banksRes.data) referenceData.setBanks(banksRes.data as any);
                if (reportsRes.data) {
                    reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null 
                    })));
                }

                // 2. TENTATIVA DE RECUPERAÇÃO DA LISTA VIVA (Isolado em try/catch)
                // Se a tabela consolidated_transactions não existir (404), isso falha silenciosamente
                // sem impedir que o resto do app funcione.
                try {
                    const pendingTxs = await consolidationService.getPendingTransactions(user.id);

                    if (pendingTxs && pendingTxs.length > 0) {
                        console.log(`[Hydration] Recuperando ${pendingTxs.length} transações vivas do banco.`);

                        const liveTransactions = pendingTxs.map(dbTx => ({
                            id: dbTx.id,
                            date: dbTx.transaction_date,
                            amount: dbTx.amount,
                            description: dbTx.description,
                            cleanedDescription: dbTx.description, 
                            contributionType: dbTx.type,
                            originalAmount: String(dbTx.amount)
                        }));

                        const virtualContent = liveTransactions
                            .map(t => `${t.date};${t.description};${t.amount};${t.contributionType}`)
                            .join('\n');

                        const targetBankId = banksRes.data && banksRes.data.length > 0 ? banksRes.data[0].id : 'active-session-bank';

                        reconciliation.setBankStatementFile({
                            bankId: targetBankId,
                            content: virtualContent,
                            fileName: 'Sessão Ativa (Nuvem)',
                            processedTransactions: liveTransactions as Transaction[],
                            rawFile: undefined 
                        });

                        if (reconciliation.matchResults.length === 0) {
                            const mappedResults: MatchResult[] = liveTransactions.map(tx => ({
                                transaction: tx as Transaction,
                                contributor: null,
                                status: 'NÃO IDENTIFICADO',
                                church: PLACEHOLDER_CHURCH,
                                matchMethod: undefined,
                                similarity: 0
                            }));

                            reconciliation.setMatchResults(mappedResults);
                            reconciliation.setReportPreviewData({
                                income: groupResultsByChurch(mappedResults),
                                expenses: { 'all_expenses_group': [] }
                            });

                            reconciliation.setHasActiveSession(true);
                        }
                    }
                } catch (dbError) {
                    console.warn("[Hydration] Falha ao carregar Lista Viva (Tabela pode não existir ainda):", dbError);
                    // Não faz nada, permite que o app carregue sem a lista viva
                }

            } catch (err) { 
                console.error('Critical sync failed', err); 
            } finally { 
                setIsSyncing(false); 
                setInitialDataLoaded(true); // Garante que a tela de loading saia
            }
        };

        fetchData();
    }, [user?.id]);

    // --- Actions ---

    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);

    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;

        try {
            switch(deletingItem.type) {
                case 'bank':
                    referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
                    if (user) await supabase.from('banks').delete().eq('id', deletingItem.id);
                    break;
                case 'church':
                    referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
                    if (user) await supabase.from('churches').delete().eq('id', deletingItem.id);
                    break;
                case 'report-saved':
                    reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
                    if (user) await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
                    break;
                case 'report-row':
                    reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
                    const newResults = reconciliation.matchResults.filter(r => r.transaction.id !== deletingItem.id);
                    reconciliation.setReportPreviewData({
                        income: groupResultsByChurch(newResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                        expenses: { 'all_expenses_group': newResults.filter(r => r.transaction.amount < 0) }
                    });
                    break;
                case 'uploaded-files':
                    reconciliation.clearFiles();
                    break;
                case 'match-results':
                    reconciliation.setMatchResults([]);
                    reconciliation.setReportPreviewData(null);
                    reconciliation.setHasActiveSession(false);
                    reconciliation.setActiveReportId(null);
                    break;
                case 'learned-associations':
                    referenceData.setLearnedAssociations([]);
                    if (user) await supabase.from('learned_associations').delete().eq('user_id', user.id);
                    break;
                case 'all-data':
                    // Reset everything
                    referenceData.setBanks([]);
                    referenceData.setChurches([]);
                    referenceData.setLearnedAssociations([]);
                    reconciliation.resetReconciliation();
                    if (user) {
                        await supabase.from('banks').delete().eq('user_id', user.id);
                        await supabase.from('churches').delete().eq('user_id', user.id);
                        await supabase.from('learned_associations').delete().eq('user_id', user.id);
                    }
                    break;
            }
            showToast("Item excluído com sucesso.", "success");
        } catch (e) {
            console.error(e);
            showToast("Erro ao excluir item.", "error");
        } finally {
            setDeletingItem(null);
        }
    }, [deletingItem, referenceData, reportManager, reconciliation, user, showToast]);

    // Manual Identification
    const openManualIdentify = useCallback((id: string) => {
        const result = reconciliation.matchResults.find(r => r.transaction.id === id);
        if (result) {
            reconciliation.setManualIdentificationTx(result.transaction);
        }
    }, [reconciliation.matchResults, reconciliation.setManualIdentificationTx]);

    const confirmManualIdentification = useCallback(async (txId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        const result = reconciliation.matchResults.find(r => r.transaction.id === txId);
        if (result) {
            const updated: MatchResult = {
                ...result,
                status: 'IDENTIFICADO',
                church,
                matchMethod: 'MANUAL',
                similarity: 100
            };
            reconciliation.updateReportData(updated, 'income');

            // Learn association
            await referenceData.learnAssociation(updated);

            // Update DB (Safe Fire-and-Forget)
            try {
                await consolidationService.markAsIdentified(txId);
            } catch (e) { console.warn("Failed to mark as identified in DB", e); }

            reconciliation.setManualIdentificationTx(null);
            showToast("Identificação manual realizada e aprendida.", "success");
        }
    }, [reconciliation, referenceData, showToast]);

    const confirmBulkManualIdentification = useCallback((txIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        txIds.forEach(id => {
            const result = reconciliation.matchResults.find(r => r.transaction.id === id);
            if (result) {
                const updated: MatchResult = {
                    ...result,
                    status: 'IDENTIFICADO',
                    church,
                    matchMethod: 'MANUAL',
                    similarity: 100
                };
                reconciliation.updateReportData(updated, 'income');
                referenceData.learnAssociation(updated);
                // Update DB
                consolidationService.markAsIdentified(id).catch(() => {});
            }
        });

        reconciliation.setBulkIdentificationTxs(null);
        showToast(`${txIds.length} transações identificadas em massa.`, "success");
    }, [reconciliation, referenceData, showToast]);

    const saveCurrentReportChanges = useCallback(() => {
        if (reconciliation.activeReportId) {
            reportManager.overwriteSavedReport(reconciliation.activeReportId, reconciliation.matchResults);
        }
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager]);

    // View Saved Report Logic
    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            let report = reportManager.savedReports.find(r => r.id === reportId);

            if (!report) {
                const { data: dbReport, error } = await supabase.from('saved_reports').select('*').eq('id', reportId).single();
                if (error || !dbReport) throw new Error("Relatório não encontrado.");

                const parsedData = typeof dbReport.data === 'string' ? JSON.parse(dbReport.data as string) : dbReport.data;
                report = {
                    id: dbReport.id,
                    name: dbReport.name,
                    createdAt: dbReport.created_at,
                    recordCount: dbReport.record_count,
                    user_id: dbReport.user_id,
                    data: parsedData
                };
            } else if (!report.data) {
                const { data: reportContent, error } = await supabase
                    .from('saved_reports')
                    .select('data')
                    .eq('id', reportId)
                    .single();

                if (error) throw error;

                if (reportContent) {
                    const parsedData = typeof reportContent.data === 'string' 
                        ? JSON.parse(reportContent.data) 
                        : reportContent.data;

                    report = { ...report, data: parsedData };
                    reportManager.setSavedReports(prev => prev.map(r => r.id === reportId ? report! : r));
                }
            }

            if (!report || !report.data) throw new Error("Conteúdo do relatório vazio.");

            reconciliation.clearFiles();
            setActiveSpreadsheetData(null);

            if (report.data.spreadsheet) {
                setActiveSpreadsheetData(report.data.spreadsheet);
                reconciliation.setActiveReportId(reportId);
                setActiveView('smart_analysis');
                showToast(`Planilha "${report.name}" carregada.`, "success");
            } else {
                // Live List Logic
                let livePendingTransactions: Transaction[] = [];
                if (user) {
                    try {
                        const pendingDb = await consolidationService.getPendingTransactions(user.id);
                        if (pendingDb) {
                            livePendingTransactions = pendingDb.map(tx => ({
                                id: tx.id,
                                date: tx.transaction_date,
                                amount: tx.amount,
                                description: tx.description,
                                cleanedDescription: tx.description,
                                contributionType: tx.type,
                                originalAmount: String(tx.amount)
                            }));
                        }
                    } catch (dbError) {
                        console.warn("Offline or DB Error getting live pending transactions:", dbError);
                    }
                }

                const savedIdentifiedResults = report.data.results
                    .filter((r: any) => r.status === 'IDENTIFICADO' || r.status === 'RESOLVED')
                    .map((r: any) => ({ 
                        ...r, 
                        church: r.church || referenceData.churches.find(c => c.id === r._churchId) || PLACEHOLDER_CHURCH 
                    }));

                const livePendingResults: MatchResult[] = livePendingTransactions.map(tx => ({
                    transaction: tx,
                    contributor: null,
                    status: 'NÃO IDENTIFICADO',
                    church: PLACEHOLDER_CHURCH,
                    matchMethod: undefined,
                    similarity: 0
                }));

                const combinedResults = [...savedIdentifiedResults, ...livePendingResults];

                reconciliation.setMatchResults(combinedResults);
                reconciliation.setReportPreviewData({
                    income: groupResultsByChurch(combinedResults.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': combinedResults.filter((r: any) => r.transaction.amount < 0) }
                });

                reconciliation.setHasActiveSession(true); 
                reconciliation.setActiveReportId(reportId); 
                setActiveView('reports'); 

                if (livePendingTransactions.length > 0) {
                    showToast(`Relatório "${report.name}" carregado com Lista Viva atualizada.`, "success");
                } else {
                    showToast(`Relatório "${report.name}" carregado (Histórico).`, "success");
                }
            }

        } catch (error: any) {
            console.error(error);
            showToast("Erro ao abrir relatório: " + error.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager, reconciliation, setActiveView, setIsLoading, showToast, user, referenceData.churches]);

    const handleGmailSyncSuccess = useCallback((transactions: Transaction[]) => {
        if (reconciliation.bankStatementFile) {
            reconciliation.setBankStatementFile(prev => {
                if (!prev) return null;
                return {
                    ...prev,
                    processedTransactions: [...(prev.processedTransactions || []), ...transactions]
                };
            });
            setTimeout(() => reconciliation.handleCompare(), 500);
        } else {
            const csvContent = ""; 
            const virtualFile = new File([csvContent], "gmail_import.csv", { type: "text/csv" });
            reconciliation.setBankStatementFile({
                bankId: 'gmail',
                content: csvContent,
                fileName: 'Importação Gmail',
                rawFile: virtualFile,
                processedTransactions: transactions
            });
            setTimeout(() => reconciliation.handleCompare(), 500);
        }
    }, [reconciliation]);

    const undoIdentification = useCallback(async (transactionId: string) => {
        const result = reconciliation.matchResults.find(r => r.transaction.id === transactionId);
        if (result && result.status === 'IDENTIFICADO') {
            reconciliation.updateReportData({
                ...result,
                status: 'NÃO IDENTIFICADO',
                church: PLACEHOLDER_CHURCH,
                contributor: null,
                matchMethod: undefined,
                similarity: 0
            }, 'income');

            // Revert DB status
            try {
                await consolidationService.markAsPending(transactionId);
            } catch(e) { console.warn("Failed to revert status in DB", e); }

            showToast("Identificação desfeita.", "success");
        }
    }, [reconciliation, showToast]);

    const findMatchResult = useCallback((id: string) => {
        return reconciliation.matchResults.find(r => r.transaction.id === id);
    }, [reconciliation.matchResults]);

    const summary = useMemo(() => {
        const total = reconciliation.matchResults.length;
        const identifiedCount = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO').length;
        const unidentifiedCount = reconciliation.matchResults.filter(r => r.status === 'NÃO IDENTIFICADO' || r.status === 'PENDENTE').length;

        const auto = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod !== 'MANUAL');
        const manual = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod === 'MANUAL');
        const pending = reconciliation.matchResults.filter(r => r.status === 'NÃO IDENTIFICADO' || r.status === 'PENDENTE');

        const totalValue = reconciliation.matchResults.reduce((acc, r) => acc + (r.transaction.amount || 0), 0);

        const churchMap = new Map<string, number>();
        reconciliation.matchResults.forEach(r => {
            if (r.status === 'IDENTIFICADO' && r.church && r.church.id !== 'unidentified') {
                const current = churchMap.get(r.church.name) || 0;
                churchMap.set(r.church.name, current + (r.contributorAmount || r.transaction.amount));
            }
        });
        const valuePerChurch = Array.from(churchMap.entries()).sort((a, b) => b[1] - a[1]).slice(0, 5);

        const methodBreakdown = {
            AUTOMATIC: reconciliation.matchResults.filter(r => r.matchMethod === 'AUTOMATIC').length,
            MANUAL: reconciliation.matchResults.filter(r => r.matchMethod === 'MANUAL').length,
            LEARNED: reconciliation.matchResults.filter(r => r.matchMethod === 'LEARNED').length,
            AI: reconciliation.matchResults.filter(r => r.matchMethod === 'AI').length
        };

        return {
            total,
            identifiedCount,
            unidentifiedCount,
            autoConfirmed: { count: auto.length, value: auto.reduce((s, r) => s + (r.transaction.amount || 0), 0) },
            manualConfirmed: { count: manual.length, value: manual.reduce((s, r) => s + (r.transaction.amount || 0), 0) },
            pending: { count: pending.length, value: pending.reduce((s, r) => s + (r.transaction.amount || 0), 0) },
            totalValue,
            valuePerChurch,
            methodBreakdown,
            isHistorical: !!reconciliation.activeReportId
        };
    }, [reconciliation.matchResults, reconciliation.activeReportId]);

    const openSmartEdit = useCallback((target: MatchResult) => setSmartEditTarget(target), []);
    const closeSmartEdit = useCallback(() => setSmartEditTarget(null), []);
    const saveSmartEdit = useCallback(async (updated: MatchResult) => {
        reconciliation.updateReportData(updated, 'income');
        if (updated.status === 'IDENTIFICADO') {
            await referenceData.learnAssociation(updated);
            // Update DB
            consolidationService.markAsIdentified(updated.transaction.id).catch(() => {});
        }
        setSmartEditTarget(null);
        showToast("Registro atualizado com sucesso.", "success");
    }, [reconciliation, referenceData, showToast]);

    const contextValue: AppContextType = {
        ...referenceData,
        ...reportManager,
        ...reconciliation,

        initialDataLoaded,
        deletingItem,
        openDeleteConfirmation,
        closeDeleteConfirmation,
        confirmDeletion,

        isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true),
        closePaymentModal: () => setIsPaymentModalOpen(false),

        isRecompareModalOpen,
        openRecompareModal: () => setIsRecompareModalOpen(true),
        closeRecompareModal: () => setIsRecompareModalOpen(false),

        manualIdentificationTx: reconciliation.manualIdentificationTx,
        bulkIdentificationTxs: reconciliation.bulkIdentificationTxs,
        openManualIdentify, 
        closeManualIdentify: reconciliation.closeManualIdentify,
        confirmManualIdentification,
        confirmBulkManualIdentification,

        smartEditTarget,
        openSmartEdit,
        closeSmartEdit,
        saveSmartEdit,

        isUpdateFilesModalOpen,
        openUpdateFilesModal: () => setIsUpdateFilesModalOpen(true),
        closeUpdateFilesModal: () => setIsUpdateFilesModalOpen(false),

        isSyncing,
        viewSavedReport,
        activeSpreadsheetData,
        setActiveSpreadsheetData,
        summary,
        effectiveIgnoreKeywords,
        saveCurrentReportChanges,
        handleGmailSyncSuccess,
        undoIdentification,
        findMatchResult
    };

    return (
        <AppContext.Provider value={contextValue}>
            {children}
        </AppContext.Provider>
    );
};

// --- FETCH DE DADOS E HIDRATAÇÃO ---
// Estratégia de "Fail-Safe": Carrega o essencial primeiro. Se a Lista Viva falhar (tabela não existe), não quebra o resto.
useEffect(() => {
    if (!user) {
        setInitialDataLoaded(true);
        return;
    }

    const fetchData = async () => {
        setIsSyncing(true);
        try {
            // 1. DADOS ESSENCIAIS (Bancos, Igrejas, Relatórios)
            // Usamos Promise.allSettled para que falha em um não trave os outros
            const [churchesRes, banksRes, reportsRes] = await Promise.all([
                supabase.from('churches').select('*').order('name'),
                supabase.from('banks').select('*').order('name'),
                supabase.from('saved_reports')
                    .select('id, name, created_at, record_count, user_id') 
                    .eq('user_id', user.id)
                    .order('created_at', { ascending: false }),
            ]);

            // Aplica dados que vieram com sucesso
            if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
            if (banksRes.data) referenceData.setBanks(banksRes.data as any);
            if (reportsRes.data) {
                reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                    id: r.id, 
                    name: r.name, 
                    createdAt: r.created_at, 
                    recordCount: r.record_count, 
                    user_id: r.user_id, 
                    data: null 
                })));
            }

            // 2. TENTATIVA DE RECUPERAÇÃO DA LISTA VIVA (Isolado em try/catch)
            // Se a tabela consolidated_transactions não existir (404), isso falha silenciosamente
            // sem impedir que o resto do app funcione.
            try {
                const pendingTxs = await consolidationService.getPendingTransactions(user.id);

                if (pendingTxs && pendingTxs.length > 0) {
                    console.log(`[Hydration] Recuperando ${pendingTxs.length} transações vivas do banco.`);

                    const liveTransactions = pendingTxs.map(dbTx => ({
                        id: dbTx.id,
                        date: dbTx.transaction_date,
                        amount: dbTx.amount,
                        description: dbTx.description,
                        cleanedDescription: dbTx.description, 
                        contributionType: dbTx.type,
                        originalAmount: String(dbTx.amount)
                    }));

                    const virtualContent = liveTransactions
                        .map(t => `${t.date};${t.description};${t.amount};${t.contributionType}`)
                        .join('\n');

                    const targetBankId = banksRes.data && banksRes.data.length > 0 ? banksRes.data[0].id : 'active-session-bank';

                    reconciliation.setBankStatementFile({
                        bankId: targetBankId,
                        content: virtualContent,
                        fileName: 'Sessão Ativa (Nuvem)',
                        processedTransactions: liveTransactions as Transaction[],
                        rawFile: undefined 
                    });

                    if (reconciliation.matchResults.length === 0) {
                        const mappedResults: MatchResult[] = liveTransactions.map(tx => ({
                            transaction: tx as Transaction,
                            contributor: null,
                            status: 'NÃO IDENTIFICADO',
                            church: PLACEHOLDER_CHURCH,
                            matchMethod: undefined,
                            similarity: 0
                        }));

                        reconciliation.setMatchResults(mappedResults);
                        reconciliation.setReportPreviewData({
                            income: groupResultsByChurch(mappedResults),
                            expenses: { 'all_expenses_group': [] }
                        });

                        reconciliation.setHasActiveSession(true);
                    }
                }
            } catch (dbError) {
                console.warn("[Hydration] Falha ao carregar Lista Viva (Tabela pode não existir ainda):", dbError);
                // Não faz nada, permite que o app carregue sem a lista viva
            }

        } catch (err) { 
            console.error('Critical sync failed', err); 
        } finally { 
            setIsSyncing(false); 
            setInitialDataLoaded(true); // Garante que a tela de loading saia
        }
    };

    fetchData();
}, [user?.id]);

import React, { createContext, useState, useEffect, useContext, useMemo, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReconciliation } from '../hooks/useReconciliation';
import { useReportManager } from '../hooks/useReportManager';
import { 
    Bank, Church, FileModel, MatchResult, SavedReport, 
    SearchFilters, Transaction, Contributor, DeletingItem,
    SavingReportState, SpreadsheetData, ComparisonType,
    LearnedAssociation, GroupedReportData
} from '../types';
import { modelService } from '../services/modelService';
import { supabase } from '../services/supabaseClient';
import { consolidationService } from '../services/ConsolidationService';
import { PLACEHOLDER_CHURCH, groupResultsByChurch } from '../services/processingService';

// Define context type (extensive, based on usage)
interface AppContextType {
    // Reference Data
    banks: Bank[];
    churches: Church[];
    fileModels: FileModel[];
    similarityLevel: number;
    setSimilarityLevel: (level: number) => void;
    dayTolerance: number;
    setDayTolerance: (days: number) => void;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: LearnedAssociation[];
    addBank: (name: string) => Promise<boolean>;
    updateBank: (id: string, name: string) => void;
    addChurch: (data: any) => Promise<boolean>;
    updateChurch: (id: string, data: any) => void;
    learnAssociation: (match: MatchResult) => void;
    addIgnoreKeyword: (k: string) => void;
    removeIgnoreKeyword: (k: string) => void;
    addContributionKeyword: (k: string) => void;
    removeContributionKeyword: (k: string) => void;
    fetchModels: () => void;

    // Modals & Editing State (Reference Data)
    editingBank: Bank | null;
    openEditBank: (bank: Bank) => void;
    closeEditBank: () => void;
    editingChurch: Church | null;
    openEditChurch: (church: Church) => void;
    closeEditChurch: () => void;

    // Reconciliation
    bankStatementFile: { bankId: string; content: string; fileName: string; rawFile?: File; processedTransactions?: Transaction[] } | null;
    setBankStatementFile: React.Dispatch<React.SetStateAction<{ bankId: string; content: string; fileName: string; rawFile?: File; processedTransactions?: Transaction[] } | null>>;
    contributorFiles: { churchId: string; content: string; fileName: string; contributors?: Contributor[] }[];
    matchResults: MatchResult[];
    setMatchResults: React.Dispatch<React.SetStateAction<MatchResult[]>>;
    reportPreviewData: { income: GroupedReportData; expenses: GroupedReportData } | null;
    setReportPreviewData: React.Dispatch<React.SetStateAction<{ income: GroupedReportData; expenses: GroupedReportData } | null>>;
    hasActiveSession: boolean;
    setHasActiveSession: React.Dispatch<React.SetStateAction<boolean>>;
    activeReportId: string | null;
    setActiveReportId: React.Dispatch<React.SetStateAction<string | null>>;
    comparisonType: ComparisonType;
    setComparisonType: (type: ComparisonType) => void;

    handleStatementUpload: (content: string, fileName: string, bankId: string, rawFile: File) => void;
    handleContributorsUpload: (content: string, fileName: string, churchId: string, rawFile?: File) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (churchId: string) => void;
    clearFiles: () => void;
    handleCompare: () => Promise<void>;
    updateReportData: (updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => void;
    discardCurrentReport: () => void;
    resetReconciliation: () => void;

    // Reconciliation - Manual & AI
    manualIdentificationTx: Transaction | null;
    setManualIdentificationTx: React.Dispatch<React.SetStateAction<Transaction | null>>;
    bulkIdentificationTxs: Transaction[] | null;
    setBulkIdentificationTxs: React.Dispatch<React.SetStateAction<Transaction[] | null>>;
    closeManualIdentify: () => void;
    openManualIdentify: (transactionId: string) => void;
    openBulkManualIdentify: (transactions: Transaction[]) => void;
    confirmManualIdentification: (transactionId: string, churchId: string) => void;
    confirmBulkManualIdentification: (transactionIds: string[], churchId: string) => void;
    findMatchResult: (transactionId: string) => MatchResult | undefined;
    undoIdentification: (transactionId: string) => void;

    manualMatchState: { record: MatchResult; suggestions: Transaction[] } | null;
    setManualMatchState: React.Dispatch<React.SetStateAction<{ record: MatchResult; suggestions: Transaction[] } | null>>;
    openManualMatchModal: (record: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (tx: Transaction) => void;

    divergenceConfirmation: MatchResult | null;
    setDivergenceConfirmation: React.Dispatch<React.SetStateAction<MatchResult | null>>;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (match: MatchResult) => void;
    rejectDivergence: (match: MatchResult) => void;

    loadingAiId: string | null;
    setLoadingAiId: React.Dispatch<React.SetStateAction<string | null>>;
    aiSuggestion: { id: string; name: string } | null;
    setAiSuggestion: React.Dispatch<React.SetStateAction<{ id: string; name: string } | null>>;
    handleAnalyze: (tx: Transaction, contributors: Contributor[]) => void;

    smartEditTarget: MatchResult | null;
    openSmartEdit: (target: MatchResult) => void;
    closeSmartEdit: () => void;
    saveSmartEdit: (updated: MatchResult) => void;

    pendingTraining: { content: string; fileName: string; type: 'statement' | 'contributor'; entityId: string; rawFile?: File } | null;
    setPendingTraining: React.Dispatch<React.SetStateAction<{ content: string; fileName: string; type: 'statement' | 'contributor'; entityId: string; rawFile?: File } | null>>;
    handleTrainingSuccess: (model: FileModel, data: Transaction[]) => void;
    openLabManually: (file?: any) => void;

    // Reports & Search
    savedReports: SavedReport[];
    setSavedReports: React.Dispatch<React.SetStateAction<SavedReport[]>>;
    maxSavedReports: number;
    searchFilters: SearchFilters;
    setSearchFilters: React.Dispatch<React.SetStateAction<SearchFilters>>;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    clearSearchFilters: () => void;

    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => void;
    updateSavedReportName: (id: string, name: string) => void;
    updateSavedReportTransaction: (txId: string, result: MatchResult) => void;
    saveFilteredReport: (results: MatchResult[]) => void;
    overwriteSavedReport: (reportId: string, results: MatchResult[], spreadsheet?: SpreadsheetData) => void;
    deleteOldReports: (date: Date) => void;
    allHistoricalResults: MatchResult[];
    viewSavedReport: (reportId: string) => void;

    // App State / UI
    initialDataLoaded: boolean;
    setInitialDataLoaded: React.Dispatch<React.SetStateAction<boolean>>;
    isSyncing: boolean;
    setIsSyncing: React.Dispatch<React.SetStateAction<boolean>>;

    // Deletion Modal
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;

    // Other Modals
    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;

    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    isUpdateFilesModalOpen: boolean;
    openUpdateFilesModal: () => void;
    closeUpdateFilesModal: () => void;

    // Derived
    isCompareDisabled: boolean;
    summary: any;
    effectiveIgnoreKeywords: string[]; // Combined global + custom

    handleGmailSyncSuccess: (transactions: Transaction[]) => void;
    activeSpreadsheetData?: SpreadsheetData;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user, systemSettings } = useAuth();
    const { showToast, setActiveView, setIsLoading } = useUI();
    const [initialDataLoaded, setInitialDataLoaded] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);

    // --- Hooks Composition ---
    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);
    const reconciliation = useReconciliation({
        user,
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: referenceData.fileModels,
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: referenceData.customIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast,
        setIsLoading,
        setActiveView
    });

    // --- Global State ---
    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);
    const [isUpdateFilesModalOpen, setIsUpdateFilesModalOpen] = useState(false);
    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);

    // Combine global keywords with custom ones
    const effectiveIgnoreKeywords = useMemo(() => {
        const globals = systemSettings?.globalIgnoreKeywords || [];
        return Array.from(new Set([...globals, ...referenceData.customIgnoreKeywords]));
    }, [systemSettings, referenceData.customIgnoreKeywords]);

    // --- Manual Identification Logic (Bridging RefData & Reconciliation) ---
    const openManualIdentify = (transactionId: string) => {
        const tx = reconciliation.matchResults.find(r => r.transaction.id === transactionId)?.transaction;
        if (tx) {
            reconciliation.setManualIdentificationTx(tx);
            reconciliation.setBulkIdentificationTxs(null);
        }
    };

    const openBulkManualIdentify = (transactions: Transaction[]) => {
        if (transactions.length > 0) {
            reconciliation.setBulkIdentificationTxs(transactions);
            reconciliation.setManualIdentificationTx(null);
        }
    };

    const findMatchResult = useCallback((transactionId: string) => {
        return reconciliation.matchResults.find(r => r.transaction.id === transactionId);
    }, [reconciliation.matchResults]);

    const confirmManualIdentification = (transactionId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        const result = findMatchResult(transactionId);

        if (church && result) {
            const updatedResult: MatchResult = {
                ...result,
                status: 'IDENTIFICADO',
                church: church,
                matchMethod: 'MANUAL',
                similarity: 100
            };

            // Learn association if enabled logic exists in useReferenceData (it does)
            referenceData.learnAssociation(updatedResult);

            reconciliation.updateReportData(updatedResult, 'income');
            reconciliation.closeManualIdentify();
            showToast("Identificação manual realizada.", "success");
        }
    };

    const confirmBulkManualIdentification = (transactionIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        let count = 0;
        transactionIds.forEach(id => {
            const result = findMatchResult(id);
            if (result) {
                const updatedResult: MatchResult = {
                    ...result,
                    status: 'IDENTIFICADO',
                    church: church,
                    matchMethod: 'MANUAL',
                    similarity: 100
                };
                referenceData.learnAssociation(updatedResult);
                reconciliation.updateReportData(updatedResult, 'income');
                count++;
            }
        });

        reconciliation.closeManualIdentify();
        showToast(`${count} transações identificadas em massa.`, "success");
    };

    const undoIdentification = (transactionId: string) => {
        const result = findMatchResult(transactionId);
        if (result && result.status === 'IDENTIFICADO') {
            const originalStatus = result.contributor ? 'PENDENTE' : 'NÃO IDENTIFICADO';
            const updatedResult: MatchResult = {
                ...result,
                status: 'NÃO IDENTIFICADO', // Reset to unidentified mostly
                church: PLACEHOLDER_CHURCH,
                matchMethod: undefined,
                similarity: result.similarity // Keep original similarity if needed
            };

            // Se tinha contribuinte original, talvez devesse voltar para PENDENTE/SUGESTÃO? 
            // Simplificação: Volta para não identificado na lista geral
            reconciliation.updateReportData(updatedResult, 'income');
            showToast("Identificação desfeita.", "success");
        }
    };

    // --- Smart Edit ---
    const openSmartEdit = (target: MatchResult) => setSmartEditTarget(target);
    const closeSmartEdit = () => setSmartEditTarget(null);

    const saveSmartEdit = (updated: MatchResult) => {
        // Se tinha ID fantasma (pendente), remove
        const ghostId = updated.status === 'IDENTIFICADO' && smartEditTarget?.status === 'PENDENTE' 
            ? smartEditTarget.transaction.id 
            : undefined;

        reconciliation.updateReportData(updated, 'income', ghostId);

        if (updated.status === 'IDENTIFICADO') {
            referenceData.learnAssociation(updated);
        }

        closeSmartEdit();
        showToast("Registro atualizado.", "success");
    };

    // --- Deletion Logic ---
    const openDeleteConfirmation = (item: DeletingItem) => setDeletingItem(item);
    const closeDeleteConfirmation = () => setDeletingItem(null);

    const confirmDeletion = async () => {
        if (!deletingItem) return;

        const { type, id } = deletingItem;

        try {
            switch (type) {
                case 'bank':
                    if (referenceData.banks.length <= 1) { // Prevent deleting last bank if logic requires
                        // actually no hard constraint
                    }
                    referenceData.setBanks(prev => prev.filter(b => b.id !== id));
                    await supabase.from('banks').delete().eq('id', id);
                    showToast("Banco excluído.", "success");
                    break;
                case 'church':
                    referenceData.setChurches(prev => prev.filter(c => c.id !== id));
                    reconciliation.removeContributorFile(id);
                    await supabase.from('churches').delete().eq('id', id);
                    showToast("Igreja excluída.", "success");
                    break;
                case 'report-saved':
                    reportManager.setSavedReports(prev => prev.filter(r => r.id !== id));
                    await supabase.from('saved_reports').delete().eq('id', id);
                    showToast("Relatório excluído.", "success");
                    break;
                case 'report-row':
                    const rowToDelete = findMatchResult(id);
                    if (rowToDelete) {
                        reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== id));
                        reconciliation.updateReportData(rowToDelete, deletingItem.meta?.reportType || 'income', id); // Force remove from groups
                        showToast("Linha removida do relatório.", "success");
                    }
                    break;
                case 'uploaded-files':
                    reconciliation.setBankStatementFile(null);
                    reconciliation.setContributorFiles([]);
                    showToast("Arquivos limpos.", "success");
                    break;
                case 'match-results':
                    reconciliation.setMatchResults([]);
                    reconciliation.setReportPreviewData(null);
                    reconciliation.setHasActiveSession(false);
                    showToast("Resultados limpos.", "success");
                    break;
                case 'learned-associations':
                    referenceData.setLearnedAssociations([]);
                    await supabase.from('learned_associations').delete().eq('user_id', user!.id);
                    showToast("Associações aprendidas excluídas.", "success");
                    break;
                case 'all-data':
                    // Reset everything
                    referenceData.setBanks([]);
                    referenceData.setChurches([]);
                    referenceData.setLearnedAssociations([]);
                    reconciliation.resetReconciliation();
                    // Keep saved reports? The text says "restore system to initial state".
                    // Usually "All Data" implies local workspace reset, maybe not saved reports.
                    // But implementation in SettingsView says "delete all... registrations (banks/churches)".

                    if (user) {
                        // Delete from DB
                        await Promise.all([
                            supabase.from('banks').delete().eq('user_id', user.id),
                            supabase.from('churches').delete().eq('user_id', user.id),
                            supabase.from('learned_associations').delete().eq('user_id', user.id),
                            // Optional: Delete file_models?
                        ]);
                    }
                    showToast("Sistema resetado com sucesso.", "success");
                    break;
            }
        } catch (error) {
            console.error("Deletion error", error);
            showToast("Erro ao excluir item.", "error");
        } finally {
            closeDeleteConfirmation();
        }
    };

    // --- Sync & Hydration ---
    // Copied logic from provided file fragment
    useEffect(() => {
        if (!user) {
            setInitialDataLoaded(true);
            return;
        }

        const fetchData = async () => {
            setIsSyncing(true);
            try {
                const [churchesRes, banksRes, reportsRes] = await Promise.all([
                    supabase.from('churches').select('*').order('name'),
                    supabase.from('banks').select('*').order('name'),
                    supabase.from('saved_reports')
                        .select('id, name, created_at, record_count, user_id') 
                        .eq('user_id', user.id)
                        .order('created_at', { ascending: false }),
                ]);

                if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
                if (banksRes.data) referenceData.setBanks(banksRes.data as any);
                if (reportsRes.data) {
                    reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null 
                    })));
                }

                // Try to recover live list
                try {
                    const pendingTxs = await consolidationService.getPendingTransactions(user.id);

                    if (pendingTxs && pendingTxs.length > 0) {
                        console.log(`[Hydration] Recuperando ${pendingTxs.length} transações vivas do banco.`);

                        const liveTransactions = pendingTxs.map(dbTx => ({
                            id: dbTx.id,
                            date: dbTx.transaction_date,
                            amount: dbTx.amount,
                            description: dbTx.description,
                            cleanedDescription: dbTx.description, 
                            contributionType: dbTx.type,
                            originalAmount: String(dbTx.amount)
                        }));

                        const virtualContent = liveTransactions
                            .map(t => `${t.date};${t.description};${t.amount};${t.contributionType}`)
                            .join('\n');

                        const targetBankId = banksRes.data && banksRes.data.length > 0 ? banksRes.data[0].id : 'active-session-bank';

                        reconciliation.setBankStatementFile({
                            bankId: targetBankId,
                            content: virtualContent,
                            fileName: 'Sessão Ativa (Nuvem)',
                            processedTransactions: liveTransactions as Transaction[],
                            rawFile: undefined 
                        });

                        if (reconciliation.matchResults.length === 0) {
                            const mappedResults: MatchResult[] = liveTransactions.map(tx => ({
                                transaction: tx as Transaction,
                                contributor: null,
                                status: 'NÃO IDENTIFICADO',
                                church: PLACEHOLDER_CHURCH,
                                matchMethod: undefined,
                                similarity: 0
                            }));

                            reconciliation.setMatchResults(mappedResults);
                            reconciliation.setReportPreviewData({
                                income: groupResultsByChurch(mappedResults),
                                expenses: { 'all_expenses_group': [] }
                            });

                            reconciliation.setHasActiveSession(true);
                        }
                    }
                } catch (dbError) {
                    console.warn("[Hydration] Falha ao carregar Lista Viva:", dbError);
                }

            } catch (err) { 
                console.error('Critical sync failed', err); 
            } finally { 
                setIsSyncing(false); 
                setInitialDataLoaded(true); 
            }
        };

        fetchData();
    }, [user?.id]); // Only re-run if user ID changes

    // --- Gmail Sync ---
    const handleGmailSyncSuccess = (transactions: Transaction[]) => {
        // Similar to handleStatementUpload but assumes parsed transactions
        // We create a virtual CSV content
        const csvContent = transactions.map(t => `${t.date};${t.description};${t.amount};${t.contributionType}`).join('\n');
        const virtualFile = new File([csvContent], "gmail_import.csv", { type: "text/csv" });

        // Use a generic bank ID or first available
        const targetBankId = referenceData.banks.length > 0 ? referenceData.banks[0].id : 'gmail-bank';

        reconciliation.handleStatementUpload(csvContent, `Gmail Sync ${new Date().toLocaleDateString()}`, targetBankId, virtualFile);
    };

    // --- Report View Logic ---
    const viewSavedReport = async (reportId: string) => {
        setIsLoading(true);
        try {
            const { data, error } = await supabase.from('saved_reports').select('*').eq('id', reportId).single();

            if (error) throw error;
            if (!data) throw new Error("Relatório não encontrado");

            const reportData = data.data as any; // Typed as Json in DB

            reconciliation.clearFiles();
            reconciliation.setMatchResults(reportData.results || []);

            // Re-hydrate church objects if they are just IDs
            // Note: services/analysisProcessor.ts hydrateMatchResults does this better, 
            // but we need to do it here for the context state.
            // Simplified hydration:
            if (reportData.results) {
               // ... logic similar to hydrateMatchResults would be good here
               // For now, assume saved data is sufficient or will be hydrated by views
            }

            // Grouping logic for preview
            const income = groupResultsByChurch(reportData.results?.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE') || []);
            const expenses = { 'all_expenses_group': reportData.results?.filter((r: any) => r.transaction.amount < 0) || [] };

            reconciliation.setReportPreviewData({ income, expenses });
            reconciliation.setHasActiveSession(true);
            reconciliation.setActiveReportId(reportId);

            setActiveView('reports');
        } catch (e: any) {
            console.error(e);
            showToast("Erro ao abrir relatório: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    };

    // --- Derived ---
    const summary = useMemo(() => {
        const results = reconciliation.matchResults;
        if (!results) return { totalValue: 0, identifiedCount: 0, unidentifiedCount: 0, autoConfirmed: { value: 0 }, manualConfirmed: { value: 0 }, pending: { value: 0 }, valuePerChurch: [], methodBreakdown: {} };

        const identified = results.filter(r => r.status === 'IDENTIFICADO');
        const unidentified = results.filter(r => r.status === 'NÃO IDENTIFICADO' || r.status === 'PENDENTE');

        const totalValue = results.reduce((acc, r) => acc + Math.abs(r.transaction.amount), 0);

        const methodBreakdown = results.reduce((acc: any, r) => {
            const method = r.matchMethod || 'AUTOMATIC';
            if (r.status === 'IDENTIFICADO') {
                acc[method] = (acc[method] || 0) + 1;
            }
            return acc;
        }, { AUTOMATIC: 0, MANUAL: 0, LEARNED: 0, AI: 0 });

        const autoConfirmed = identified.filter(r => r.matchMethod !== 'MANUAL' && r.matchMethod !== 'AI').reduce((acc, r) => acc + Math.abs(r.transaction.amount), 0);
        const manualConfirmed = identified.filter(r => r.matchMethod === 'MANUAL' || r.matchMethod === 'AI').reduce((acc, r) => acc + Math.abs(r.transaction.amount), 0);
        const pendingValue = unidentified.reduce((acc, r) => acc + Math.abs(r.transaction.amount), 0);

        // Value per church
        const churchMap: Record<string, number> = {};
        identified.forEach(r => {
            const name = r.church?.name || 'Desconhecida';
            churchMap[name] = (churchMap[name] || 0) + Math.abs(r.transaction.amount);
        });
        const valuePerChurch = Object.entries(churchMap).sort((a, b) => b[1] - a[1]);

        return {
            totalValue,
            identifiedCount: identified.length,
            unidentifiedCount: unidentified.length,
            autoConfirmed: { value: autoConfirmed },
            manualConfirmed: { value: manualConfirmed },
            pending: { value: pendingValue },
            valuePerChurch,
            methodBreakdown,
            isHistorical: !!reconciliation.activeReportId
        };
    }, [reconciliation.matchResults, reconciliation.activeReportId]);

    const activeSpreadsheetData = useMemo(() => {
        if (!reconciliation.activeReportId) return undefined;
        const report = reportManager.savedReports.find(r => r.id === reconciliation.activeReportId);
        return report?.data?.spreadsheet;
    }, [reconciliation.activeReportId, reportManager.savedReports]);

    const contextValue: AppContextType = {
        ...referenceData,
        ...reconciliation,
        ...reportManager,

        initialDataLoaded,
        setInitialDataLoaded,
        isSyncing,
        setIsSyncing,

        deletingItem,
        openDeleteConfirmation,
        closeDeleteConfirmation,
        confirmDeletion,

        isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true),
        closePaymentModal: () => setIsPaymentModalOpen(false),

        isRecompareModalOpen,
        openRecompareModal: () => setIsRecompareModalOpen(true),
        closeRecompareModal: () => setIsRecompareModalOpen(false),

        isUpdateFilesModalOpen,
        openUpdateFilesModal: () => setIsUpdateFilesModalOpen(true),
        closeUpdateFilesModal: () => setIsUpdateFilesModalOpen(false),

        smartEditTarget,
        openSmartEdit,
        closeSmartEdit,
        saveSmartEdit,

        openManualIdentify,
        openBulkManualIdentify,
        closeManualIdentify: reconciliation.closeManualIdentify,
        manualIdentificationTx: reconciliation.manualIdentificationTx,
        setManualIdentificationTx: reconciliation.setManualIdentificationTx,
        bulkIdentificationTxs: reconciliation.bulkIdentificationTxs,
        setBulkIdentificationTxs: reconciliation.setBulkIdentificationTxs,
        confirmManualIdentification,
        confirmBulkManualIdentification,
        undoIdentification,
        findMatchResult,

        isCompareDisabled: !reconciliation.bankStatementFile && !reconciliation.activeReportId,
        summary,
        effectiveIgnoreKeywords,

        handleGmailSyncSuccess,
        viewSavedReport,
        activeSpreadsheetData
    };

    return (
        <AppContext.Provider value={contextValue}>
            {children}
        </AppContext.Provider>
    );
};

// --- FETCH DE DADOS E HIDRATAÇÃO ---
// Estratégia de "Fail-Safe": Carrega cada entidade independentemente.
// Se uma tabela falhar (ex: Lista Viva), as outras (Bancos/Igrejas) ainda aparecem.
useEffect(() => {
    if (!user) {
        setInitialDataLoaded(true);
        return;
    }

    const fetchData = async () => {
        setIsSyncing(true);

        // 1. Carregar Igrejas
        try {
            const { data, error } = await supabase.from('churches').select('*').order('name');
            if (error) throw error;
            if (data) referenceData.setChurches(data as any);
        } catch (e) {
            console.warn("[Hydration] Falha ao carregar Igrejas:", e);
        }

        // 2. Carregar Bancos
        try {
            const { data, error } = await supabase.from('banks').select('*').order('name');
            if (error) throw error;
            if (data) referenceData.setBanks(data as any);
        } catch (e) {
            console.warn("[Hydration] Falha ao carregar Bancos:", e);
        }

        // 3. Carregar Relatórios Salvos
        try {
            const { data, error } = await supabase.from('saved_reports')
                .select('id, name, created_at, record_count, user_id') 
                .eq('user_id', user.id)
                .order('created_at', { ascending: false });

            if (error) throw error;

            if (data) {
                reportManager.setSavedReports((data || []).map(r => ({ 
                    id: r.id, 
                    name: r.name, 
                    createdAt: r.created_at, 
                    recordCount: r.record_count, 
                    user_id: r.user_id, 
                    data: null 
                })));
            }
        } catch (e) {
            console.warn("[Hydration] Falha ao carregar Relatórios:", e);
        }

        // 4. Carregar Lista Viva (Transações Pendentes)
        // Esta é a parte mais sensível a erros de esquema (404), então isolamos completamente.
        try {
            const pendingTxs = await consolidationService.getPendingTransactions(user.id);

            if (pendingTxs && pendingTxs.length > 0) {
                console.log(`[Hydration] Recuperando ${pendingTxs.length} transações vivas do banco.`);

                const liveTransactions = pendingTxs.map(dbTx => ({
                    id: dbTx.id,
                    date: dbTx.transaction_date,
                    amount: dbTx.amount,
                    description: dbTx.description,
                    cleanedDescription: dbTx.description, 
                    contributionType: dbTx.type,
                    originalAmount: String(dbTx.amount)
                }));

                const virtualContent = liveTransactions
                    .map(t => `${t.date};${t.description};${t.amount};${t.contributionType}`)
                    .join('\n');

                // Usa o primeiro banco disponível ou um placeholder
                const targetBankId = referenceData.banks.length > 0 ? referenceData.banks[0].id : 'active-session-bank';

                reconciliation.setBankStatementFile({
                    bankId: targetBankId,
                    content: virtualContent,
                    fileName: 'Sessão Ativa (Nuvem)',
                    processedTransactions: liveTransactions as Transaction[],
                    rawFile: undefined 
                });

                if (reconciliation.matchResults.length === 0) {
                    const mappedResults: MatchResult[] = liveTransactions.map(tx => ({
                        transaction: tx as Transaction,
                        contributor: null,
                        status: 'NÃO IDENTIFICADO',
                        church: PLACEHOLDER_CHURCH,
                        matchMethod: undefined,
                        similarity: 0
                    }));

                    reconciliation.setMatchResults(mappedResults);
                    reconciliation.setReportPreviewData({
                        income: groupResultsByChurch(mappedResults),
                        expenses: { 'all_expenses_group': [] }
                    });

                    reconciliation.setHasActiveSession(true);
                }
            }
        } catch (dbError) {
            console.warn("[Hydration] Falha ao carregar Lista Viva (Provavelmente tabela nova ausente):", dbError);
        }

        setIsSyncing(false); 
        setInitialDataLoaded(true); // Libera a UI
    };

    fetchData();
}, [user?.id]);

import React, { createContext, useState, useEffect, useMemo, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReconciliation } from '../hooks/useReconciliation';
import { useReportManager } from '../hooks/useReportManager';
import { 
    Bank, Church, MatchResult, Transaction, Contributor, 
    SavedReport, SearchFilters, DeletingItem, SavingReportState, 
    FileModel, SpreadsheetData 
} from '../types';
import { supabase } from '../services/supabaseClient';
import { consolidationService } from '../services/ConsolidationService';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';

// Create Context
export const AppContext = createContext<any>(null!);

// Provider Component
export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user } = useAuth();
    const { showToast, setIsLoading, setActiveView } = useUI();

    // --- 1. Reference Data Hook ---
    const referenceData = useReferenceData(user, showToast);

    // --- 2. Report Manager Hook ---
    const reportManager = useReportManager(user, showToast);

    // --- 3. Reconciliation Hook ---
    const reconciliation = useReconciliation({
        user,
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: referenceData.fileModels,
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: referenceData.customIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast,
        setIsLoading,
        setActiveView
    });

    // --- 4. Global UI State & Modals ---
    const [initialDataLoaded, setInitialDataLoaded] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);

    // Delete Modal
    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);

    // Payment Modal
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const openPaymentModal = useCallback(() => setIsPaymentModalOpen(true), []);
    const closePaymentModal = useCallback(() => setIsPaymentModalOpen(false), []);

    // Smart Edit Modal
    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);
    const openSmartEdit = useCallback((target: MatchResult) => setSmartEditTarget(target), []);
    const closeSmartEdit = useCallback(() => setSmartEditTarget(null), []);

    // Update Files Modal
    const [isUpdateFilesModalOpen, setIsUpdateFilesModalOpen] = useState(false);
    const openUpdateFilesModal = useCallback(() => setIsUpdateFilesModalOpen(true), []);
    const closeUpdateFilesModal = useCallback(() => setIsUpdateFilesModalOpen(false), []);

    // Recompare Modal
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);
    const openRecompareModal = useCallback(() => setIsRecompareModalOpen(true), []);
    const closeRecompareModal = useCallback(() => setIsRecompareModalOpen(false), []);

    // Active Spreadsheet (Derived)
    const activeSpreadsheetData = useMemo(() => {
        if (reconciliation.activeReportId) {
            const report = reportManager.savedReports.find(r => r.id === reconciliation.activeReportId);
            return report?.data?.spreadsheet;
        }
        return null;
    }, [reconciliation.activeReportId, reportManager.savedReports]);

    // Summary Statistics
    const summary = useMemo(() => {
        const results = reconciliation.matchResults;
        const totalValue = results.reduce((acc, r) => acc + Math.abs(r.transaction.amount), 0);
        const identified = results.filter(r => r.status === 'IDENTIFICADO');
        const unidentified = results.filter(r => r.status === 'NÃO IDENTIFICADO');
        const pending = results.filter(r => r.status === 'PENDENTE');

        const valuePerChurch = Object.entries(groupResultsByChurch(results))
            .filter(([id]) => id !== 'unidentified' && id !== 'placeholder')
            .map(([id, items]) => {
                const churchName = items[0]?.church?.name || 'Desconhecida';
                const total = items.reduce((sum, item) => sum + item.transaction.amount, 0);
                return [churchName, total] as [string, number];
            })
            .sort((a, b) => b[1] - a[1])
            .slice(0, 5);

        // Method Breakdown
        const methodBreakdown = {
            'AUTOMATIC': identified.filter(r => r.matchMethod === 'AUTOMATIC').length,
            'MANUAL': identified.filter(r => r.matchMethod === 'MANUAL').length,
            'LEARNED': identified.filter(r => r.matchMethod === 'LEARNED').length,
            'AI': identified.filter(r => r.matchMethod === 'AI').length,
        };

        return {
            totalValue,
            identifiedCount: identified.length,
            unidentifiedCount: unidentified.length + pending.length,
            autoConfirmed: { value: identified.reduce((acc, r) => acc + r.transaction.amount, 0) }, 
            manualConfirmed: { value: 0 }, 
            pending: { value: unidentified.reduce((acc, r) => acc + Math.abs(r.transaction.amount), 0) + pending.reduce((acc,r) => acc + (r.contributorAmount || 0), 0) },
            valuePerChurch,
            methodBreakdown,
            isHistorical: !!reconciliation.activeReportId
        };
    }, [reconciliation.matchResults, reconciliation.activeReportId]);

    // --- HYDRATION ---
    useEffect(() => {
        if (!user) {
            setInitialDataLoaded(true);
            return;
        }

        const fetchData = async () => {
            setIsSyncing(true);

            // 1. Carregar Igrejas
            try {
                const { data, error } = await supabase.from('churches').select('*').order('name');
                if (error) throw error;
                if (data) referenceData.setChurches(data as any);
            } catch (e) {
                console.warn("[Hydration] Falha ao carregar Igrejas:", e);
            }

            // 2. Carregar Bancos
            try {
                const { data, error } = await supabase.from('banks').select('*').order('name');
                if (error) throw error;
                if (data) referenceData.setBanks(data as any);
            } catch (e) {
                console.warn("[Hydration] Falha ao carregar Bancos:", e);
            }

            // 3. Carregar Relatórios Salvos
            try {
                const { data, error } = await supabase.from('saved_reports')
                    .select('id, name, created_at, record_count, user_id') 
                    .eq('user_id', user.id)
                    .order('created_at', { ascending: false });

                if (error) throw error;

                if (data) {
                    reportManager.setSavedReports((data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null 
                    })));
                }
            } catch (e) {
                console.warn("[Hydration] Falha ao carregar Relatórios:", e);
            }

            // 4. Carregar Lista Viva (Transações Pendentes)
            try {
                const pendingTxs = await consolidationService.getPendingTransactions(user.id);

                if (pendingTxs && pendingTxs.length > 0) {
                    const liveTransactions = pendingTxs.map(dbTx => ({
                        id: dbTx.id,
                        date: dbTx.transaction_date,
                        amount: dbTx.amount,
                        description: dbTx.description,
                        cleanedDescription: dbTx.description, 
                        contributionType: dbTx.type,
                        originalAmount: String(dbTx.amount)
                    }));

                    const virtualContent = liveTransactions
                        .map(t => `${t.date};${t.description};${t.amount};${t.contributionType}`)
                        .join('\n');

                    const targetBankId = referenceData.banks.length > 0 ? referenceData.banks[0].id : 'active-session-bank';

                    reconciliation.setBankStatementFile({
                        bankId: targetBankId,
                        content: virtualContent,
                        fileName: 'Sessão Ativa (Nuvem)',
                        processedTransactions: liveTransactions as Transaction[],
                        rawFile: undefined 
                    });

                    if (reconciliation.matchResults.length === 0) {
                        const mappedResults: MatchResult[] = liveTransactions.map(tx => ({
                            transaction: tx as Transaction,
                            contributor: null,
                            status: 'NÃO IDENTIFICADO',
                            church: PLACEHOLDER_CHURCH,
                            matchMethod: undefined,
                            similarity: 0
                        }));

                        reconciliation.setMatchResults(mappedResults);
                        reconciliation.setReportPreviewData({
                            income: groupResultsByChurch(mappedResults),
                            expenses: { 'all_expenses_group': [] }
                        });

                        reconciliation.setHasActiveSession(true);
                    }
                }
            } catch (dbError) {
                console.warn("[Hydration] Falha ao carregar Lista Viva:", dbError);
            }

            setIsSyncing(false); 
            setInitialDataLoaded(true);
        };

        fetchData();
    }, [user?.id]);

    // --- ACTIONS IMPLEMENTATIONS ---

    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;

        setIsLoading(true);
        try {
            switch (deletingItem.type) {
                case 'bank':
                    const { error: bankError } = await supabase.from('banks').delete().eq('id', deletingItem.id);
                    if (bankError) throw bankError;
                    referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
                    showToast('Banco removido.', 'success');
                    break;

                case 'church':
                    const { error: churchError } = await supabase.from('churches').delete().eq('id', deletingItem.id);
                    if (churchError) throw churchError;
                    referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
                    showToast('Igreja removida.', 'success');
                    break;

                case 'report-saved':
                    const { error: repError } = await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
                    if (repError) throw repError;
                    reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
                    showToast('Relatório excluído.', 'success');
                    break;

                case 'report-row':
                    reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
                    const reportType = deletingItem.meta?.reportType || 'income';
                    reconciliation.setReportPreviewData(prev => {
                        if(!prev) return null;
                        const newPrev = {...prev};
                        const targetGroup = reportType === 'expenses' ? newPrev.expenses : newPrev.income;
                        Object.keys(targetGroup).forEach(k => {
                            targetGroup[k] = targetGroup[k].filter((r: MatchResult) => r.transaction.id !== deletingItem.id);
                        });
                        return newPrev;
                    });
                    showToast('Linha removida.', 'success');
                    break;

                case 'uploaded-files':
                    reconciliation.removeBankStatementFile();
                    reconciliation.setContributorFiles([]);
                    showToast('Arquivos limpos.', 'success');
                    break;

                case 'match-results':
                    reconciliation.setMatchResults([]);
                    reconciliation.setReportPreviewData(null);
                    reconciliation.setHasActiveSession(false);
                    reconciliation.setActiveReportId(null);
                    showToast('Resultados limpos.', 'success');
                    break;

                case 'learned-associations':
                    const { error: laError } = await supabase.from('learned_associations').delete().eq('user_id', user!.id);
                    if (laError) throw laError;
                    referenceData.setLearnedAssociations([]);
                    showToast('Associações aprendidas removidas.', 'success');
                    break;

                case 'all-data':
                    if (user) {
                        await supabase.from('banks').delete().eq('user_id', user.id);
                        await supabase.from('churches').delete().eq('user_id', user.id);
                        await supabase.from('learned_associations').delete().eq('user_id', user.id);
                    }
                    referenceData.setBanks([]);
                    referenceData.setChurches([]);
                    referenceData.setLearnedAssociations([]);
                    reconciliation.resetReconciliation();
                    showToast('Reset completo realizado.', 'success');
                    break;
            }
        } catch (e: any) {
            console.error(e);
            showToast('Erro ao excluir: ' + e.message, 'error');
        } finally {
            setIsLoading(false);
            closeDeleteConfirmation();
        }
    }, [deletingItem, user, referenceData, reportManager, reconciliation, showToast, setIsLoading, closeDeleteConfirmation]);

    const saveSmartEdit = useCallback((updatedResult: MatchResult) => {
        reconciliation.updateReportData(updatedResult, 'income');
        if (smartEditTarget?.status === 'NÃO IDENTIFICADO' && updatedResult.status === 'IDENTIFICADO') {
            referenceData.learnAssociation(updatedResult);
        }
        closeSmartEdit();
        showToast('Identificação aplicada.', 'success');
    }, [smartEditTarget, reconciliation, referenceData, closeSmartEdit, showToast]);

    const confirmManualIdentification = useCallback((txId: string, churchId: string) => {
        const tx = reconciliation.matchResults.find(r => r.transaction.id === txId)?.transaction;
        if (!tx) return;

        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        const contributor: Contributor = {
            id: `manual-${txId}`,
            name: tx.cleanedDescription || tx.description,
            amount: tx.amount,
            date: tx.date,
            contributionType: tx.contributionType
        };

        const result: MatchResult = {
            transaction: tx,
            contributor,
            church,
            status: 'IDENTIFICADO',
            matchMethod: 'MANUAL',
            similarity: 100,
            contributorAmount: tx.amount
        };

        reconciliation.updateReportData(result, 'income');
        referenceData.learnAssociation(result);

        reconciliation.setManualIdentificationTx(null);
        reconciliation.setBulkIdentificationTxs(null);
        showToast('Identificado manualmente.', 'success');
    }, [reconciliation, referenceData, showToast]);

    const confirmBulkManualIdentification = useCallback((txIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        txIds.forEach(id => {
            const tx = reconciliation.matchResults.find(r => r.transaction.id === id)?.transaction;
            if (tx) {
                const contributor: Contributor = {
                    id: `manual-${id}`,
                    name: tx.cleanedDescription || tx.description,
                    amount: tx.amount,
                    date: tx.date,
                    contributionType: tx.contributionType
                };
                const result: MatchResult = {
                    transaction: tx,
                    contributor,
                    church,
                    status: 'IDENTIFICADO',
                    matchMethod: 'MANUAL',
                    similarity: 100,
                    contributorAmount: tx.amount
                };
                reconciliation.updateReportData(result, 'income');
                referenceData.learnAssociation(result);
            }
        });

        reconciliation.setManualIdentificationTx(null);
        reconciliation.setBulkIdentificationTxs(null);
        showToast(`${txIds.length} transações identificadas.`, 'success');
    }, [reconciliation, referenceData, showToast]);

    const openManualIdentify = useCallback((transactionId: string) => {
        const result = reconciliation.matchResults.find(r => r.transaction.id === transactionId);
        if (result) {
            reconciliation.setManualIdentificationTx(result.transaction);
        }
    }, [reconciliation.matchResults, reconciliation.setManualIdentificationTx]);

    const undoIdentification = useCallback((transactionId: string) => {
        const result = reconciliation.matchResults.find(r => r.transaction.id === transactionId);
        if (!result) return;

        const reverted: MatchResult = {
            ...result,
            status: 'NÃO IDENTIFICADO',
            contributor: null,
            church: PLACEHOLDER_CHURCH,
            matchMethod: undefined,
            similarity: 0
        };
        reconciliation.updateReportData(reverted, 'income');
        showToast('Identificação desfeita.', 'success');
    }, [reconciliation, showToast]);

    const saveCurrentReportChanges = useCallback(() => {
        if (reconciliation.activeReportId) {
            reportManager.overwriteSavedReport(reconciliation.activeReportId, reconciliation.matchResults);
        } else {
            showToast("Nenhum relatório ativo para salvar.", "error");
        }
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager, showToast]);

    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            const report = reportManager.savedReports.find(r => r.id === reportId);
            if (!report) throw new Error("Relatório não encontrado.");

            let results: MatchResult[] = [];
            if (!report.data) {
                const { data, error } = await supabase.from('saved_reports').select('data').eq('id', reportId).single();
                if(error) throw error;
                const parsed = typeof data.data === 'string' ? JSON.parse(data.data) : data.data;
                results = parsed.results;
            } else {
                results = report.data.results;
            }

            const hydratedResults = results.map(r => {
                const cId = r.church?.id || (r as any)._churchId;
                const church = referenceData.churches.find(c => c.id === cId) || r.church || PLACEHOLDER_CHURCH;
                return { ...r, church };
            });

            reconciliation.setMatchResults(hydratedResults);
            reconciliation.setReportPreviewData({
                income: groupResultsByChurch(hydratedResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                expenses: { 'all_expenses_group': hydratedResults.filter(r => r.transaction.amount < 0) }
            });
            reconciliation.setActiveReportId(reportId);
            reconciliation.setHasActiveSession(true);

            reconciliation.clearFiles();

            setActiveView('reports');
            showToast(`Relatório "${report.name}" carregado.`, 'success');

        } catch (e: any) {
            console.error(e);
            showToast("Erro ao abrir relatório: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, referenceData.churches, reconciliation, setActiveView, showToast, setIsLoading]);

    const handleGmailSyncSuccess = useCallback((transactions: Transaction[]) => {
        if (transactions.length === 0) return;

        if (user) {
             const consolidationData = transactions.map(t => ({
                transaction_date: t.date,
                amount: t.amount,
                description: t.description,
                type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                pix_key: null,
                source: 'gmail' as 'gmail',
                user_id: user.id
            }));
            consolidationService.addTransactions(consolidationData)
                .catch(e => console.warn("Background sync failed", e));
        }

        reconciliation.setBankStatementFile(prev => {
            const current = prev?.processedTransactions || [];
            const newTxs = [...current, ...transactions];
            return {
                bankId: prev?.bankId || 'gmail-import',
                content: prev?.content || '',
                fileName: prev?.fileName || `Gmail Import ${new Date().toLocaleDateString()}`,
                processedTransactions: newTxs,
                rawFile: undefined
            };
        });

        showToast(`${transactions.length} transações importadas do Gmail.`, 'success');

    }, [user, reconciliation, showToast]);

    // --- CONTEXT VALUE ---
    const value = {
        // Reference Data
        banks: referenceData.banks,
        churches: referenceData.churches,
        fileModels: referenceData.fileModels,
        fetchModels: referenceData.fetchModels,
        similarityLevel: referenceData.similarityLevel,
        setSimilarityLevel: referenceData.setSimilarityLevel,
        dayTolerance: referenceData.dayTolerance,
        setDayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: referenceData.customIgnoreKeywords,
        addIgnoreKeyword: referenceData.addIgnoreKeyword,
        removeIgnoreKeyword: referenceData.removeIgnoreKeyword,
        contributionKeywords: referenceData.contributionKeywords,
        addContributionKeyword: referenceData.addContributionKeyword,
        removeContributionKeyword: referenceData.removeContributionKeyword,
        learnedAssociations: referenceData.learnedAssociations,
        learnAssociation: referenceData.learnAssociation,
        effectiveIgnoreKeywords: referenceData.customIgnoreKeywords,

        // Reference Data Actions
        addBank: referenceData.addBank,
        updateBank: referenceData.updateBank,
        openEditBank: referenceData.openEditBank,
        closeEditBank: referenceData.closeEditBank,
        editingBank: referenceData.editingBank,
        addChurch: referenceData.addChurch,
        updateChurch: referenceData.updateChurch,
        openEditChurch: referenceData.openEditChurch,
        closeEditChurch: referenceData.closeEditChurch,
        editingChurch: referenceData.editingChurch,

        // Report Manager
        savedReports: reportManager.savedReports,
        maxSavedReports: reportManager.maxSavedReports,
        searchFilters: reportManager.searchFilters,
        setSearchFilters: reportManager.setSearchFilters,
        isSearchFiltersOpen: reportManager.isSearchFiltersOpen,
        openSearchFilters: reportManager.openSearchFilters,
        closeSearchFilters: reportManager.closeSearchFilters,
        clearSearchFilters: reportManager.clearSearchFilters,
        savingReportState: reportManager.savingReportState,
        openSaveReportModal: reportManager.openSaveReportModal,
        closeSaveReportModal: reportManager.closeSaveReportModal,
        confirmSaveReport: reportManager.confirmSaveReport,
        updateSavedReportName: reportManager.updateSavedReportName,
        updateSavedReportTransaction: reportManager.updateSavedReportTransaction,
        saveFilteredReport: reportManager.saveFilteredReport,
        overwriteSavedReport: reportManager.overwriteSavedReport,
        deleteOldReports: reportManager.deleteOldReports,
        allHistoricalResults: reportManager.allHistoricalResults,
        viewSavedReport: viewSavedReport,

        // Reconciliation
        bankStatementFile: reconciliation.bankStatementFile,
        setBankStatementFile: reconciliation.setBankStatementFile,
        contributorFiles: reconciliation.contributorFiles,
        matchResults: reconciliation.matchResults,
        setMatchResults: reconciliation.setMatchResults,
        reportPreviewData: reconciliation.reportPreviewData,
        setReportPreviewData: reconciliation.setReportPreviewData,
        hasActiveSession: reconciliation.hasActiveSession,
        setHasActiveSession: reconciliation.setHasActiveSession,
        activeReportId: reconciliation.activeReportId,
        setActiveReportId: reconciliation.setActiveReportId,
        pendingTraining: reconciliation.pendingTraining,
        setPendingTraining: reconciliation.setPendingTraining,
        comparisonType: reconciliation.comparisonType,
        setComparisonType: reconciliation.setComparisonType,
        handleStatementUpload: reconciliation.handleStatementUpload,
        handleContributorsUpload: reconciliation.handleContributorsUpload,
        removeBankStatementFile: reconciliation.removeBankStatementFile,
        removeContributorFile: reconciliation.removeContributorFile,
        clearFiles: reconciliation.clearFiles,
        handleCompare: reconciliation.handleCompare,
        updateReportData: reconciliation.updateReportData,
        discardCurrentReport: reconciliation.discardCurrentReport,
        openLabManually: reconciliation.openLabManually,
        handleTrainingSuccess: reconciliation.handleTrainingSuccess,
        resetReconciliation: reconciliation.resetReconciliation,
        manualIdentificationTx: reconciliation.manualIdentificationTx,
        setManualIdentificationTx: reconciliation.setManualIdentificationTx,
        bulkIdentificationTxs: reconciliation.bulkIdentificationTxs,
        closeManualIdentify: reconciliation.closeManualIdentify,
        manualMatchState: reconciliation.manualMatchState,
        openManualMatchModal: reconciliation.openManualMatchModal,
        closeManualMatchModal: reconciliation.closeManualMatchModal,
        confirmManualAssociation: reconciliation.confirmManualAssociation,
        divergenceConfirmation: reconciliation.divergenceConfirmation,
        openDivergenceModal: reconciliation.openDivergenceModal,
        closeDivergenceModal: reconciliation.closeDivergenceModal,
        confirmDivergence: reconciliation.confirmDivergence,
        rejectDivergence: reconciliation.rejectDivergence,
        loadingAiId: reconciliation.loadingAiId,
        handleAnalyze: reconciliation.handleAnalyze,
        aiSuggestion: reconciliation.aiSuggestion,
        openManualIdentify,
        undoIdentification,
        confirmManualIdentification,
        confirmBulkManualIdentification,
        saveCurrentReportChanges,
        handleGmailSyncSuccess,

        // Globals & Modals
        initialDataLoaded,
        isSyncing,
        summary,
        deletingItem,
        openDeleteConfirmation,
        closeDeleteConfirmation,
        confirmDeletion,
        isPaymentModalOpen,
        openPaymentModal,
        closePaymentModal,
        smartEditTarget,
        openSmartEdit,
        closeSmartEdit,
        saveSmartEdit,
        activeSpreadsheetData,
        isUpdateFilesModalOpen,
        openUpdateFilesModal,
        closeUpdateFilesModal,
        isRecompareModalOpen,
        openRecompareModal,
        closeRecompareModal,

        // Misc helpers
        isCompareDisabled: !reconciliation.bankStatementFile && !reconciliation.activeReportId,
        findMatchResult: (id: string) => reconciliation.matchResults.find(r => r.transaction.id === id),
    };

    return (
        <AppContext.Provider value={value}>
            {children}
        </AppContext.Provider>
    );
};

import React, { useContext, useState, useMemo, useEffect, useCallback } from 'react';
import { AppContext } from '../contexts/AppContext';
import { useUI } from '../contexts/UIContext';
import { useTranslation } from '../contexts/I18nContext';
import { EmptyState } from '../components/EmptyState';
import { EditableReportTable } from '../components/reports/EditableReportTable';
import { 
    ChartBarIcon, 
    BuildingOfficeIcon, 
    ExclamationTriangleIcon, 
    BanknotesIcon, 
    FloppyDiskIcon, 
    DocumentDuplicateIcon,
    MagnifyingGlassIcon,
    ChevronLeftIcon,
    ChevronRightIcon,
    PrinterIcon,
    DocumentArrowDownIcon,
    ArrowPathIcon 
} from '../components/Icons';
import { formatCurrency, formatDate } from '../utils/formatters';
import { MatchResult } from '../types';

export const ReportsView: React.FC = () => {
    const { 
        reportPreviewData, 
        activeReportId, 
        saveCurrentReportChanges, 
        openSaveReportModal, 
        matchResults,
        updateReportData,
        loadingAiId,
        openSmartEdit
    } = useContext(AppContext);

    const { setActiveView } = useUI();
    const { t, language } = useTranslation();

    // Categorias Principais
    const [activeCategory, setActiveCategory] = useState<'churches' | 'unidentified' | 'expenses'>('churches');

    // ID do Relatório Específico Selecionado (Ex: ID da Igreja)
    const [selectedReportId, setSelectedReportId] = useState<string | null>(null);

    const [sortConfig, setSortConfig] = useState<{ key: string, direction: 'asc' | 'desc' } | null>(null);
    const [searchTerm, setSearchTerm] = useState('');

    // --- EFEITO: Seleção Inicial Automática ---
    useEffect(() => {
        if (!reportPreviewData) return;

        if (activeCategory === 'churches') {
            const churchIds = Object.keys(reportPreviewData.income).filter(k => k !== 'unidentified').sort();
            if (churchIds.length > 0) {
                // Se o ID selecionado não estiver na lista de igrejas, seleciona o primeiro
                if (!selectedReportId || !churchIds.includes(selectedReportId)) {
                    setSelectedReportId(churchIds[0]);
                }
            } else {
                setSelectedReportId(null);
            }
        } else if (activeCategory === 'unidentified') {
            setSelectedReportId('unidentified');
        } else if (activeCategory === 'expenses') {
            setSelectedReportId('all_expenses_group');
        }
    }, [activeCategory, reportPreviewData]);

    // --- DADOS CALCULADOS ---
    const churchList = useMemo(() => {
        if (!reportPreviewData?.income) return [];
        return Object.entries(reportPreviewData.income)
            .filter(([id]) => id !== 'unidentified')
            .map(([id, results]) => {
                const res = results as MatchResult[];
                return {
                    id,
                    name: res[0]?.church?.name || 'Igreja Desconhecida',
                    count: res.length,
                    total: res.reduce((sum, r) => sum + r.transaction.amount, 0)
                };
            })
            .sort((a, b) => a.name.localeCompare(b.name));
    }, [reportPreviewData]);

    const counts = useMemo(() => {
        const churches = churchList.length;
        const pending = reportPreviewData?.income['unidentified']?.length || 0;
        const expenses = reportPreviewData?.expenses['all_expenses_group']?.length || 0;
        return { churches, pending, expenses };
    }, [churchList, reportPreviewData]);

    // Dados da Tabela Ativa
    const activeData = useMemo(() => {
        if (!reportPreviewData || !selectedReportId) return [];

        let data: MatchResult[] = [];
        if (activeCategory === 'expenses') {
            data = reportPreviewData.expenses[selectedReportId] || [];
        } else {
            data = reportPreviewData.income[selectedReportId] || [];
        }

        // Filtragem local por termo de busca
        if (searchTerm) {
            const lower = searchTerm.toLowerCase();
            data = data.filter(r => 
                (r.transaction.description || '').toLowerCase().includes(lower) ||
                (r.contributor?.name || '').toLowerCase().includes(lower) ||
                (r.contributor?.cleanedName || '').toLowerCase().includes(lower)
            );
        }

        return data;
    }, [reportPreviewData, selectedReportId, activeCategory, searchTerm]);

    const activeReportType = activeCategory === 'expenses' ? 'expenses' : 'income';

    // Totais do Relatório Ativo
    const activeSummary = useMemo(() => {
        const count = activeData.length;
        const total = activeData.reduce((sum, r) => sum + r.transaction.amount, 0);

        // Filtros
        const pendingTxs = activeData.filter(r => r.status === 'PENDENTE');
        const autoTxs = activeData.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod !== 'MANUAL');
        const manualTxs = activeData.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod === 'MANUAL');

        // Contagens e Valores
        const pending = pendingTxs.length;
        const pendingValue = pendingTxs.reduce((sum, r) => sum + (r.contributorAmount || 0), 0);

        const auto = autoTxs.length;
        const autoValue = autoTxs.reduce((sum, r) => sum + r.transaction.amount, 0);

        const manual = manualTxs.length;
        const manualValue = manualTxs.reduce((sum, r) => sum + r.transaction.amount, 0);

        return { 
            count, total, 
            pending, pendingValue, 
            auto, autoValue, 
            manual, manualValue 
        };
    }, [activeData]);

    const handleSort = (key: string) => {
        setSortConfig(current => ({
            key,
            direction: current?.key === key && current.direction === 'asc' ? 'desc' : 'asc'
        }));
    };

    const sortedData = useMemo(() => {
        if (!sortConfig) return activeData;
        return [...activeData].sort((a, b) => {
            let valA: any;
            let valB: any;

            if (sortConfig.key.includes('.')) {
                const parts = sortConfig.key.split('.');
                valA = parts.reduce((obj: any, k) => obj?.[k], a);
                valB = parts.reduce((obj: any, k) => obj?.[k], b);
            } else {
                valA = (a as any)[sortConfig.key];
                valB = (b as any)[sortConfig.key];
            }

            if (valA === undefined || valA === null) valA = '';
            if (valB === undefined || valB === null) valB = '';

            if (typeof valA === 'string') {
                valA = valA.toLowerCase();
                valB = valB.toLowerCase();
            }

            if (valA < valB) return sortConfig.direction === 'asc' ? -1 : 1;
            if (valA > valB) return sortConfig.direction === 'asc' ? 1 : -1;
            return 0;
        });
    }, [activeData, sortConfig]);

    const handleSaveReport = () => {
        const resultsToSave = matchResults;
        openSaveReportModal({
            type: 'global',
            results: resultsToSave,
            groupName: 'Geral'
        });
    };

    const handleDownload = () => {
        const headers = ["Data", "Descrição", "Tipo", "Status", "Valor"];
        const csvContent = [
            headers.join(";"),
            ...sortedData.map(r => {
                const date = formatDate(r.transaction.date);
                const desc = (r.contributor?.cleanedName || r.transaction.description).replace(/;/g, ' ');
                const type = (r.contributor?.contributionType || r.transaction.contributionType || "").replace(/;/g, ' ');
                const status = r.status === 'IDENTIFICADO' ? (r.matchMethod || 'AUTO') : r.status;
                // Formata para padrão brasileiro no CSV (vírgula decimal)
                const amount = (r.status === 'PENDENTE' ? (r.contributorAmount || 0) : r.transaction.amount)
                    .toFixed(2).replace('.', ',');

                return [`"${date}"`, `"${desc}"`, `"${type}"`, `"${status}"`, `"${amount}"`].join(";");
            })
        ].join("\n");

        const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
        const url = URL.createObjectURL(blob);
        const link = document.createElement("a");
        link.setAttribute("href", url);
        link.setAttribute("download", `relatorio_${new Date().toISOString().slice(0,10)}.csv`);
        document.body.appendChild(link);
        link.click();
        document.body.removeChild(link);
    };

