export const AppContext = createContext<any>(null!);

// Provider Component
export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user } = useAuth();
    const { showToast, setIsLoading, setActiveView } = useUI();

    // --- 1. Reference Data Hook ---
    const referenceData = useReferenceData(user, showToast);

    // --- 2. Report Manager Hook ---
    const reportManager = useReportManager(user, showToast);

    // --- 3. Reconciliation Hook ---
    const reconciliation = useReconciliation({
        user,
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: referenceData.fileModels,
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: referenceData.customIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast,
        setIsLoading,
        setActiveView
    });

    // --- 4. Global UI State & Modals ---
    const [initialDataLoaded, setInitialDataLoaded] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);

    // Delete Modal
    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);

    // Payment Modal
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const openPaymentModal = useCallback(() => setIsPaymentModalOpen(true), []);
    const closePaymentModal = useCallback(() => setIsPaymentModalOpen(false), []);

    // Smart Edit Modal
    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);
    const openSmartEdit = useCallback((target: MatchResult) => setSmartEditTarget(target), []);
    const closeSmartEdit = useCallback(() => setSmartEditTarget(null), []);

    // Recompare Modal
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);
    const openRecompareModal = useCallback(() => setIsRecompareModalOpen(true), []);
    const closeRecompareModal = useCallback(() => setIsRecompareModalOpen(false), []);

    // Active Spreadsheet (Derived)
    const activeSpreadsheetData = useMemo(() => {
        if (reconciliation.activeReportId) {
            const report = reportManager.savedReports.find(r => r.id === reconciliation.activeReportId);
            return report?.data?.spreadsheet;
        }
        return null;
    }, [reconciliation.activeReportId, reportManager.savedReports]);

    // Summary Statistics
    const summary = useMemo(() => {
        const results = reconciliation.matchResults;
        const totalValue = results.reduce((acc, r) => acc + Math.abs(r.transaction.amount), 0);
        const identified = results.filter(r => r.status === 'IDENTIFICADO');
        const unidentified = results.filter(r => r.status === 'NÃO IDENTIFICADO');
        const pending = results.filter(r => r.status === 'PENDENTE');

        const valuePerChurch = Object.entries(groupResultsByChurch(results))
            .filter(([id]) => id !== 'unidentified' && id !== 'placeholder')
            .map(([id, items]) => {
                const churchName = items[0]?.church?.name || 'Desconhecida';
                const total = items.reduce((sum, item) => sum + item.transaction.amount, 0);
                return [churchName, total] as [string, number];
            })
            .sort((a, b) => b[1] - a[1])
            .slice(0, 5);

        // Method Breakdown
        const methodBreakdown = {
            'AUTOMATIC': identified.filter(r => r.matchMethod === 'AUTOMATIC').length,
            'MANUAL': identified.filter(r => r.matchMethod === 'MANUAL').length,
            'LEARNED': identified.filter(r => r.matchMethod === 'LEARNED').length,
            'AI': identified.filter(r => r.matchMethod === 'AI').length,
        };

        return {
            totalValue,
            identifiedCount: identified.length,
            unidentifiedCount: unidentified.length + pending.length,
            autoConfirmed: { value: identified.reduce((acc, r) => acc + r.transaction.amount, 0) }, 
            manualConfirmed: { value: 0 }, 
            pending: { value: unidentified.reduce((acc, r) => acc + Math.abs(r.transaction.amount), 0) + pending.reduce((acc,r) => acc + (r.contributorAmount || 0), 0) },
            valuePerChurch,
            methodBreakdown,
            isHistorical: !!reconciliation.activeReportId
        };
    }, [reconciliation.matchResults, reconciliation.activeReportId]);

    // --- HYDRATION ---
    useEffect(() => {
        if (!user) {
            setInitialDataLoaded(true);
            return;
        }

        const fetchData = async () => {
            setIsSyncing(true);

            // 1. Carregar Igrejas
            try {
                const { data, error } = await supabase.from('churches').select('*').order('name');
                if (error) throw error;
                if (data) referenceData.setChurches(data as any);
            } catch (e) {
                console.warn("[Hydration] Falha ao carregar Igrejas:", e);
            }

            // 2. Carregar Bancos
            try {
                const { data, error } = await supabase.from('banks').select('*').order('name');
                if (error) throw error;
                if (data) referenceData.setBanks(data as any);
            } catch (e) {
                console.warn("[Hydration] Falha ao carregar Bancos:", e);
            }

            // 3. Carregar Relatórios Salvos
            try {
                const { data, error } = await supabase.from('saved_reports')
                    .select('id, name, created_at, record_count, user_id') 
                    .eq('user_id', user.id)
                    .order('created_at', { ascending: false });

                if (error) throw error;

                if (data) {
                    reportManager.setSavedReports((data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null 
                    })));
                }
            } catch (e) {
                console.warn("[Hydration] Falha ao carregar Relatórios:", e);
            }

            // 4. Carregar Lista Viva (Transações Pendentes)
            try {
                const pendingTxs = await consolidationService.getPendingTransactions(user.id);

                if (pendingTxs && pendingTxs.length > 0) {
                    const liveTransactions = pendingTxs.map(dbTx => ({
                        id: dbTx.id,
                        date: dbTx.transaction_date,
                        amount: dbTx.amount,
                        description: dbTx.description,
                        cleanedDescription: dbTx.description, 
                        contributionType: dbTx.type,
                        originalAmount: String(dbTx.amount)
                    }));

                    const virtualContent = liveTransactions
                        .map(t => `${t.date};${t.description};${t.amount};${t.contributionType}`)
                        .join('\n');

                    const targetBankId = referenceData.banks.length > 0 ? referenceData.banks[0].id : 'active-session-bank';

                    reconciliation.setBankStatementFile({
                        bankId: targetBankId,
                        content: virtualContent,
                        fileName: 'Sessão Ativa (Nuvem)',
                        processedTransactions: liveTransactions as Transaction[],
                        rawFile: undefined 
                    });

                    if (reconciliation.matchResults.length === 0) {
                        const mappedResults: MatchResult[] = liveTransactions.map(tx => ({
                            transaction: tx as Transaction,
                            contributor: null,
                            status: 'NÃO IDENTIFICADO',
                            church: PLACEHOLDER_CHURCH,
                            matchMethod: undefined,
                            similarity: 0
                        }));

                        reconciliation.setMatchResults(mappedResults);
                        reconciliation.setReportPreviewData({
                            income: groupResultsByChurch(mappedResults),
                            expenses: { 'all_expenses_group': [] }
                        });

                        reconciliation.setHasActiveSession(true);
                    }
                }
            } catch (dbError) {
                console.warn("[Hydration] Falha ao carregar Lista Viva:", dbError);
            }

            setIsSyncing(false); 
            setInitialDataLoaded(true);
        };

        fetchData();
    }, [user?.id]);

    // --- ACTIONS IMPLEMENTATIONS ---

    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;

        setIsLoading(true);
        try {
            switch (deletingItem.type) {
                case 'bank':
                    const { error: bankError } = await supabase.from('banks').delete().eq('id', deletingItem.id);
                    if (bankError) throw bankError;
                    referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
                    showToast('Banco removido.', 'success');
                    break;

                case 'church':
                    const { error: churchError } = await supabase.from('churches').delete().eq('id', deletingItem.id);
                    if (churchError) throw churchError;
                    referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
                    showToast('Igreja removida.', 'success');
                    break;

                case 'report-saved':
                    const { error: repError } = await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
                    if (repError) throw repError;
                    reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
                    showToast('Relatório excluído.', 'success');
                    break;

                case 'report-row':
                    reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
                    const reportType = deletingItem.meta?.reportType || 'income';
                    reconciliation.setReportPreviewData(prev => {
                        if(!prev) return null;
                        const newPrev = {...prev};
                        const targetGroup = reportType === 'expenses' ? newPrev.expenses : newPrev.income;
                        Object.keys(targetGroup).forEach(k => {
                            targetGroup[k] = targetGroup[k].filter((r: MatchResult) => r.transaction.id !== deletingItem.id);
                        });
                        return newPrev;
                    });
                    showToast('Linha removida.', 'success');
                    break;

                case 'uploaded-files':
                    reconciliation.removeBankStatementFile();
                    reconciliation.setContributorFiles([]);
                    showToast('Arquivos limpos.', 'success');
                    break;

                case 'match-results':
                    reconciliation.setMatchResults([]);
                    reconciliation.setReportPreviewData(null);
                    reconciliation.setHasActiveSession(false);
                    reconciliation.setActiveReportId(null);
                    showToast('Resultados limpos.', 'success');
                    break;

                case 'learned-associations':
                    const { error: laError } = await supabase.from('learned_associations').delete().eq('user_id', user!.id);
                    if (laError) throw laError;
                    referenceData.setLearnedAssociations([]);
                    showToast('Associações aprendidas removidas.', 'success');
                    break;

                case 'all-data':
                    if (user) {
                        await supabase.from('banks').delete().eq('user_id', user.id);
                        await supabase.from('churches').delete().eq('user_id', user.id);
                        await supabase.from('learned_associations').delete().eq('user_id', user.id);
                    }
                    referenceData.setBanks([]);
                    referenceData.setChurches([]);
                    referenceData.setLearnedAssociations([]);
                    reconciliation.resetReconciliation();
                    showToast('Reset completo realizado.', 'success');
                    break;
            }
        } catch (e: any) {
            console.error(e);
            showToast('Erro ao excluir: ' + e.message, 'error');
        } finally {
            setIsLoading(false);
            closeDeleteConfirmation();
        }
    }, [deletingItem, user, referenceData, reportManager, reconciliation, showToast, setIsLoading, closeDeleteConfirmation]);

    const saveSmartEdit = useCallback((updatedResult: MatchResult) => {
        reconciliation.updateReportData(updatedResult, 'income');
        if (smartEditTarget?.status === 'NÃO IDENTIFICADO' && updatedResult.status === 'IDENTIFICADO') {
            referenceData.learnAssociation(updatedResult);
        }
        closeSmartEdit();
        showToast('Identificação aplicada.', 'success');
    }, [smartEditTarget, reconciliation, referenceData, closeSmartEdit, showToast]);

    const confirmManualIdentification = useCallback((txId: string, churchId: string) => {
        const tx = reconciliation.matchResults.find(r => r.transaction.id === txId)?.transaction;
        if (!tx) return;

        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        const contributor: Contributor = {
            id: `manual-${txId}`,
            name: tx.cleanedDescription || tx.description,
            amount: tx.amount,
            date: tx.date,
            contributionType: tx.contributionType
        };

        const result: MatchResult = {
            transaction: tx,
            contributor,
            church,
            status: 'IDENTIFICADO',
            matchMethod: 'MANUAL',
            similarity: 100,
            contributorAmount: tx.amount
        };

        reconciliation.updateReportData(result, 'income');
        referenceData.learnAssociation(result);

        reconciliation.setManualIdentificationTx(null);
        reconciliation.setBulkIdentificationTxs(null);
        showToast('Identificado manualmente.', 'success');
    }, [reconciliation, referenceData, showToast]);

    const confirmBulkManualIdentification = useCallback((txIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        txIds.forEach(id => {
            const tx = reconciliation.matchResults.find(r => r.transaction.id === id)?.transaction;
            if (tx) {
                const contributor: Contributor = {
                    id: `manual-${id}`,
                    name: tx.cleanedDescription || tx.description,
                    amount: tx.amount,
                    date: tx.date,
                    contributionType: tx.contributionType
                };
                const result: MatchResult = {
                    transaction: tx,
                    contributor,
                    church,
                    status: 'IDENTIFICADO',
                    matchMethod: 'MANUAL',
                    similarity: 100,
                    contributorAmount: tx.amount
                };
                reconciliation.updateReportData(result, 'income');
                referenceData.learnAssociation(result);
            }
        });

        reconciliation.setManualIdentificationTx(null);
        reconciliation.setBulkIdentificationTxs(null);
        showToast(`${txIds.length} transações identificadas.`, 'success');
    }, [reconciliation, referenceData, showToast]);

    const openManualIdentify = useCallback((transactionId: string) => {
        const result = reconciliation.matchResults.find(r => r.transaction.id === transactionId);
        if (result) {
            reconciliation.setManualIdentificationTx(result.transaction);
        }
    }, [reconciliation.matchResults, reconciliation.setManualIdentificationTx]);

    const undoIdentification = useCallback((transactionId: string) => {
        const result = reconciliation.matchResults.find(r => r.transaction.id === transactionId);
        if (!result) return;

        const reverted: MatchResult = {
            ...result,
            status: 'NÃO IDENTIFICADO',
            contributor: null,
            church: PLACEHOLDER_CHURCH,
            matchMethod: undefined,
            similarity: 0
        };
        reconciliation.updateReportData(reverted, 'income');
        showToast('Identificação desfeita.', 'success');
    }, [reconciliation, showToast]);

    const saveCurrentReportChanges = useCallback(() => {
        if (reconciliation.activeReportId) {
            reportManager.overwriteSavedReport(reconciliation.activeReportId, reconciliation.matchResults);
        } else {
            showToast("Nenhum relatório ativo para salvar.", "error");
        }
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager, showToast]);

    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            const report = reportManager.savedReports.find(r => r.id === reportId);
            if (!report) throw new Error("Relatório não encontrado.");

            let results: MatchResult[] = [];
            if (!report.data) {
                const { data, error } = await supabase.from('saved_reports').select('data').eq('id', reportId).single();
                if(error) throw error;
                const parsed = typeof data.data === 'string' ? JSON.parse(data.data) : data.data;
                results = parsed.results;
            } else {
                results = report.data.results;
            }

            const hydratedResults = results.map(r => {
                const cId = r.church?.id || (r as any)._churchId;
                const church = referenceData.churches.find(c => c.id === cId) || r.church || PLACEHOLDER_CHURCH;
                return { ...r, church };
            });

            reconciliation.setMatchResults(hydratedResults);
            reconciliation.setReportPreviewData({
                income: groupResultsByChurch(hydratedResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                expenses: { 'all_expenses_group': hydratedResults.filter(r => r.transaction.amount < 0) }
            });
            reconciliation.setActiveReportId(reportId);
            reconciliation.setHasActiveSession(true);

            reconciliation.clearFiles();

            setActiveView('reports');
            showToast(`Relatório "${report.name}" carregado.`, 'success');

        } catch (e: any) {
            console.error(e);
            showToast("Erro ao abrir relatório: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, referenceData.churches, reconciliation, setActiveView, showToast, setIsLoading]);

    const handleGmailSyncSuccess = useCallback((transactions: Transaction[]) => {
        if (transactions.length === 0) return;

        if (user) {
             const consolidationData = transactions.map(t => ({
                transaction_date: t.date,
                amount: t.amount,
                description: t.description,
                type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                pix_key: null,
                source: 'gmail' as 'gmail',
                user_id: user.id
            }));
            consolidationService.addTransactions(consolidationData)
                .catch(e => console.warn("Background sync failed", e));
        }

        reconciliation.setBankStatementFile(prev => {
            const current = prev?.processedTransactions || [];
            const newTxs = [...current, ...transactions];
            return {
                bankId: prev?.bankId || 'gmail-import',
                content: prev?.content || '',
                fileName: prev?.fileName || `Gmail Import ${new Date().toLocaleDateString()}`,
                processedTransactions: newTxs,
                rawFile: undefined
            };
        });

        showToast(`${transactions.length} transações importadas do Gmail.`, 'success');

    }, [user, reconciliation, showToast]);

    // --- CONTEXT VALUE ---
    const value = {
        // Reference Data
        banks: referenceData.banks,
        churches: referenceData.churches,
        fileModels: referenceData.fileModels,
        fetchModels: referenceData.fetchModels,
        similarityLevel: referenceData.similarityLevel,
        setSimilarityLevel: referenceData.setSimilarityLevel,
        dayTolerance: referenceData.dayTolerance,
        setDayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: referenceData.customIgnoreKeywords,
        addIgnoreKeyword: referenceData.addIgnoreKeyword,
        removeIgnoreKeyword: referenceData.removeIgnoreKeyword,
        contributionKeywords: referenceData.contributionKeywords,
        addContributionKeyword: referenceData.addContributionKeyword,
        removeContributionKeyword: referenceData.removeContributionKeyword,
        learnedAssociations: referenceData.learnedAssociations,
        learnAssociation: referenceData.learnAssociation,
        effectiveIgnoreKeywords: referenceData.customIgnoreKeywords,

        // Reference Data Actions
        addBank: referenceData.addBank,
        updateBank: referenceData.updateBank,
        openEditBank: referenceData.openEditBank,
        closeEditBank: referenceData.closeEditBank,
        editingBank: referenceData.editingBank,
        addChurch: referenceData.addChurch,
        updateChurch: referenceData.updateChurch,
        openEditChurch: referenceData.openEditChurch,
        closeEditChurch: referenceData.closeEditChurch,
        editingChurch: referenceData.editingChurch,

        // Report Manager
        savedReports: reportManager.savedReports,
        maxSavedReports: reportManager.maxSavedReports,
        searchFilters: reportManager.searchFilters,
        setSearchFilters: reportManager.setSearchFilters,
        isSearchFiltersOpen: reportManager.isSearchFiltersOpen,
        openSearchFilters: reportManager.openSearchFilters,
        closeSearchFilters: reportManager.closeSearchFilters,
        clearSearchFilters: reportManager.clearSearchFilters,
        savingReportState: reportManager.savingReportState,
        openSaveReportModal: reportManager.openSaveReportModal,
        closeSaveReportModal: reportManager.closeSaveReportModal,
        confirmSaveReport: reportManager.confirmSaveReport,
        updateSavedReportName: reportManager.updateSavedReportName,
        updateSavedReportTransaction: reportManager.updateSavedReportTransaction,
        saveFilteredReport: reportManager.saveFilteredReport,
        overwriteSavedReport: reportManager.overwriteSavedReport,
        deleteOldReports: reportManager.deleteOldReports,
        allHistoricalResults: reportManager.allHistoricalResults,
        viewSavedReport: viewSavedReport,

        // Reconciliation
        bankStatementFile: reconciliation.bankStatementFile,
        setBankStatementFile: reconciliation.setBankStatementFile,
        contributorFiles: reconciliation.contributorFiles,
        matchResults: reconciliation.matchResults,
        setMatchResults: reconciliation.setMatchResults,
        reportPreviewData: reconciliation.reportPreviewData,
        setReportPreviewData: reconciliation.setReportPreviewData,
        hasActiveSession: reconciliation.hasActiveSession,
        setHasActiveSession: reconciliation.setHasActiveSession,
        activeReportId: reconciliation.activeReportId,
        setActiveReportId: reconciliation.setActiveReportId,
        pendingTraining: reconciliation.pendingTraining,
        setPendingTraining: reconciliation.setPendingTraining,
        comparisonType: reconciliation.comparisonType,
        setComparisonType: reconciliation.setComparisonType,
        handleStatementUpload: reconciliation.handleStatementUpload,
        handleContributorsUpload: reconciliation.handleContributorsUpload,
        removeBankStatementFile: reconciliation.removeBankStatementFile,
        removeContributorFile: reconciliation.removeContributorFile,
        clearFiles: reconciliation.clearFiles,
        handleCompare: reconciliation.handleCompare,
        updateReportData: reconciliation.updateReportData,
        discardCurrentReport: reconciliation.discardCurrentReport,
        openLabManually: reconciliation.openLabManually,
        handleTrainingSuccess: reconciliation.handleTrainingSuccess,
        resetReconciliation: reconciliation.resetReconciliation,
        manualIdentificationTx: reconciliation.manualIdentificationTx,
        setManualIdentificationTx: reconciliation.setManualIdentificationTx,
        bulkIdentificationTxs: reconciliation.bulkIdentificationTxs,
        closeManualIdentify: reconciliation.closeManualIdentify,
        manualMatchState: reconciliation.manualMatchState,
        openManualMatchModal: reconciliation.openManualMatchModal,
        closeManualMatchModal: reconciliation.closeManualMatchModal,
        confirmManualAssociation: reconciliation.confirmManualAssociation,
        divergenceConfirmation: reconciliation.divergenceConfirmation,
        openDivergenceModal: reconciliation.openDivergenceModal,
        closeDivergenceModal: reconciliation.closeDivergenceModal,
        confirmDivergence: reconciliation.confirmDivergence,
        rejectDivergence: reconciliation.rejectDivergence,
        loadingAiId: reconciliation.loadingAiId,
        handleAnalyze: reconciliation.handleAnalyze,
        aiSuggestion: reconciliation.aiSuggestion,
        openManualIdentify,
        undoIdentification,
        confirmManualIdentification,
        confirmBulkManualIdentification,
        saveCurrentReportChanges,
        handleGmailSyncSuccess,

        // Globals & Modals
        initialDataLoaded,
        isSyncing,
        summary,
        deletingItem,
        openDeleteConfirmation,
        closeDeleteConfirmation,
        confirmDeletion,
        isPaymentModalOpen,
        openPaymentModal,
        closePaymentModal,
        smartEditTarget,
        openSmartEdit,
        closeSmartEdit,
        saveSmartEdit,
        activeSpreadsheetData,
        isUpdateFilesModalOpen: false, // Stub for removal
        openUpdateFilesModal: () => {}, // Stub for removal
        closeUpdateFilesModal: () => {}, // Stub for removal
        isRecompareModalOpen,
        openRecompareModal,
        closeRecompareModal,

        // Misc helpers
        isCompareDisabled: !reconciliation.bankStatementFile && !reconciliation.activeReportId,
        findMatchResult: (id: string) => reconciliation.matchResults.find(r => r.transaction.id === id),
    };

    return (
        <AppContext.Provider value={value}>
            {children}
        </AppContext.Provider>
    );
};

import { useState, useCallback, useMemo } from 'react';
import { usePersistentState } from './usePersistentState';
import { 
    Transaction, 
    Contributor, 
    MatchResult, 
    Church, 
    Bank, 
    FileModel, 
    GroupedReportData, 
    ComparisonType,
    ViewType,
    LearnedAssociation
} from '../types';
import { 
    matchTransactions, 
    groupResultsByChurch, 
    PLACEHOLDER_CHURCH,
    normalizeString,
    processFileContent
} from '../services/processingService';
import { User } from '@supabase/supabase-js';
import { consolidationService } from '../services/ConsolidationService';

interface UseReconciliationProps {
    user: User | null; // Adicionado User
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: LearnedAssociation[];
    showToast: (msg: string, type?: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: ViewType) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    // Cria um sufixo único baseado no ID do usuário para isolar os dados no LocalStorage/IndexedDB
    const userSuffix = user ? `-${user.id}` : '-guest';

    const [bankStatementFile, setBankStatementFile] = usePersistentState<{ 
        bankId: string, 
        content: string, 
        fileName: string, 
        rawFile?: File,
        processedTransactions?: Transaction[]
    } | null>(`identificapix-statement-v7${userSuffix}`, null, true);

    const [contributorFiles, setContributorFiles] = usePersistentState<{ churchId: string; content: string; fileName: string, contributors?: Contributor[] }[]>(`identificapix-contributors-v6${userSuffix}`, [], true);
    const [matchResults, setMatchResults] = usePersistentState<MatchResult[]>(`identificapix-results-v6${userSuffix}`, [], true);
    const [reportPreviewData, setReportPreviewData] = usePersistentState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(`identificapix-report-preview-v6${userSuffix}`, null, true);
    const [hasActiveSession, setHasActiveSession] = usePersistentState<boolean>(`identificapix-has-session-v6${userSuffix}`, false, false);
    // NOVO: Rastreia se estamos editando um relatório já salvo
    const [activeReportId, setActiveReportId] = usePersistentState<string | null>(`identificapix-active-report-id${userSuffix}`, null, false);

    const [comparisonType, setComparisonType] = useState<ComparisonType>('both');

    const [pendingTraining, setPendingTraining] = useState<{ content: string; fileName: string; type: 'statement' | 'contributor'; entityId: string, rawFile?: File } | null>(null);

    // Manual Identification State
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[] | null>(null);
    const [manualMatchState, setManualMatchState] = useState<{ record: MatchResult, suggestions: Transaction[] } | null>(null);
    const [divergenceConfirmation, setDivergenceConfirmation] = useState<MatchResult | null>(null);
    const [loadingAiId, setLoadingAiId] = useState<string | null>(null);
    const [aiSuggestion, setAiSuggestion] = useState<{ id: string, name: string } | null>(null);

    // --- LÓGICA DE LIMPEZA UNIFICADA ---
    // Combina palavras ignoradas globais com os Tipos de Contribuição.
    // Isso garante que "Dízimo", "Oferta", etc., sejam removidos da coluna NOME,
    // mas a detecção de TIPO (que ocorre no raw description) continua funcionando.
    const cleaningKeywords = useMemo(() => {
        return Array.from(new Set([...customIgnoreKeywords, ...contributionKeywords]));
    }, [customIgnoreKeywords, contributionKeywords]);

    const handleStatementUpload = useCallback((content: string, fileName: string, bankId: string, rawFile: File) => {
        setIsLoading(true);
        try {
            // ESTRATÉGIA DIRETA: Usa a lista combinada para limpar descrições
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            if (transactions.length > 0) {
                setBankStatementFile({ 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile,
                    processedTransactions: transactions 
                });

                if (result.appliedModel) {
                    showToast("Um modelo de arquivo foi identificado automaticamente e aplicado com sucesso.", "success");
                } else {
                    showToast(`Extrato carregado (${result.method}).`, 'success');
                }

                // --- INTEGRATION: Consolidation Service ---
                if (user) {
                    const consolidationData = transactions.map(t => ({
                        transaction_date: t.date,
                        amount: t.amount,
                        description: t.description, // Raw description preferred for audit
                        type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                        pix_key: null, // Basic file upload typically does not parse PIX key separately yet
                        source: 'file' as 'file',
                        user_id: user.id
                    }));

                    // Fire and forget - Silent error handling (Avoid blocking UI if table is missing)
                    consolidationService.addTransactions(consolidationData)
                        .catch(err => console.warn("[Consolidation] Background sync skipped (DB Error/Offline):", err));
                }
                // ------------------------------------------

            } else {
                showToast("Formato de arquivo não reconhecido pelo sistema automático. Verifique se é um arquivo suportado.", "error");
            }
        } catch (e: any) {
            console.error(e);
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [setBankStatementFile, showToast, setIsLoading, fileModels, cleaningKeywords, user]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string, rawFile?: File) => {
        setIsLoading(true);
        try {
            // ESTRATÉGIA DIRETA: Usa a lista combinada para limpar nomes de contribuintes
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            const contributors: Contributor[] = transactions.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            if (contributors.length > 0) {
                setContributorFiles(prev => {
                    const other = prev.filter(f => f.churchId !== churchId);
                    return [...other, { churchId, content, fileName, contributors }];
                });

                if (result.appliedModel) {
                    showToast("Um modelo de arquivo foi identificado automaticamente e aplicado com sucesso.", "success");
                } else {
                    showToast(`Lista carregada (${result.method}).`, 'success');
                }
            } else {
                showToast("Formato de lista não reconhecido. Use CSV ou Excel padronizado.", "error");
            }
        } catch (e: any) {
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [cleaningKeywords, setContributorFiles, showToast, setIsLoading, fileModels]);

    const handleTrainingSuccess = useCallback((model: FileModel, processedData: Transaction[]) => {
        if (!pendingTraining) return;

        const { type, entityId, content, fileName, rawFile } = pendingTraining;

        if (type === 'statement') {
            setBankStatementFile({ 
                bankId: entityId, 
                content, 
                fileName, 
                rawFile,
                processedTransactions: processedData 
            });
            showToast("Extrato processado e salvo!", "success");

            // --- INTEGRATION: Consolidation Service (Training Flow) ---
            if (user && processedData.length > 0) {
                const consolidationData = processedData.map(t => ({
                    transaction_date: t.date,
                    amount: t.amount,
                    description: t.description,
                    type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                    pix_key: null,
                    source: 'file' as 'file',
                    user_id: user.id
                }));
                consolidationService.addTransactions(consolidationData)
                    .catch(err => console.warn("[Consolidation] Background sync skipped:", err));
            }
            // ---------------------------------------------------------

        } else {
            const contributors: Contributor[] = processedData.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            setContributorFiles(prev => {
                const other = prev.filter(f => f.churchId !== entityId);
                return [...other, { churchId: entityId, content, fileName, contributors }];
            });
            showToast("Lista de contribuintes salva!", "success");
        }

        setPendingTraining(null);
    }, [pendingTraining, cleaningKeywords, setBankStatementFile, setContributorFiles, showToast, user]);

    const openLabManually = useCallback((targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => {
        if (targetFile) {
            setPendingTraining({
                content: targetFile.content,
                fileName: targetFile.fileName,
                type: targetFile.type,
                entityId: targetFile.id,
                rawFile: targetFile.rawFile
            });
        } else if (bankStatementFile) {
            setPendingTraining({
                content: bankStatementFile.content,
                fileName: bankStatementFile.fileName,
                type: 'statement',
                entityId: bankStatementFile.bankId,
                rawFile: bankStatementFile.rawFile
            });
        } else {
            showToast("Carregue um arquivo primeiro.", "error");
        }
    }, [bankStatementFile, showToast]);

    const removeBankStatementFile = useCallback(() => setBankStatementFile(null), [setBankStatementFile]);
    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, [setContributorFiles]);

    // Limpa apenas os arquivos (usado ao abrir um relatório salvo para evitar estado sujo)
    const clearFiles = useCallback(() => {
        setBankStatementFile(null);
        setContributorFiles([]);
    }, [setBankStatementFile, setContributorFiles]);

    // Função para limpar tudo e iniciar nova conciliação
    const resetReconciliation = useCallback(() => {
        setBankStatementFile(null);
        setContributorFiles([]);
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null); // Limpa o ID do relatório ativo
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
        setManualMatchState(null);
        setDivergenceConfirmation(null);
        setAiSuggestion(null);
        showToast("Ambiente limpo para nova conciliação.", "success");
    }, [setBankStatementFile, setContributorFiles, setMatchResults, setReportPreviewData, setHasActiveSession, showToast, setActiveReportId]);

    // --- RECONCILIATION ENGINE JIT (Just-In-Time) ---
    const handleCompare = useCallback(async () => {
        if (!bankStatementFile && !activeReportId) return; // Bloqueio padrão

        setIsLoading(true);

        try {
            let activeTransactions: Transaction[] = [];

            // 1. OBTENÇÃO DAS TRANSAÇÕES (Prioridade: Arquivo > Banco > Relatório)
            // Se houver arquivo carregado (Lista Viva), ele é a fonte da verdade para atualização
            if (bankStatementFile) {
                // Se já temos transações processadas no arquivo, usa elas
                if (bankStatementFile.processedTransactions && bankStatementFile.processedTransactions.length > 0) {
                    activeTransactions = bankStatementFile.processedTransactions;
                } else {
                    // Fallback para reprocessamento se necessário (raro)
                    const stmtResult = processFileContent(bankStatementFile.content, bankStatementFile.fileName, fileModels, cleaningKeywords);
                    activeTransactions = stmtResult.transactions;
                }
            } 
            // Se não tem arquivo mas está editando, tenta buscar do banco para garantir que temos "o que falta"
            else if (activeReportId && user) {
                try {
                    const dbTransactions = await consolidationService.getPendingTransactions(user.id);
                    activeTransactions = dbTransactions.map(dbTx => ({
                        id: dbTx.id,
                        date: dbTx.transaction_date,
                        amount: dbTx.amount,
                        description: dbTx.description,
                        cleanedDescription: dbTx.description,
                        contributionType: dbTx.type,
                        originalAmount: String(dbTx.amount)
                    }));
                } catch(e) {
                    // Fallback para o que está no matchResults não identificado se DB falhar
                    activeTransactions = matchResults
                        .filter(r => r.status === 'NÃO IDENTIFICADO')
                        .map(r => r.transaction);
                }
            }
            // Modo Offline/Visitante sem arquivo novo (usa o que tem no relatório)
            else if (activeReportId) {
                activeTransactions = matchResults
                    .filter(r => r.status === 'NÃO IDENTIFICADO')
                    .map(r => r.transaction);
            }

            if (activeTransactions.length === 0) {
                showToast("Não há transações pendentes para processar.", "error");
                return;
            }

            // Filtro por tipo (Entrada/Saída)
            let filteredTransactions = activeTransactions;
            if (comparisonType === 'income') filteredTransactions = activeTransactions.filter(t => t.amount > 0);
            else if (comparisonType === 'expenses') filteredTransactions = activeTransactions.filter(t => t.amount < 0);

            // 2. PROCESSAMENTO DAS LISTAS DE CONTRIBUINTES
            const contributorData = contributorFiles.map(cf => {
                const church = churches.find(c => c.id === cf.churchId) || PLACEHOLDER_CHURCH;
                // Otimização: Se já tiver contributors processados, não reprocessa
                if (cf.contributors && cf.contributors.length > 0) {
                    return { church, contributors: cf.contributors };
                }

                const listResult = processFileContent(cf.content, cf.fileName, fileModels, cleaningKeywords);
                const currentContributors = listResult.transactions.map(t => ({
                    name: t.description,
                    cleanedName: t.cleanedDescription,
                    normalizedName: normalizeString(t.description, cleaningKeywords),
                    amount: t.amount,
                    date: t.date,
                    originalAmount: t.originalAmount,
                    contributionType: t.contributionType
                }));

                return { church, contributors: currentContributors };
            });

            // 3. EXECUTAR O MATCHING (Novo Conjunto)
            const newResults = matchTransactions(
                filteredTransactions, 
                contributorData, 
                { similarityThreshold: similarityLevel, dayTolerance }, 
                learnedAssociations, 
                churches, 
                cleaningKeywords
            );

            // 4. ATUALIZAÇÃO DE ESTADO (MERGE vs OVERWRITE)
            if (activeReportId) {
                // MODO MERGE (Atualização de Relatório)
                setMatchResults(prevResults => {
                    const finalResults = [...prevResults];

                    newResults.forEach(newRes => {
                        // Tenta encontrar se essa transação já existe no relatório
                        const index = finalResults.findIndex(r => r.transaction.id === newRes.transaction.id);

                        if (index !== -1) {
                            const existing = finalResults[index];

                            // Regra de Merge:
                            // 1. Se o existente já foi identificado Manualmente, MANTER (não sobrescrever com auto)
                            if (existing.matchMethod === 'MANUAL' || existing.matchMethod === 'AI') {
                                return;
                            }

                            // 2. Se o novo achou um match e o antigo não tinha, ATUALIZAR
                            if (newRes.status === 'IDENTIFICADO' && existing.status !== 'IDENTIFICADO') {
                                finalResults[index] = newRes;
                            }
                            // 3. Se o novo tem sugestão melhor, ATUALIZAR
                            else if (newRes.suggestion && !existing.suggestion) {
                                finalResults[index] = newRes;
                            }
                        } else {
                            // Se não existe (transação nova da Lista Viva), ADICIONAR
                            finalResults.push(newRes);
                        }
                    });

                    setReportPreviewData({
                        income: groupResultsByChurch(finalResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                        expenses: { 'all_expenses_group': finalResults.filter(r => r.transaction.amount < 0) }
                    });
                    return finalResults;
                });
                showToast("Relatório atualizado com novos dados da Lista Viva!", 'success');
            } else {
                // MODO OVERWRITE (Novo Relatório)
                setMatchResults(newResults);
                setReportPreviewData({
                    income: groupResultsByChurch(newResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': newResults.filter(r => r.transaction.amount < 0) }
                });
                showToast("Conciliação finalizada!", 'success');
            }

            // 5. PERSISTÊNCIA DE MATCHES AUTOMÁTICOS
            if (user) {
                const autoMatches = newResults.filter(r => r.status === 'IDENTIFICADO' && r.transaction.id && !r.transaction.id.startsWith('ghost-'));
                if (autoMatches.length > 0) {
                    const updatePromises = autoMatches.map(m => 
                        consolidationService.markAsIdentified(m.transaction.id)
                            .catch(e => console.warn(`Falha ao persistir match automático ${m.transaction.id}`, e))
                    );
                    Promise.all(updatePromises).then(() => console.log(`[Consolidation] ${autoMatches.length} matches automáticos persistidos.`));
                }
            }

            setHasActiveSession(true);
            setActiveView('reports');

        } catch (e: any) {
            console.error(e);
            showToast(e.message || "Erro ao processar dados.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [bankStatementFile, activeReportId, contributorFiles, churches, similarityLevel, dayTolerance, cleaningKeywords, learnedAssociations, setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, showToast, setIsLoading, comparisonType, setBankStatementFile, fileModels, matchResults, user]);

    const updateReportData = useCallback((updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => {
        // 1. Atualiza lista plana (MatchResults)
        setMatchResults(prev => {
            let next = prev;
            // Se tiver ID para remover (Transação Fantasma Pendente), remove antes
            if (idToRemove) {
                next = next.filter(r => r.transaction.id !== idToRemove);
            }
            return next.map(r => r.transaction.id === updatedRow.transaction.id ? updatedRow : r);
        });

        // 2. Atualiza dados agrupados (ReportPreview)
        setReportPreviewData(prev => {
            if (!prev) return null;
            const newPreview = JSON.parse(JSON.stringify(prev));
            const targetGroup = reportType === 'expenses' ? newPreview.expenses : newPreview.income;

            if (reportType === 'income') {
                // LÓGICA DE ENTRADAS (Income)
                // Remove o item de qualquer grupo onde ele esteja (tanto o ID real quanto o ID fantasma)
                // Isso evita duplicação ao mover de 'unidentified' ou 'pendente' para uma igreja específica
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].filter((r: MatchResult) => {
                        const isTarget = r.transaction.id === updatedRow.transaction.id;
                        const isGhost = idToRemove && r.transaction.id === idToRemove;
                        return !isTarget && !isGhost;
                    });
                });

                // Adiciona o item atualizado ao grupo correto
                const currentChurchId = updatedRow.church.id || 'unidentified';
                if (!newPreview.income[currentChurchId]) newPreview.income[currentChurchId] = [];
                newPreview.income[currentChurchId].push(updatedRow);

            } else {
                // LÓGICA DE SAÍDAS (Expenses) - Mantém comportamento padrão de atualização in-place
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].map((r: MatchResult) => 
                        r.transaction.id === updatedRow.transaction.id ? updatedRow : r
                    );
                });
            }

            return newPreview;
        });
    }, [setMatchResults, setReportPreviewData]);

    const discardCurrentReport = useCallback(() => {
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null);
        setActiveView('upload');
    }, [setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, setActiveReportId]);

    const closeManualIdentify = useCallback(() => {
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
    }, []);

    const openManualMatchModal = useCallback((record: MatchResult) => {
        const suggestions = matchResults.map(r => r.transaction); 
        setManualMatchState({ record, suggestions });
    }, [matchResults]);

    const closeManualMatchModal = useCallback(() => setManualMatchState(null), []);

    const confirmManualAssociation = useCallback((selectedTx: Transaction) => {
        if (!manualMatchState) return;
        const { record } = manualMatchState;

        // Se o registro original era PENDENTE, significa que era uma transação fantasma da lista.
        // Precisamos capturar esse ID para removê-lo, pois ele será substituído pela transação real do banco.
        const ghostIdToRemove = record.status === 'PENDENTE' ? record.transaction.id : undefined;

        const updatedResult: MatchResult = {
            ...record,
            transaction: selectedTx,
            status: 'IDENTIFICADO',
            matchMethod: 'MANUAL',
            similarity: 100
        };

        updateReportData(updatedResult, 'income', ghostIdToRemove);
        closeManualMatchModal();
        showToast("Associação manual aplicada.", "success");
    }, [manualMatchState, updateReportData, closeManualMatchModal, showToast]);

    const openDivergenceModal = useCallback((match: MatchResult) => setDivergenceConfirmation(match), []);
    const closeDivergenceModal = useCallback(() => setDivergenceConfirmation(null), []);

    const confirmDivergence = useCallback((divergentMatch: MatchResult) => {
        updateReportData({ ...divergentMatch, status: 'IDENTIFICADO' }, 'income');
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const rejectDivergence = useCallback((divergentMatch: MatchResult) => {
        if (divergentMatch.divergence?.expectedChurch) {
             const restored: MatchResult = {
                 ...divergentMatch,
                 church: divergentMatch.divergence.expectedChurch,
                 status: 'IDENTIFICADO'
             };
             updateReportData(restored, 'income');
        } else {
             updateReportData({ ...divergentMatch, status: 'NÃO IDENTIFICADO', church: PLACEHOLDER_CHURCH, contributor: null }, 'income');
        }
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const handleAnalyze = useCallback(async (transactionId: string) => {
        setLoadingAiId(transactionId);
        setTimeout(() => {
            setAiSuggestion({ id: transactionId, name: "Sugestão AI Simulada" });
            setLoadingAiId(null);
        }, 1500);
    }, []);

    return useMemo(() => ({
        bankStatementFile, contributorFiles, matchResults, setMatchResults, reportPreviewData, setReportPreviewData, hasActiveSession, setHasActiveSession,
        activeReportId, setActiveReportId, // EXPORTED
        pendingTraining, setPendingTraining, comparisonType, setComparisonType,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, clearFiles, // EXPORTED
        handleCompare, updateReportData, discardCurrentReport, openLabManually,
        handleTrainingSuccess, resetReconciliation,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        closeManualIdentify,
        manualMatchState, setManualMatchState,
        openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, setDivergenceConfirmation,
        openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, setLoadingAiId, aiSuggestion, setAiSuggestion, handleAnalyze,
        setBankStatementFile // EXPORTED
    }), [
        bankStatementFile, contributorFiles, matchResults, reportPreviewData, hasActiveSession, activeReportId, pendingTraining, comparisonType, 
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, clearFiles, handleCompare, updateReportData, discardCurrentReport, openLabManually, handleTrainingSuccess,
        setMatchResults, setReportPreviewData, setHasActiveSession, setActiveReportId, resetReconciliation,
        manualIdentificationTx, bulkIdentificationTxs, closeManualIdentify,
        manualMatchState, openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, aiSuggestion, handleAnalyze, setBankStatementFile
    ]);
};

// ... (imports) ...

    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            const report = reportManager.savedReports.find(r => r.id === reportId);
            if (!report) throw new Error("Relatório não encontrado.");

            let results: MatchResult[] = [];
            if (!report.data) {
                const { data, error } = await supabase.from('saved_reports').select('data').eq('id', reportId).single();
                if(error) throw error;
                const parsed = typeof data.data === 'string' ? JSON.parse(data.data) : data.data;
                results = parsed.results;
            } else {
                results = report.data.results;
            }

            const hydratedResults = results.map(r => {
                const cId = r.church?.id || (r as any)._churchId;
                const church = referenceData.churches.find(c => c.id === cId) || r.church || PLACEHOLDER_CHURCH;
                return { ...r, church };
            });

            reconciliation.setMatchResults(hydratedResults);
            reconciliation.setReportPreviewData({
                income: groupResultsByChurch(hydratedResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                expenses: { 'all_expenses_group': hydratedResults.filter(r => r.transaction.amount < 0) }
            });
            reconciliation.setActiveReportId(reportId);
            reconciliation.setHasActiveSession(true);

            // REMOVIDO: reconciliation.clearFiles(); 
            // Motivo: Permitir que a "Lista Viva" (bankStatementFile) persista para updates/merges.

            setActiveView('reports');
            showToast(`Relatório "${report.name}" carregado.`, 'success');

        } catch (e: any) {
            console.error(e);
            showToast("Erro ao abrir relatório: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, referenceData.churches, reconciliation, setActiveView, showToast, setIsLoading]);

// ... (rest of the file) ...

import { useState, useCallback, useMemo } from 'react';
import { usePersistentState } from './usePersistentState';
import { 
    Transaction, 
    Contributor, 
    MatchResult, 
    Church, 
    Bank, 
    FileModel, 
    GroupedReportData, 
    ComparisonType,
    ViewType,
    LearnedAssociation
} from '../types';
import { 
    matchTransactions, 
    groupResultsByChurch, 
    PLACEHOLDER_CHURCH,
    normalizeString,
    processFileContent
} from '../services/processingService';
import { User } from '@supabase/supabase-js';
import { consolidationService } from '../services/ConsolidationService';

interface UseReconciliationProps {
    user: User | null; // Adicionado User
    churches: Church[];
    banks: Bank[];
    fileModels: FileModel[];
    similarityLevel: number;
    dayTolerance: number;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    learnedAssociations: LearnedAssociation[];
    showToast: (msg: string, type?: 'success' | 'error') => void;
    setIsLoading: (loading: boolean) => void;
    setActiveView: (view: ViewType) => void;
}

export const useReconciliation = ({
    user,
    churches,
    banks,
    fileModels,
    similarityLevel,
    dayTolerance,
    customIgnoreKeywords,
    contributionKeywords,
    learnedAssociations,
    showToast,
    setIsLoading,
    setActiveView
}: UseReconciliationProps) => {

    // Cria um sufixo único baseado no ID do usuário para isolar os dados no LocalStorage/IndexedDB
    const userSuffix = user ? `-${user.id}` : '-guest';

    const [bankStatementFile, setBankStatementFile] = usePersistentState<{ 
        bankId: string, 
        content: string, 
        fileName: string, 
        rawFile?: File,
        processedTransactions?: Transaction[]
    } | null>(`identificapix-statement-v7${userSuffix}`, null, true);

    const [contributorFiles, setContributorFiles] = usePersistentState<{ churchId: string; content: string; fileName: string, contributors?: Contributor[] }[]>(`identificapix-contributors-v6${userSuffix}`, [], true);
    const [matchResults, setMatchResults] = usePersistentState<MatchResult[]>(`identificapix-results-v6${userSuffix}`, [], true);
    const [reportPreviewData, setReportPreviewData] = usePersistentState<{ income: GroupedReportData; expenses: GroupedReportData } | null>(`identificapix-report-preview-v6${userSuffix}`, null, true);
    const [hasActiveSession, setHasActiveSession] = usePersistentState<boolean>(`identificapix-has-session-v6${userSuffix}`, false, false);
    // NOVO: Rastreia se estamos editando um relatório já salvo
    const [activeReportId, setActiveReportId] = usePersistentState<string | null>(`identificapix-active-report-id${userSuffix}`, null, false);

    const [comparisonType, setComparisonType] = useState<ComparisonType>('both');

    const [pendingTraining, setPendingTraining] = useState<{ content: string; fileName: string; type: 'statement' | 'contributor'; entityId: string, rawFile?: File } | null>(null);

    // Manual Identification State
    const [manualIdentificationTx, setManualIdentificationTx] = useState<Transaction | null>(null);
    const [bulkIdentificationTxs, setBulkIdentificationTxs] = useState<Transaction[] | null>(null);
    const [manualMatchState, setManualMatchState] = useState<{ record: MatchResult, suggestions: Transaction[] } | null>(null);
    const [divergenceConfirmation, setDivergenceConfirmation] = useState<MatchResult | null>(null);
    const [loadingAiId, setLoadingAiId] = useState<string | null>(null);
    const [aiSuggestion, setAiSuggestion] = useState<{ id: string, name: string } | null>(null);

    // --- LÓGICA DE LIMPEZA UNIFICADA ---
    // Combina palavras ignoradas globais com os Tipos de Contribuição.
    // Isso garante que "Dízimo", "Oferta", etc., sejam removidos da coluna NOME,
    // mas a detecção de TIPO (que ocorre no raw description) continua funcionando.
    const cleaningKeywords = useMemo(() => {
        return Array.from(new Set([...customIgnoreKeywords, ...contributionKeywords]));
    }, [customIgnoreKeywords, contributionKeywords]);

    const handleStatementUpload = useCallback((content: string, fileName: string, bankId: string, rawFile: File) => {
        setIsLoading(true);
        try {
            // ESTRATÉGIA DIRETA: Usa a lista combinada para limpar descrições
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            if (transactions.length > 0) {
                setBankStatementFile({ 
                    bankId, 
                    content, 
                    fileName, 
                    rawFile,
                    processedTransactions: transactions 
                });

                if (result.appliedModel) {
                    showToast("Um modelo de arquivo foi identificado automaticamente e aplicado com sucesso.", "success");
                } else {
                    showToast(`Extrato carregado (${result.method}).`, 'success');
                }

                // --- INTEGRATION: Consolidation Service ---
                if (user) {
                    const consolidationData = transactions.map(t => ({
                        transaction_date: t.date,
                        amount: t.amount,
                        description: t.description, // Raw description preferred for audit
                        type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                        pix_key: null, // Basic file upload typically does not parse PIX key separately yet
                        source: 'file' as 'file',
                        user_id: user.id
                    }));

                    // Fire and forget - Silent error handling (Avoid blocking UI if table is missing)
                    consolidationService.addTransactions(consolidationData)
                        .catch(err => console.warn("[Consolidation] Background sync skipped (DB Error/Offline):", err));
                }
                // ------------------------------------------

            } else {
                showToast("Formato de arquivo não reconhecido pelo sistema automático. Verifique se é um arquivo suportado.", "error");
            }
        } catch (e: any) {
            console.error(e);
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [setBankStatementFile, showToast, setIsLoading, fileModels, cleaningKeywords, user]);

    const handleContributorsUpload = useCallback((content: string, fileName: string, churchId: string, rawFile?: File) => {
        setIsLoading(true);
        try {
            // ESTRATÉGIA DIRETA: Usa a lista combinada para limpar nomes de contribuintes
            const result = processFileContent(content, fileName, fileModels, cleaningKeywords);
            const transactions = result.transactions;

            const contributors: Contributor[] = transactions.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            if (contributors.length > 0) {
                setContributorFiles(prev => {
                    const other = prev.filter(f => f.churchId !== churchId);
                    return [...other, { churchId, content, fileName, contributors }];
                });

                if (result.appliedModel) {
                    showToast("Um modelo de arquivo foi identificado automaticamente e aplicado com sucesso.", "success");
                } else {
                    showToast(`Lista carregada (${result.method}).`, 'success');
                }
            } else {
                showToast("Formato de lista não reconhecido. Use CSV ou Excel padronizado.", "error");
            }
        } catch (e: any) {
            showToast("Erro ao ler o arquivo: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [cleaningKeywords, setContributorFiles, showToast, setIsLoading, fileModels]);

    const handleTrainingSuccess = useCallback((model: FileModel, processedData: Transaction[]) => {
        if (!pendingTraining) return;

        const { type, entityId, content, fileName, rawFile } = pendingTraining;

        if (type === 'statement') {
            setBankStatementFile({ 
                bankId: entityId, 
                content, 
                fileName, 
                rawFile,
                processedTransactions: processedData 
            });
            showToast("Extrato processado e salvo!", "success");

            // --- INTEGRATION: Consolidation Service (Training Flow) ---
            if (user && processedData.length > 0) {
                const consolidationData = processedData.map(t => ({
                    transaction_date: t.date,
                    amount: t.amount,
                    description: t.description,
                    type: (t.amount >= 0 ? 'income' : 'expense') as 'income' | 'expense',
                    pix_key: null,
                    source: 'file' as 'file',
                    user_id: user.id
                }));
                consolidationService.addTransactions(consolidationData)
                    .catch(err => console.warn("[Consolidation] Background sync skipped:", err));
            }
            // ---------------------------------------------------------

        } else {
            const contributors: Contributor[] = processedData.map(t => ({
                name: t.description,
                cleanedName: t.cleanedDescription,
                normalizedName: normalizeString(t.description, cleaningKeywords),
                amount: t.amount,
                date: t.date,
                originalAmount: t.originalAmount,
                contributionType: t.contributionType
            }));

            setContributorFiles(prev => {
                const other = prev.filter(f => f.churchId !== entityId);
                return [...other, { churchId: entityId, content, fileName, contributors }];
            });
            showToast("Lista de contribuintes salva!", "success");
        }

        setPendingTraining(null);
    }, [pendingTraining, cleaningKeywords, setBankStatementFile, setContributorFiles, showToast, user]);

    const openLabManually = useCallback((targetFile?: { content: string, fileName: string, type: 'statement' | 'contributor', id: string, rawFile?: File }) => {
        if (targetFile) {
            setPendingTraining({
                content: targetFile.content,
                fileName: targetFile.fileName,
                type: targetFile.type,
                entityId: targetFile.id,
                rawFile: targetFile.rawFile
            });
        } else if (bankStatementFile) {
            setPendingTraining({
                content: bankStatementFile.content,
                fileName: bankStatementFile.fileName,
                type: 'statement',
                entityId: bankStatementFile.bankId,
                rawFile: bankStatementFile.rawFile
            });
        } else {
            showToast("Carregue um arquivo primeiro.", "error");
        }
    }, [bankStatementFile, showToast]);

    const removeBankStatementFile = useCallback(() => setBankStatementFile(null), [setBankStatementFile]);
    const removeContributorFile = useCallback((churchId: string) => {
        setContributorFiles(prev => prev.filter(f => f.churchId !== churchId));
    }, [setContributorFiles]);

    // Limpa apenas os arquivos (usado ao abrir um relatório salvo para evitar estado sujo)
    const clearFiles = useCallback(() => {
        setBankStatementFile(null);
        setContributorFiles([]);
    }, [setBankStatementFile, setContributorFiles]);

    // Função para limpar tudo e iniciar nova conciliação
    const resetReconciliation = useCallback(() => {
        setBankStatementFile(null);
        setContributorFiles([]);
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null); // Limpa o ID do relatório ativo
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
        setManualMatchState(null);
        setDivergenceConfirmation(null);
        setAiSuggestion(null);
        showToast("Ambiente limpo para nova conciliação.", "success");
    }, [setBankStatementFile, setContributorFiles, setMatchResults, setReportPreviewData, setHasActiveSession, showToast, setActiveReportId]);

    // --- RECONCILIATION ENGINE JIT (Just-In-Time) ---
    const handleCompare = useCallback(async () => {
        if (!bankStatementFile && !activeReportId) return; // Bloqueio padrão

        setIsLoading(true);

        try {
            let activeTransactions: Transaction[] = [];

            // 1. OBTENÇÃO DAS TRANSAÇÕES (Prioridade: Arquivo > Banco > Relatório)
            // Se houver arquivo carregado (Lista Viva), ele é a fonte da verdade para atualização
            if (bankStatementFile) {
                // Se já temos transações processadas no arquivo, usa elas
                if (bankStatementFile.processedTransactions && bankStatementFile.processedTransactions.length > 0) {
                    activeTransactions = bankStatementFile.processedTransactions;
                } else {
                    // Fallback para reprocessamento se necessário (raro)
                    const stmtResult = processFileContent(bankStatementFile.content, bankStatementFile.fileName, fileModels, cleaningKeywords);
                    activeTransactions = stmtResult.transactions;
                }
            } 
            // Se não tem arquivo mas está editando, tenta buscar do banco para garantir que temos "o que falta"
            else if (activeReportId && user) {
                try {
                    const dbTransactions = await consolidationService.getPendingTransactions(user.id);
                    activeTransactions = dbTransactions.map(dbTx => ({
                        id: dbTx.id,
                        date: dbTx.transaction_date,
                        amount: dbTx.amount,
                        description: dbTx.description,
                        cleanedDescription: dbTx.description,
                        contributionType: dbTx.type,
                        originalAmount: String(dbTx.amount)
                    }));
                } catch(e) {
                    // Fallback para o que está no matchResults não identificado se DB falhar
                    activeTransactions = matchResults
                        .filter(r => r.status === 'NÃO IDENTIFICADO')
                        .map(r => r.transaction);
                }
            }
            // Modo Offline/Visitante sem arquivo novo (usa o que tem no relatório)
            else if (activeReportId) {
                activeTransactions = matchResults
                    .filter(r => r.status === 'NÃO IDENTIFICADO')
                    .map(r => r.transaction);
            }

            if (activeTransactions.length === 0) {
                showToast("Não há transações pendentes para processar.", "error");
                return;
            }

            // Filtro por tipo (Entrada/Saída)
            let filteredTransactions = activeTransactions;
            if (comparisonType === 'income') filteredTransactions = activeTransactions.filter(t => t.amount > 0);
            else if (comparisonType === 'expenses') filteredTransactions = activeTransactions.filter(t => t.amount < 0);

            // 2. PROCESSAMENTO DAS LISTAS DE CONTRIBUINTES
            const contributorData = contributorFiles.map(cf => {
                const church = churches.find(c => c.id === cf.churchId) || PLACEHOLDER_CHURCH;
                // Otimização: Se já tiver contributors processados, não reprocessa
                if (cf.contributors && cf.contributors.length > 0) {
                    return { church, contributors: cf.contributors };
                }

                const listResult = processFileContent(cf.content, cf.fileName, fileModels, cleaningKeywords);
                const currentContributors = listResult.transactions.map(t => ({
                    name: t.description,
                    cleanedName: t.cleanedDescription,
                    normalizedName: normalizeString(t.description, cleaningKeywords),
                    amount: t.amount,
                    date: t.date,
                    originalAmount: t.originalAmount,
                    contributionType: t.contributionType
                }));

                return { church, contributors: currentContributors };
            });

            // 3. EXECUTAR O MATCHING (Novo Conjunto)
            const newResults = matchTransactions(
                filteredTransactions, 
                contributorData, 
                { similarityThreshold: similarityLevel, dayTolerance }, 
                learnedAssociations, 
                churches, 
                cleaningKeywords
            );

            // 4. ATUALIZAÇÃO DE ESTADO (MERGE vs OVERWRITE)
            if (activeReportId) {
                // MODO MERGE (Atualização de Relatório)
                setMatchResults(prevResults => {
                    const finalResults = [...prevResults];

                    newResults.forEach(newRes => {
                        // Tenta encontrar se essa transação já existe no relatório
                        const index = finalResults.findIndex(r => r.transaction.id === newRes.transaction.id);

                        if (index !== -1) {
                            const existing = finalResults[index];

                            // Regra de Merge:
                            // 1. Se o existente já foi identificado Manualmente, MANTER (não sobrescrever com auto)
                            if (existing.matchMethod === 'MANUAL' || existing.matchMethod === 'AI') {
                                return;
                            }

                            // 2. Se o novo achou um match e o antigo não tinha, ATUALIZAR
                            if (newRes.status === 'IDENTIFICADO' && existing.status !== 'IDENTIFICADO') {
                                finalResults[index] = newRes;
                            }
                            // 3. Se o novo tem sugestão melhor, ATUALIZAR
                            else if (newRes.suggestion && !existing.suggestion) {
                                finalResults[index] = newRes;
                            }
                        } else {
                            // Se não existe (transação nova da Lista Viva), ADICIONAR
                            finalResults.push(newRes);
                        }
                    });

                    setReportPreviewData({
                        income: groupResultsByChurch(finalResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                        expenses: { 'all_expenses_group': finalResults.filter(r => r.transaction.amount < 0) }
                    });
                    return finalResults;
                });
                showToast("Relatório atualizado com novos dados da Lista Viva!", 'success');
            } else {
                // MODO OVERWRITE (Novo Relatório)
                setMatchResults(newResults);
                setReportPreviewData({
                    income: groupResultsByChurch(newResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': newResults.filter(r => r.transaction.amount < 0) }
                });
                showToast("Conciliação finalizada!", 'success');
            }

            // 5. PERSISTÊNCIA DE MATCHES AUTOMÁTICOS
            if (user) {
                const autoMatches = newResults.filter(r => r.status === 'IDENTIFICADO' && r.transaction.id && !r.transaction.id.startsWith('ghost-'));
                if (autoMatches.length > 0) {
                    const updatePromises = autoMatches.map(m => 
                        consolidationService.markAsIdentified(m.transaction.id)
                            .catch(e => console.warn(`Falha ao persistir match automático ${m.transaction.id}`, e))
                    );
                    Promise.all(updatePromises).then(() => console.log(`[Consolidation] ${autoMatches.length} matches automáticos persistidos.`));
                }
            }

            setHasActiveSession(true);
            setActiveView('reports');

        } catch (e: any) {
            console.error(e);
            showToast(e.message || "Erro ao processar dados.", "error");
        } finally {
            setIsLoading(false);
        }
    }, [bankStatementFile, activeReportId, contributorFiles, churches, similarityLevel, dayTolerance, cleaningKeywords, learnedAssociations, setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, showToast, setIsLoading, comparisonType, setBankStatementFile, fileModels, matchResults, user]);

    const updateReportData = useCallback((updatedRow: MatchResult, reportType: 'income' | 'expenses', idToRemove?: string) => {
        // 1. Atualiza lista plana (MatchResults)
        setMatchResults(prev => {
            let next = prev;
            // Se tiver ID para remover (Transação Fantasma Pendente), remove antes
            if (idToRemove) {
                next = next.filter(r => r.transaction.id !== idToRemove);
            }
            return next.map(r => r.transaction.id === updatedRow.transaction.id ? updatedRow : r);
        });

        // 2. Atualiza dados agrupados (ReportPreview)
        setReportPreviewData(prev => {
            if (!prev) return null;
            const newPreview = JSON.parse(JSON.stringify(prev));
            const targetGroup = reportType === 'expenses' ? newPreview.expenses : newPreview.income;

            if (reportType === 'income') {
                // LÓGICA DE ENTRADAS (Income)
                // Remove o item de qualquer grupo onde ele esteja (tanto o ID real quanto o ID fantasma)
                // Isso evita duplicação ao mover de 'unidentified' ou 'pendente' para uma igreja específica
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].filter((r: MatchResult) => {
                        const isTarget = r.transaction.id === updatedRow.transaction.id;
                        const isGhost = idToRemove && r.transaction.id === idToRemove;
                        return !isTarget && !isGhost;
                    });
                });

                // Adiciona o item atualizado ao grupo correto
                const currentChurchId = updatedRow.church.id || 'unidentified';
                if (!newPreview.income[currentChurchId]) newPreview.income[currentChurchId] = [];
                newPreview.income[currentChurchId].push(updatedRow);

            } else {
                // LÓGICA DE SAÍDAS (Expenses) - Mantém comportamento padrão de atualização in-place
                Object.keys(targetGroup).forEach(key => {
                    targetGroup[key] = targetGroup[key].map((r: MatchResult) => 
                        r.transaction.id === updatedRow.transaction.id ? updatedRow : r
                    );
                });
            }

            return newPreview;
        });
    }, [setMatchResults, setReportPreviewData]);

    const discardCurrentReport = useCallback(() => {
        setMatchResults([]);
        setReportPreviewData(null);
        setHasActiveSession(false);
        setActiveReportId(null);
        setActiveView('upload');
    }, [setMatchResults, setReportPreviewData, setHasActiveSession, setActiveView, setActiveReportId]);

    const closeManualIdentify = useCallback(() => {
        setManualIdentificationTx(null);
        setBulkIdentificationTxs(null);
    }, []);

    const openManualMatchModal = useCallback((record: MatchResult) => {
        const suggestions = matchResults.map(r => r.transaction); 
        setManualMatchState({ record, suggestions });
    }, [matchResults]);

    const closeManualMatchModal = useCallback(() => setManualMatchState(null), []);

    const confirmManualAssociation = useCallback((selectedTx: Transaction) => {
        if (!manualMatchState) return;
        const { record } = manualMatchState;

        // Se o registro original era PENDENTE, significa que era uma transação fantasma da lista.
        // Precisamos capturar esse ID para removê-lo, pois ele será substituído pela transação real do banco.
        const ghostIdToRemove = record.status === 'PENDENTE' ? record.transaction.id : undefined;

        const updatedResult: MatchResult = {
            ...record,
            transaction: selectedTx,
            status: 'IDENTIFICADO',
            matchMethod: 'MANUAL',
            similarity: 100
        };

        updateReportData(updatedResult, 'income', ghostIdToRemove);
        closeManualMatchModal();
        showToast("Associação manual aplicada.", "success");
    }, [manualMatchState, updateReportData, closeManualMatchModal, showToast]);

    const openDivergenceModal = useCallback((match: MatchResult) => setDivergenceConfirmation(match), []);
    const closeDivergenceModal = useCallback(() => setDivergenceConfirmation(null), []);

    const confirmDivergence = useCallback((divergentMatch: MatchResult) => {
        updateReportData({ ...divergentMatch, status: 'IDENTIFICADO' }, 'income');
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const rejectDivergence = useCallback((divergentMatch: MatchResult) => {
        if (divergentMatch.divergence?.expectedChurch) {
             const restored: MatchResult = {
                 ...divergentMatch,
                 church: divergentMatch.divergence.expectedChurch,
                 status: 'IDENTIFICADO'
             };
             updateReportData(restored, 'income');
        } else {
             updateReportData({ ...divergentMatch, status: 'NÃO IDENTIFICADO', church: PLACEHOLDER_CHURCH, contributor: null }, 'income');
        }
        setDivergenceConfirmation(null);
    }, [updateReportData]);

    const handleAnalyze = useCallback(async (transaction: Transaction, contributors: Contributor[]) => {
        setLoadingAiId(transaction.id);
        setTimeout(() => {
            setAiSuggestion({ id: transaction.id, name: "Sugestão AI Simulada" });
            setLoadingAiId(null);
        }, 1500);
    }, []);

    return useMemo(() => ({
        bankStatementFile, contributorFiles, matchResults, setMatchResults, reportPreviewData, setReportPreviewData, hasActiveSession, setHasActiveSession,
        activeReportId, setActiveReportId, // EXPORTED
        pendingTraining, setPendingTraining, comparisonType, setComparisonType,
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, clearFiles, // EXPORTED
        handleCompare, updateReportData, discardCurrentReport, openLabManually,
        handleTrainingSuccess, resetReconciliation,
        manualIdentificationTx, setManualIdentificationTx,
        bulkIdentificationTxs, setBulkIdentificationTxs,
        closeManualIdentify,
        manualMatchState, setManualMatchState,
        openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, setDivergenceConfirmation,
        openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, setLoadingAiId, aiSuggestion, setAiSuggestion, handleAnalyze,
        setBankStatementFile // EXPORTED
    }), [
        bankStatementFile, contributorFiles, matchResults, reportPreviewData, hasActiveSession, activeReportId, pendingTraining, comparisonType, 
        handleStatementUpload, handleContributorsUpload, removeBankStatementFile, removeContributorFile, clearFiles, handleCompare, updateReportData, discardCurrentReport, openLabManually, handleTrainingSuccess,
        setMatchResults, setReportPreviewData, setHasActiveSession, setActiveReportId, resetReconciliation,
        manualIdentificationTx, bulkIdentificationTxs, closeManualIdentify,
        manualMatchState, openManualMatchModal, closeManualMatchModal, confirmManualAssociation,
        divergenceConfirmation, openDivergenceModal, closeDivergenceModal, confirmDivergence, rejectDivergence,
        loadingAiId, aiSuggestion, handleAnalyze, setBankStatementFile
    ]);
};

import React, { createContext, useState, useCallback, useMemo, useEffect } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReportManager } from '../hooks/useReportManager';
import { useReconciliation } from '../hooks/useReconciliation';
import { Bank, Church, Transaction, MatchResult, SavedReport, SearchFilters, SavingReportState, DeletingItem, FileModel, ComparisonType, GroupedReportData, Contributor, SpreadsheetData, LearnedAssociation } from '../types';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';
import { supabase } from '../services/supabaseClient';

interface AppContextType {
    // Reference Data
    banks: Bank[];
    churches: Church[];
    fileModels: FileModel[];
    fetchModels: () => Promise<void>;
    similarityLevel: number;
    setSimilarityLevel: (level: number) => void;
    dayTolerance: number;
    setDayTolerance: (days: number) => void;
    customIgnoreKeywords: string[];
    contributionKeywords: string[];
    addIgnoreKeyword: (k: string) => void;
    removeIgnoreKeyword: (k: string) => void;
    addContributionKeyword: (k: string) => void;
    removeContributionKeyword: (k: string) => void;

    // Bank/Church CRUD
    editingBank: Bank | null;
    openEditBank: (bank: Bank) => void;
    closeEditBank: () => void;
    updateBank: (id: string, name: string) => void;
    addBank: (name: string) => Promise<boolean>;
    editingChurch: Church | null;
    openEditChurch: (church: Church) => void;
    closeEditChurch: () => void;
    updateChurch: (id: string, data: any) => void;
    addChurch: (data: any) => Promise<boolean>;

    // Deletion
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;

    // Report Manager
    savedReports: SavedReport[];
    maxSavedReports: number;
    searchFilters: SearchFilters;
    setSearchFilters: React.Dispatch<React.SetStateAction<SearchFilters>>;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    clearSearchFilters: () => void;
    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => void;
    updateSavedReportName: (id: string, name: string) => void;
    saveFilteredReport: (results: MatchResult[]) => void;
    deleteOldReports: (date: Date) => void;
    allHistoricalResults: MatchResult[];
    viewSavedReport: (reportId: string) => Promise<void>;
    overwriteSavedReport: (reportId: string, results: MatchResult[], spreadsheetData?: SpreadsheetData) => Promise<void>;

    // Reconciliation
    bankStatementFile: any;
    contributorFiles: any[];
    matchResults: MatchResult[];
    setMatchResults: React.Dispatch<React.SetStateAction<MatchResult[]>>;
    reportPreviewData: { income: GroupedReportData; expenses: GroupedReportData } | null;
    setReportPreviewData: React.Dispatch<React.SetStateAction<{ income: GroupedReportData; expenses: GroupedReportData } | null>>;
    hasActiveSession: boolean;
    setHasActiveSession: React.Dispatch<React.SetStateAction<boolean>>;
    activeReportId: string | null;
    setActiveReportId: React.Dispatch<React.SetStateAction<string | null>>;
    comparisonType: ComparisonType;
    setComparisonType: (type: ComparisonType) => void;

    handleStatementUpload: (content: string, fileName: string, bankId: string, rawFile: File) => void;
    handleContributorsUpload: (content: string, fileName: string, churchId: string, rawFile?: File) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (churchId: string) => void;
    clearFiles: () => void;
    handleCompare: () => Promise<void>;
    updateReportData: (row: MatchResult, type: 'income'|'expenses', idToRemove?: string) => void;
    discardCurrentReport: () => void;
    resetReconciliation: () => void;

    // Manual ID
    manualIdentificationTx: Transaction | null;
    bulkIdentificationTxs: Transaction[] | null;
    openManualIdentify: (id: string) => void;
    closeManualIdentify: () => void;
    confirmManualIdentification: (txId: string, churchId: string) => void;
    confirmBulkManualIdentification: (txIds: string[], churchId: string) => void;

    // Manual Match (Suggestions)
    manualMatchState: { record: MatchResult, suggestions: Transaction[] } | null;
    openManualMatchModal: (record: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (tx: Transaction) => void;

    // Divergence
    divergenceConfirmation: MatchResult | null;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (match: MatchResult) => void;
    rejectDivergence: (match: MatchResult) => void;

    // Smart Edit
    smartEditTarget: MatchResult | null;
    openSmartEdit: (record: MatchResult) => void;
    closeSmartEdit: () => void;
    saveSmartEdit: (updatedRecord: MatchResult) => void;

    // AI / Learning
    loadingAiId: string | null;
    setLoadingAiId: (id: string | null) => void;
    aiSuggestion: { id: string, name: string } | null;
    setAiSuggestion: (s: { id: string, name: string } | null) => void;
    handleAnalyze: (tx: Transaction, contributors: Contributor[]) => void;
    learnAssociation: (match: MatchResult) => void;
    learnedAssociations: LearnedAssociation[];

    // Lab / Training
    pendingTraining: any;
    setPendingTraining: (data: any) => void;
    handleTrainingSuccess: (model: FileModel, data: Transaction[]) => void;
    openLabManually: (file?: any) => void;

    // Misc
    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;
    initialDataLoaded: boolean;
    effectiveIgnoreKeywords: string[];
    summary: any;
    isSyncing: boolean;
    handleGmailSyncSuccess: (txs: Transaction[]) => void;
    setBankStatementFile: any;

    // Update Files Modal
    isUpdateFilesModalOpen: boolean;
    openUpdateFilesModal: () => void;
    closeUpdateFilesModal: () => void;

    // Recompare Modal
    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    // Spreadsheet
    activeSpreadsheetData: SpreadsheetData | undefined;

    // compare status
    isCompareDisabled: boolean;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user } = useAuth();
    const { showToast, setIsLoading, setActiveView } = useUI();
    const [initialDataLoaded, setInitialDataLoaded] = useState(false);
    const [isSyncing, setIsSyncing] = useState(false);

    // Hooks Composition
    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    // Effective Keywords (Custom + Global if any) - For now just Custom + Contribution Types which is handled inside useReconciliation mostly via cleaningKeywords
    const effectiveIgnoreKeywords = useMemo(() => referenceData.customIgnoreKeywords, [referenceData.customIgnoreKeywords]);

    const reconciliation = useReconciliation({
        user,
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: referenceData.fileModels,
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: referenceData.customIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast,
        setIsLoading,
        setActiveView
    });

    // --- Deletion Logic ---
    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);

    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;
        const { type, id } = deletingItem;

        // ... deletion logic implementation based on type ...
        // Simplified for brevity, referencing previous logic pattern
        if (type === 'bank') {
             // ... logic using referenceData.setBanks ...
             const newBanks = referenceData.banks.filter(b => b.id !== id);
             referenceData.setBanks(newBanks);
             if (user) await supabase.from('banks').delete().eq('id', id);
             showToast('Banco excluído.', 'success');
        } else if (type === 'church') {
             const newChurches = referenceData.churches.filter(c => c.id !== id);
             referenceData.setChurches(newChurches);
             if (user) await supabase.from('churches').delete().eq('id', id);
             showToast('Igreja excluída.', 'success');
        } else if (type === 'report-saved') {
             const newReports = reportManager.savedReports.filter(r => r.id !== id);
             reportManager.setSavedReports(newReports);
             if (user) await supabase.from('saved_reports').delete().eq('id', id);
             showToast('Relatório excluído.', 'success');
        } else if (type === 'uploaded-files') {
             reconciliation.removeBankStatementFile();
             reconciliation.clearFiles(); // Clears all
             showToast('Arquivos removidos.', 'success');
        } else if (type === 'match-results') {
             reconciliation.setMatchResults([]);
             reconciliation.setReportPreviewData(null);
             reconciliation.setHasActiveSession(false);
             reconciliation.setActiveReportId(null);
             showToast('Resultados limpos.', 'success');
        } else if (type === 'learned-associations') {
             referenceData.setLearnedAssociations([]);
             if (user) await supabase.from('learned_associations').delete().eq('user_id', user.id);
             showToast('Associações aprendidas removidas.', 'success');
        } else if (type === 'all-data') {
             // Reset everything
             reconciliation.resetReconciliation();
             // Reset refs
             referenceData.setBanks([]);
             referenceData.setChurches([]);
             referenceData.setLearnedAssociations([]);
             // Reset reports
             reportManager.setSavedReports([]);

             if (user) {
                 // DB clean up calls (simplified)
                 await supabase.from('banks').delete().eq('user_id', user.id);
                 await supabase.from('churches').delete().eq('user_id', user.id);
                 await supabase.from('learned_associations').delete().eq('user_id', user.id);
                 await supabase.from('saved_reports').delete().eq('user_id', user.id);
             }
             showToast('Todos os dados foram apagados.', 'success');
        } else if (type === 'report-row') {
             // Manual deletion from report table
             reconciliation.updateReportData({ transaction: { id } } as any, (deletingItem.meta as any).reportType, id);
             showToast('Linha removida do relatório.', 'success');
        }

        closeDeleteConfirmation();
    }, [deletingItem, referenceData, reportManager, reconciliation, user, showToast]);

    // --- Manual Identification Logic ---
    const openManualIdentify = useCallback((id: string) => {
        const tx = reconciliation.matchResults.find(r => r.transaction.id === id)?.transaction;
        if (tx) reconciliation.setManualIdentificationTx(tx);
    }, [reconciliation.matchResults]);

    const confirmManualIdentification = useCallback((txId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        const result = reconciliation.matchResults.find(r => r.transaction.id === txId);

        if (church && result) {
            const updated: MatchResult = {
                ...result,
                status: 'IDENTIFICADO',
                church,
                matchMethod: 'MANUAL',
                similarity: 100,
                // Create manual contributor if needed or link logic
                contributor: { 
                    name: result.transaction.cleanedDescription || result.transaction.description, 
                    amount: result.transaction.amount, 
                    _churchId: churchId 
                } as Contributor
            };

            reconciliation.updateReportData(updated, 'income');
            referenceData.learnAssociation(updated);

            reconciliation.setManualIdentificationTx(null);
            showToast('Identificação manual confirmada.', 'success');
        }
    }, [referenceData.churches, reconciliation.matchResults, reconciliation.updateReportData, referenceData.learnAssociation, showToast]);

    const confirmBulkManualIdentification = useCallback((txIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        txIds.forEach(id => {
             const result = reconciliation.matchResults.find(r => r.transaction.id === id);
             if (result) {
                 const updated: MatchResult = {
                    ...result,
                    status: 'IDENTIFICADO',
                    church,
                    matchMethod: 'MANUAL',
                    similarity: 100,
                    contributor: { name: result.transaction.description, amount: result.transaction.amount } as Contributor
                 };
                 reconciliation.updateReportData(updated, 'income');
                 referenceData.learnAssociation(updated);
             }
        });

        reconciliation.setBulkIdentificationTxs(null);
        showToast(`${txIds.length} transações identificadas.`, 'success');
    }, [referenceData.churches, reconciliation.matchResults, reconciliation.updateReportData, referenceData.learnAssociation, showToast]);

    // --- Smart Edit ---
    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);
    const openSmartEdit = useCallback((record: MatchResult) => setSmartEditTarget(record), []);
    const closeSmartEdit = useCallback(() => setSmartEditTarget(null), []);
    const saveSmartEdit = useCallback((updated: MatchResult) => {
        reconciliation.updateReportData(updated, updated.transaction.amount >= 0 ? 'income' : 'expenses');
        // If identified, learn
        if (updated.status === 'IDENTIFICADO') {
            referenceData.learnAssociation(updated);
        }
        closeSmartEdit();
        showToast('Edição salva.', 'success');
    }, [reconciliation.updateReportData, referenceData.learnAssociation, closeSmartEdit, showToast]);

    // --- Payment Modal ---
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const openPaymentModal = useCallback(() => setIsPaymentModalOpen(true), []);
    const closePaymentModal = useCallback(() => setIsPaymentModalOpen(false), []);

    // --- Update Files Modal ---
    const [isUpdateFilesModalOpen, setIsUpdateFilesModalOpen] = useState(false);
    const openUpdateFilesModal = useCallback(() => setIsUpdateFilesModalOpen(true), []);
    const closeUpdateFilesModal = useCallback(() => setIsUpdateFilesModalOpen(false), []);

    // --- Recompare Modal ---
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);
    const openRecompareModal = useCallback(() => setIsRecompareModalOpen(true), []);
    const closeRecompareModal = useCallback(() => setIsRecompareModalOpen(false), []);

    // --- Load Saved Data (Initial) ---
    useEffect(() => {
        if (user) {
            const load = async () => {
                const { data } = await supabase.from('saved_reports').select('*').eq('user_id', user.id).order('created_at', { ascending: false });
                if (data) {
                    reportManager.setSavedReports(data.map(r => ({
                        id: r.id,
                        name: r.name,
                        createdAt: r.created_at,
                        recordCount: r.record_count,
                        user_id: r.user_id,
                        data: typeof r.data === 'string' ? JSON.parse(r.data) : r.data
                    })));
                }
                setInitialDataLoaded(true);
            };
            load();
        } else {
            setInitialDataLoaded(true);
        }
    }, [user]);

    // --- View Report Logic (Reconstructed) ---
    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            const report = reportManager.savedReports.find(r => r.id === reportId);
            if (!report) throw new Error("Relatório não encontrado.");

            let results: MatchResult[] = [];
            // If data is light (not stored in indexeddb fully or lazy loaded)
            if (!report.data || !report.data.results) {
                const { data, error } = await supabase.from('saved_reports').select('data').eq('id', reportId).single();
                if(error) throw error;
                const parsed = typeof data.data === 'string' ? JSON.parse(data.data) : data.data;
                results = parsed.results;
                // Update local cache structure if needed
                report.data = parsed; 
            } else {
                results = report.data.results;
            }

            const hydratedResults = results.map(r => {
                const cId = r.church?.id || (r as any)._churchId;
                const church = referenceData.churches.find(c => c.id === cId) || r.church || PLACEHOLDER_CHURCH;
                // Ensure hydration of contributor church too
                let contributor = r.contributor;
                if (contributor && !contributor.church) contributor = { ...contributor, church };

                return { ...r, church, contributor };
            });

            reconciliation.setMatchResults(hydratedResults);
            reconciliation.setReportPreviewData({
                income: groupResultsByChurch(hydratedResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                expenses: { 'all_expenses_group': hydratedResults.filter(r => r.transaction.amount < 0) }
            });
            reconciliation.setActiveReportId(reportId);
            reconciliation.setHasActiveSession(true);

            // REMOVIDO: reconciliation.clearFiles(); 
            // Motivo: Permitir que a "Lista Viva" (bankStatementFile) persista para updates/merges.

            setActiveView('reports');
            showToast(`Relatório "${report.name}" carregado.`, 'success');

        } catch (e: any) {
            console.error(e);
            showToast("Erro ao abrir relatório: " + e.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager.savedReports, referenceData.churches, reconciliation, setActiveView, showToast, setIsLoading]);

    // --- Gmail Sync Success Handler ---
    const handleGmailSyncSuccess = useCallback((txs: Transaction[]) => {
        // Logic to inject transactions into current context
        // Here we simulate uploading a virtual statement file
        const csvContent = txs.map(t => `${t.date};${t.description};${t.amount}`).join('\n');
        reconciliation.handleStatementUpload(csvContent, `Gmail Sync ${new Date().toLocaleDateString()}`, 'gmail-import', new File([csvContent], 'gmail.csv'));
    }, [reconciliation.handleStatementUpload]);

    // Summary calculation
    const summary = useMemo(() => {
        const identifiedCount = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO').length;
        const unidentifiedCount = reconciliation.matchResults.filter(r => r.status === 'NÃO IDENTIFICADO').length;
        const totalValue = reconciliation.matchResults.reduce((acc, r) => acc + r.transaction.amount, 0);

        const autoConfirmed = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod !== 'MANUAL');
        const manualConfirmed = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod === 'MANUAL');
        const pending = reconciliation.matchResults.filter(r => r.status === 'PENDENTE');

        const valuePerChurch = Object.entries(reconciliation.reportPreviewData?.income || {})
            .filter(([k]) => k !== 'unidentified')
            .map(([k, v]) => {
                const churchName = (v as MatchResult[])[0]?.church?.name || 'Desconhecida';
                const total = (v as MatchResult[]).reduce((sum, r) => sum + (r.transaction.amount || 0), 0);
                return [churchName, total] as [string, number];
            })
            .sort((a, b) => b[1] - a[1]);

        return {
            identifiedCount,
            unidentifiedCount,
            totalValue,
            autoConfirmed: { value: autoConfirmed.length },
            manualConfirmed: { value: manualConfirmed.length },
            pending: { value: pending.length },
            valuePerChurch,
            methodBreakdown: {
                AUTOMATIC: autoConfirmed.filter(r => r.matchMethod === 'AUTOMATIC').length,
                LEARNED: autoConfirmed.filter(r => r.matchMethod === 'LEARNED').length,
                AI: autoConfirmed.filter(r => r.matchMethod === 'AI').length,
                MANUAL: manualConfirmed.length
            },
            isHistorical: !!reconciliation.activeReportId
        };
    }, [reconciliation.matchResults, reconciliation.reportPreviewData, reconciliation.activeReportId]);

    const activeSpreadsheetData = useMemo(() => {
        if (!reconciliation.activeReportId) return undefined;
        const report = reportManager.savedReports.find(r => r.id === reconciliation.activeReportId);
        return report?.data?.spreadsheet;
    }, [reconciliation.activeReportId, reportManager.savedReports]);

    const value = useMemo(() => ({
        ...referenceData,
        ...reportManager,
        ...reconciliation,

        deletingItem, openDeleteConfirmation, closeDeleteConfirmation, confirmDeletion,

        openManualIdentify, closeManualIdentify, confirmManualIdentification, confirmBulkManualIdentification,

        smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit,

        isPaymentModalOpen, openPaymentModal, closePaymentModal,
        isUpdateFilesModalOpen, openUpdateFilesModal, closeUpdateFilesModal,
        isRecompareModalOpen, openRecompareModal, closeRecompareModal,

        initialDataLoaded,
        effectiveIgnoreKeywords,
        summary,
        isSyncing,
        handleGmailSyncSuccess,
        viewSavedReport,
        activeSpreadsheetData,
        isCompareDisabled: !reconciliation.bankStatementFile && !reconciliation.activeReportId
    }), [
        referenceData, reportManager, reconciliation,
        deletingItem, openDeleteConfirmation, closeDeleteConfirmation, confirmDeletion,
        openManualIdentify, closeManualIdentify, confirmManualIdentification, confirmBulkManualIdentification,
        smartEditTarget, openSmartEdit, closeSmartEdit, saveSmartEdit,
        isPaymentModalOpen, openPaymentModal, closePaymentModal,
        isUpdateFilesModalOpen, openUpdateFilesModal, closeUpdateFilesModal,
        isRecompareModalOpen, openRecompareModal, closeRecompareModal,
        initialDataLoaded, effectiveIgnoreKeywords, summary, isSyncing, handleGmailSyncSuccess, viewSavedReport, activeSpreadsheetData
    ]);

    return (
        <AppContext.Provider value={value}>
            {children}
        </AppContext.Provider>
    );
};

import React, { createContext, useState, useEffect, useMemo, useCallback } from 'react';
import { useAuth } from './AuthContext';
import { useUI } from './UIContext';
import { useReferenceData } from '../hooks/useReferenceData';
import { useReportManager } from '../hooks/useReportManager';
import { useReconciliation } from '../hooks/useReconciliation';
import { 
    Bank, Church, MatchResult, Transaction, 
    DeletingItem, SpreadsheetData, SavingReportState 
} from '../types';
import { supabase } from '../services/supabaseClient';
import { consolidationService } from '../services/ConsolidationService';
import { groupResultsByChurch, PLACEHOLDER_CHURCH } from '../services/processingService';

interface AppContextType {
    // Reference Data
    banks: Bank[];
    churches: Church[];
    fileModels: any[];
    similarityLevel: number;
    setSimilarityLevel: (val: number) => void;
    dayTolerance: number;
    setDayTolerance: (val: number) => void;
    customIgnoreKeywords: string[];
    addIgnoreKeyword: (k: string) => void;
    removeIgnoreKeyword: (k: string) => void;
    contributionKeywords: string[];
    addContributionKeyword: (k: string) => void;
    removeContributionKeyword: (k: string) => void;
    learnedAssociations: any[];
    learnAssociation: (match: MatchResult) => Promise<void>;

    editingBank: Bank | null;
    openEditBank: (b: Bank) => void;
    closeEditBank: () => void;
    updateBank: (id: string, name: string) => Promise<void>;
    addBank: (name: string) => Promise<boolean>;

    editingChurch: Church | null;
    openEditChurch: (c: Church) => void;
    closeEditChurch: () => void;
    updateChurch: (id: string, data: any) => Promise<void>;
    addChurch: (data: any) => Promise<boolean>;

    fetchModels: () => Promise<void>;

    // Report Manager
    savedReports: any[];
    maxSavedReports: number;
    searchFilters: any;
    setSearchFilters: (filters: any) => void;
    clearSearchFilters: () => void;
    isSearchFiltersOpen: boolean;
    openSearchFilters: () => void;
    closeSearchFilters: () => void;
    savingReportState: SavingReportState | null;
    openSaveReportModal: (state: SavingReportState) => void;
    closeSaveReportModal: () => void;
    confirmSaveReport: (name: string) => Promise<void>;
    updateSavedReportName: (id: string, name: string) => Promise<void>;
    saveFilteredReport: (results: MatchResult[]) => void;
    overwriteSavedReport: (id: string, results: MatchResult[], spreadsheet?: SpreadsheetData) => Promise<void>;
    deleteOldReports: (date: Date) => Promise<void>;
    allHistoricalResults: MatchResult[];

    // Reconciliation
    bankStatementFile: any;
    setBankStatementFile: (file: any) => void;
    contributorFiles: any[];
    matchResults: MatchResult[];
    setMatchResults: (results: MatchResult[]) => void;
    reportPreviewData: any;
    setReportPreviewData: (data: any) => void;
    hasActiveSession: boolean;
    setHasActiveSession: (active: boolean) => void;
    activeReportId: string | null;
    setActiveReportId: (id: string | null) => void;

    handleStatementUpload: (content: string, name: string, id: string, file: File) => void;
    handleContributorsUpload: (content: string, name: string, id: string, file?: File) => void;
    removeBankStatementFile: () => void;
    removeContributorFile: (id: string) => void;
    handleCompare: () => Promise<void>;
    updateReportData: (row: MatchResult, type: 'income' | 'expenses', idToRemove?: string) => void;
    resetReconciliation: () => void;
    isCompareDisabled: boolean;
    comparisonType: any;
    setComparisonType: (type: any) => void;

    // Manual Identification / Modals
    manualIdentificationTx: Transaction | null;
    bulkIdentificationTxs: Transaction[] | null;
    openManualIdentify: (id: string) => void;
    closeManualIdentify: () => void;
    confirmManualIdentification: (txId: string, churchId: string) => void;
    confirmBulkManualIdentification: (txIds: string[], churchId: string) => void;

    manualMatchState: any;
    openManualMatchModal: (record: MatchResult) => void;
    closeManualMatchModal: () => void;
    confirmManualAssociation: (tx: Transaction) => void;

    divergenceConfirmation: any;
    openDivergenceModal: (match: MatchResult) => void;
    closeDivergenceModal: () => void;
    confirmDivergence: (match: MatchResult) => void;
    rejectDivergence: (match: MatchResult) => void;

    // UI States
    initialDataLoaded: boolean;
    deletingItem: DeletingItem | null;
    openDeleteConfirmation: (item: DeletingItem) => void;
    closeDeleteConfirmation: () => void;
    confirmDeletion: () => void;

    isPaymentModalOpen: boolean;
    openPaymentModal: () => void;
    closePaymentModal: () => void;

    isRecompareModalOpen: boolean;
    openRecompareModal: () => void;
    closeRecompareModal: () => void;

    pendingTraining: any;
    setPendingTraining: (val: any) => void;
    handleTrainingSuccess: (model: any, data: any) => void;
    openLabManually: (file?: any) => void;

    smartEditTarget: MatchResult | null;
    openSmartEdit: (target: MatchResult) => void;
    closeSmartEdit: () => void;
    saveSmartEdit: (updated: MatchResult) => void;

    isUpdateFilesModalOpen: boolean;
    openUpdateFilesModal: () => void;
    closeUpdateFilesModal: () => void;

    isSyncing: boolean;

    // View Saved Report
    viewSavedReport: (id: string) => Promise<void>;
    activeSpreadsheetData: SpreadsheetData | null;
    setActiveSpreadsheetData: (data: SpreadsheetData | null) => void;

    summary: any;

    loadingAiId: string | null;
    handleAnalyze: (tx: Transaction, contributors: any[]) => void;
    aiSuggestion: any;

    handleGmailSyncSuccess: (transactions: Transaction[]) => void;

    effectiveIgnoreKeywords: string[];
    saveCurrentReportChanges: () => void;

    undoIdentification: (transactionId: string) => void;
    findMatchResult: (transactionId: string) => MatchResult | undefined;
}

export const AppContext = createContext<AppContextType>(null!);

export const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
    const { user } = useAuth();
    const { showToast, setIsLoading, setActiveView } = useUI();
    const [initialDataLoaded, setInitialDataLoaded] = useState(false);

    // UI State for Modals
    const [deletingItem, setDeletingItem] = useState<DeletingItem | null>(null);
    const [isPaymentModalOpen, setIsPaymentModalOpen] = useState(false);
    const [isRecompareModalOpen, setIsRecompareModalOpen] = useState(false);
    const [smartEditTarget, setSmartEditTarget] = useState<MatchResult | null>(null);
    const [isUpdateFilesModalOpen, setIsUpdateFilesModalOpen] = useState(false);
    const [activeSpreadsheetData, setActiveSpreadsheetData] = useState<SpreadsheetData | null>(null);
    const [isSyncing, setIsSyncing] = useState(false);

    // --- Hooks ---
    const referenceData = useReferenceData(user, showToast);
    const reportManager = useReportManager(user, showToast);

    const reconciliation = useReconciliation({
        user,
        churches: referenceData.churches,
        banks: referenceData.banks,
        fileModels: referenceData.fileModels,
        similarityLevel: referenceData.similarityLevel,
        dayTolerance: referenceData.dayTolerance,
        customIgnoreKeywords: referenceData.customIgnoreKeywords,
        contributionKeywords: referenceData.contributionKeywords,
        learnedAssociations: referenceData.learnedAssociations,
        showToast,
        setIsLoading,
        setActiveView
    });

    // --- Derived State ---
    const effectiveIgnoreKeywords = useMemo(() => referenceData.customIgnoreKeywords, [referenceData.customIgnoreKeywords]);

    // --- FETCH DE DADOS E HIDRATAÇÃO ---
    // Estratégia de "Fail-Safe": Carrega o essencial primeiro. Se a Lista Viva falhar (tabela não existe), não quebra o resto.
    useEffect(() => {
        if (!user) {
            setInitialDataLoaded(true);
            return;
        }

        const fetchData = async () => {
            setIsSyncing(true);
            try {
                // 1. DADOS ESSENCIAIS (Bancos, Igrejas, Relatórios)
                // Usamos Promise.allSettled para que falha em um não trave os outros
                const [churchesRes, banksRes, reportsRes] = await Promise.all([
                    supabase.from('churches').select('*').order('name'),
                    supabase.from('banks').select('*').order('name'),
                    supabase.from('saved_reports')
                        .select('id, name, created_at, record_count, user_id') 
                        .eq('user_id', user.id)
                        .order('created_at', { ascending: false }),
                ]);

                // Aplica dados que vieram com sucesso
                if (churchesRes.data) referenceData.setChurches(churchesRes.data as any);
                if (banksRes.data) referenceData.setBanks(banksRes.data as any);
                if (reportsRes.data) {
                    reportManager.setSavedReports((reportsRes.data || []).map(r => ({ 
                        id: r.id, 
                        name: r.name, 
                        createdAt: r.created_at, 
                        recordCount: r.record_count, 
                        user_id: r.user_id, 
                        data: null 
                    })));
                }

                // 2. TENTATIVA DE RECUPERAÇÃO DA LISTA VIVA (Isolado em try/catch)
                // Se a tabela consolidated_transactions não existir (404), isso falha silenciosamente
                // sem impedir que o resto do app funcione.
                try {
                    const pendingTxs = await consolidationService.getPendingTransactions(user.id);

                    if (pendingTxs && pendingTxs.length > 0) {
                        console.log(`[Hydration] Recuperando ${pendingTxs.length} transações vivas do banco.`);

                        const liveTransactions = pendingTxs.map(dbTx => ({
                            id: dbTx.id,
                            date: dbTx.transaction_date,
                            amount: dbTx.amount,
                            description: dbTx.description,
                            cleanedDescription: dbTx.description, 
                            contributionType: dbTx.type,
                            originalAmount: String(dbTx.amount)
                        }));

                        const virtualContent = liveTransactions
                            .map(t => `${t.date};${t.description};${t.amount};${t.contributionType}`)
                            .join('\n');

                        const targetBankId = banksRes.data && banksRes.data.length > 0 ? banksRes.data[0].id : 'active-session-bank';

                        reconciliation.setBankStatementFile({
                            bankId: targetBankId,
                            content: virtualContent,
                            fileName: 'Sessão Ativa (Nuvem)',
                            processedTransactions: liveTransactions as Transaction[],
                            rawFile: undefined 
                        });

                        if (reconciliation.matchResults.length === 0) {
                            const mappedResults: MatchResult[] = liveTransactions.map(tx => ({
                                transaction: tx as Transaction,
                                contributor: null,
                                status: 'NÃO IDENTIFICADO',
                                church: PLACEHOLDER_CHURCH,
                                matchMethod: undefined,
                                similarity: 0
                            }));

                            reconciliation.setMatchResults(mappedResults);
                            reconciliation.setReportPreviewData({
                                income: groupResultsByChurch(mappedResults),
                                expenses: { 'all_expenses_group': [] }
                            });

                            reconciliation.setHasActiveSession(true);
                        }
                    }
                } catch (dbError) {
                    console.warn("[Hydration] Falha ao carregar Lista Viva (Tabela pode não existir ainda):", dbError);
                    // Não faz nada, permite que o app carregue sem a lista viva
                }

            } catch (err) { 
                console.error('Critical sync failed', err); 
            } finally { 
                setIsSyncing(false); 
                setInitialDataLoaded(true); // Garante que a tela de loading saia
            }
        };

        fetchData();
    }, [user?.id]);

    // --- Actions ---

    const openDeleteConfirmation = useCallback((item: DeletingItem) => setDeletingItem(item), []);
    const closeDeleteConfirmation = useCallback(() => setDeletingItem(null), []);

    const confirmDeletion = useCallback(async () => {
        if (!deletingItem) return;

        try {
            switch(deletingItem.type) {
                case 'bank':
                    referenceData.setBanks(prev => prev.filter(b => b.id !== deletingItem.id));
                    if (user) await supabase.from('banks').delete().eq('id', deletingItem.id);
                    break;
                case 'church':
                    referenceData.setChurches(prev => prev.filter(c => c.id !== deletingItem.id));
                    if (user) await supabase.from('churches').delete().eq('id', deletingItem.id);
                    break;
                case 'report-saved':
                    reportManager.setSavedReports(prev => prev.filter(r => r.id !== deletingItem.id));
                    if (user) await supabase.from('saved_reports').delete().eq('id', deletingItem.id);
                    break;
                case 'report-row':
                    reconciliation.setMatchResults(prev => prev.filter(r => r.transaction.id !== deletingItem.id));
                    const newResults = reconciliation.matchResults.filter(r => r.transaction.id !== deletingItem.id);
                    reconciliation.setReportPreviewData({
                        income: groupResultsByChurch(newResults.filter(r => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                        expenses: { 'all_expenses_group': newResults.filter(r => r.transaction.amount < 0) }
                    });
                    break;
                case 'uploaded-files':
                    reconciliation.clearFiles();
                    break;
                case 'match-results':
                    reconciliation.setMatchResults([]);
                    reconciliation.setReportPreviewData(null);
                    reconciliation.setHasActiveSession(false);
                    reconciliation.setActiveReportId(null);
                    break;
                case 'learned-associations':
                    referenceData.setLearnedAssociations([]);
                    if (user) await supabase.from('learned_associations').delete().eq('user_id', user.id);
                    break;
                case 'all-data':
                    // Reset everything
                    referenceData.setBanks([]);
                    referenceData.setChurches([]);
                    referenceData.setLearnedAssociations([]);
                    reconciliation.resetReconciliation();
                    if (user) {
                        await supabase.from('banks').delete().eq('user_id', user.id);
                        await supabase.from('churches').delete().eq('user_id', user.id);
                        await supabase.from('learned_associations').delete().eq('user_id', user.id);
                    }
                    break;
            }
            showToast("Item excluído com sucesso.", "success");
        } catch (e) {
            console.error(e);
            showToast("Erro ao excluir item.", "error");
        } finally {
            setDeletingItem(null);
        }
    }, [deletingItem, referenceData, reportManager, reconciliation, user, showToast]);

    // Manual Identification
    const openManualIdentify = useCallback((id: string) => {
        const result = reconciliation.matchResults.find(r => r.transaction.id === id);
        if (result) {
            reconciliation.setManualIdentificationTx(result.transaction);
        }
    }, [reconciliation.matchResults, reconciliation.setManualIdentificationTx]);

    const confirmManualIdentification = useCallback(async (txId: string, churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        const result = reconciliation.matchResults.find(r => r.transaction.id === txId);
        if (result) {
            const updated: MatchResult = {
                ...result,
                status: 'IDENTIFICADO',
                church,
                matchMethod: 'MANUAL',
                similarity: 100
            };
            reconciliation.updateReportData(updated, 'income');

            // Learn association
            await referenceData.learnAssociation(updated);

            // Update DB (Safe Fire-and-Forget)
            try {
                await consolidationService.markAsIdentified(txId);
            } catch (e) { console.warn("Failed to mark as identified in DB", e); }

            reconciliation.setManualIdentificationTx(null);
            showToast("Identificação manual realizada e aprendida.", "success");
        }
    }, [reconciliation, referenceData, showToast]);

    const confirmBulkManualIdentification = useCallback((txIds: string[], churchId: string) => {
        const church = referenceData.churches.find(c => c.id === churchId);
        if (!church) return;

        txIds.forEach(id => {
            const result = reconciliation.matchResults.find(r => r.transaction.id === id);
            if (result) {
                const updated: MatchResult = {
                    ...result,
                    status: 'IDENTIFICADO',
                    church,
                    matchMethod: 'MANUAL',
                    similarity: 100
                };
                reconciliation.updateReportData(updated, 'income');
                referenceData.learnAssociation(updated);
                // Update DB
                consolidationService.markAsIdentified(id).catch(() => {});
            }
        });

        reconciliation.setBulkIdentificationTxs(null);
        showToast(`${txIds.length} transações identificadas em massa.`, "success");
    }, [reconciliation, referenceData, showToast]);

    const saveCurrentReportChanges = useCallback(() => {
        if (reconciliation.activeReportId) {
            reportManager.overwriteSavedReport(reconciliation.activeReportId, reconciliation.matchResults);
        }
    }, [reconciliation.activeReportId, reconciliation.matchResults, reportManager]);

    // View Saved Report Logic
    const viewSavedReport = useCallback(async (reportId: string) => {
        setIsLoading(true);
        try {
            let report = reportManager.savedReports.find(r => r.id === reportId);

            if (!report) {
                const { data: dbReport, error } = await supabase.from('saved_reports').select('*').eq('id', reportId).single();
                if (error || !dbReport) throw new Error("Relatório não encontrado.");

                const parsedData = typeof dbReport.data === 'string' ? JSON.parse(dbReport.data as string) : dbReport.data;
                report = {
                    id: dbReport.id,
                    name: dbReport.name,
                    createdAt: dbReport.created_at,
                    recordCount: dbReport.record_count,
                    user_id: dbReport.user_id,
                    data: parsedData
                };
            } else if (!report.data) {
                const { data: reportContent, error } = await supabase
                    .from('saved_reports')
                    .select('data')
                    .eq('id', reportId)
                    .single();

                if (error) throw error;

                if (reportContent) {
                    const parsedData = typeof reportContent.data === 'string' 
                        ? JSON.parse(reportContent.data) 
                        : reportContent.data;

                    report = { ...report, data: parsedData };
                    reportManager.setSavedReports(prev => prev.map(r => r.id === reportId ? { ...r, data: parsedData } : r));
                }
            }

            if (!report || !report.data) throw new Error("Conteúdo do relatório vazio.");

            reconciliation.clearFiles();
            setActiveSpreadsheetData(null);

            if (report.data.spreadsheet) {
                setActiveSpreadsheetData(report.data.spreadsheet);
                reconciliation.setActiveReportId(reportId);
                setActiveView('smart_analysis');
                showToast(`Planilha "${report.name}" carregada.`, "success");
            } else {
                // Live List Logic
                let livePendingTransactions: Transaction[] = [];
                if (user) {
                    try {
                        const pendingDb = await consolidationService.getPendingTransactions(user.id);
                        if (pendingDb) {
                            livePendingTransactions = pendingDb.map(tx => ({
                                id: tx.id,
                                date: tx.transaction_date,
                                amount: tx.amount,
                                description: tx.description,
                                cleanedDescription: tx.description,
                                contributionType: tx.type,
                                originalAmount: String(tx.amount)
                            }));
                        }
                    } catch (dbError) {
                        console.warn("Offline or DB Error getting live pending transactions:", dbError);
                    }
                }

                const savedIdentifiedResults = report.data.results
                    .filter((r: any) => r.status === 'IDENTIFICADO' || r.status === 'RESOLVED')
                    .map((r: any) => ({ 
                        ...r, 
                        church: r.church || referenceData.churches.find(c => c.id === r._churchId) || PLACEHOLDER_CHURCH 
                    }));

                const livePendingResults: MatchResult[] = livePendingTransactions.map(tx => ({
                    transaction: tx,
                    contributor: null,
                    status: 'NÃO IDENTIFICADO',
                    church: PLACEHOLDER_CHURCH,
                    matchMethod: undefined,
                    similarity: 0
                }));

                const combinedResults = [...savedIdentifiedResults, ...livePendingResults];

                reconciliation.setMatchResults(combinedResults);
                reconciliation.setReportPreviewData({
                    income: groupResultsByChurch(combinedResults.filter((r: any) => r.transaction.amount > 0 || r.status === 'PENDENTE')),
                    expenses: { 'all_expenses_group': combinedResults.filter((r: any) => r.transaction.amount < 0) }
                });

                reconciliation.setHasActiveSession(true); 
                reconciliation.setActiveReportId(reportId); 
                setActiveView('reports'); 

                if (livePendingTransactions.length > 0) {
                    showToast(`Relatório "${report.name}" carregado com Lista Viva atualizada.`, "success");
                } else {
                    showToast(`Relatório "${report.name}" carregado (Histórico).`, "success");
                }
            }

        } catch (error: any) {
            console.error(error);
            showToast("Erro ao abrir relatório: " + error.message, "error");
        } finally {
            setIsLoading(false);
        }
    }, [reportManager, reconciliation, setActiveView, setIsLoading, showToast, user, referenceData.churches]);

    const handleGmailSyncSuccess = useCallback((transactions: Transaction[]) => {
        if (reconciliation.bankStatementFile) {
            reconciliation.setBankStatementFile(prev => {
                if (!prev) return null;
                return {
                    ...prev,
                    processedTransactions: [...(prev.processedTransactions || []), ...transactions]
                };
            });
            setTimeout(() => reconciliation.handleCompare(), 500);
        } else {
            const csvContent = ""; 
            const virtualFile = new File([csvContent], "gmail_import.csv", { type: "text/csv" });
            reconciliation.setBankStatementFile({
                bankId: 'gmail',
                content: csvContent,
                fileName: 'Importação Gmail',
                rawFile: virtualFile,
                processedTransactions: transactions
            });
            setTimeout(() => reconciliation.handleCompare(), 500);
        }
    }, [reconciliation]);

    const undoIdentification = useCallback(async (transactionId: string) => {
        const result = reconciliation.matchResults.find(r => r.transaction.id === transactionId);
        if (result && result.status === 'IDENTIFICADO') {
            reconciliation.updateReportData({
                ...result,
                status: 'NÃO IDENTIFICADO',
                church: PLACEHOLDER_CHURCH,
                contributor: null,
                matchMethod: undefined,
                similarity: 0
            }, 'income');

            // Revert DB status
            try {
                await consolidationService.markAsPending(transactionId);
            } catch(e) { console.warn("Failed to revert status in DB", e); }

            showToast("Identificação desfeita.", "success");
        }
    }, [reconciliation, showToast]);

    const findMatchResult = useCallback((id: string) => {
        return reconciliation.matchResults.find(r => r.transaction.id === id);
    }, [reconciliation.matchResults]);

    const summary = useMemo(() => {
        const total = reconciliation.matchResults.length;
        const identifiedCount = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO').length;
        const unidentifiedCount = reconciliation.matchResults.filter(r => r.status === 'NÃO IDENTIFICADO' || r.status === 'PENDENTE').length;

        const auto = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod !== 'MANUAL');
        const manual = reconciliation.matchResults.filter(r => r.status === 'IDENTIFICADO' && r.matchMethod === 'MANUAL');
        const pending = reconciliation.matchResults.filter(r => r.status === 'NÃO IDENTIFICADO' || r.status === 'PENDENTE');

        const totalValue = reconciliation.matchResults.reduce((acc, r) => acc + (r.transaction.amount || 0), 0);

        const churchMap = new Map<string, number>();
        reconciliation.matchResults.forEach(r => {
            if (r.status === 'IDENTIFICADO' && r.church && r.church.id !== 'unidentified') {
                const current = churchMap.get(r.church.name) || 0;
                churchMap.set(r.church.name, current + (r.contributorAmount || r.transaction.amount));
            }
        });
        const valuePerChurch = Array.from(churchMap.entries()).sort((a, b) => b[1] - a[1]).slice(0, 5);

        const methodBreakdown = {
            AUTOMATIC: reconciliation.matchResults.filter(r => r.matchMethod === 'AUTOMATIC').length,
            MANUAL: reconciliation.matchResults.filter(r => r.matchMethod === 'MANUAL').length,
            LEARNED: reconciliation.matchResults.filter(r => r.matchMethod === 'LEARNED').length,
            AI: reconciliation.matchResults.filter(r => r.matchMethod === 'AI').length
        };

        return {
            total,
            identifiedCount,
            unidentifiedCount,
            autoConfirmed: { count: auto.length, value: auto.reduce((s, r) => s + (r.transaction.amount || 0), 0) },
            manualConfirmed: { count: manual.length, value: manual.reduce((s, r) => s + (r.transaction.amount || 0), 0) },
            pending: { count: pending.length, value: pending.reduce((s, r) => s + (r.transaction.amount || 0), 0) },
            totalValue,
            valuePerChurch,
            methodBreakdown,
            isHistorical: !!reconciliation.activeReportId
        };
    }, [reconciliation.matchResults, reconciliation.activeReportId]);

    const openSmartEdit = useCallback((target: MatchResult) => setSmartEditTarget(target), []);
    const closeSmartEdit = useCallback(() => setSmartEditTarget(null), []);
    const saveSmartEdit = useCallback(async (updated: MatchResult) => {
        reconciliation.updateReportData(updated, 'income');
        if (updated.status === 'IDENTIFICADO') {
            await referenceData.learnAssociation(updated);
            // Update DB
            consolidationService.markAsIdentified(updated.transaction.id).catch(() => {});
        }
        setSmartEditTarget(null);
        showToast("Registro atualizado com sucesso.", "success");
    }, [reconciliation, referenceData, showToast]);

    const contextValue: AppContextType = {
        ...referenceData,
        ...reportManager,
        ...reconciliation,

        initialDataLoaded,
        deletingItem,
        openDeleteConfirmation,
        closeDeleteConfirmation,
        confirmDeletion,

        isPaymentModalOpen,
        openPaymentModal: () => setIsPaymentModalOpen(true),
        closePaymentModal: () => setIsPaymentModalOpen(false),

        isRecompareModalOpen,
        openRecompareModal: () => setIsRecompareModalOpen(true),
        closeRecompareModal: () => setIsRecompareModalOpen(false),

        manualIdentificationTx: reconciliation.manualIdentificationTx,
        bulkIdentificationTxs: reconciliation.bulkIdentificationTxs,
        openManualIdentify, 
        closeManualIdentify: reconciliation.closeManualIdentify,
        confirmManualIdentification,
        confirmBulkManualIdentification,

        smartEditTarget,
        openSmartEdit,
        closeSmartEdit,
        saveSmartEdit,

        isUpdateFilesModalOpen,
        openUpdateFilesModal: () => setIsUpdateFilesModalOpen(true),
        closeUpdateFilesModal: () => setIsUpdateFilesModalOpen(false),

        isSyncing,
        viewSavedReport,
        activeSpreadsheetData,
        setActiveSpreadsheetData,
        summary,
        effectiveIgnoreKeywords,
        saveCurrentReportChanges,
        handleGmailSyncSuccess,
        undoIdentification,
        findMatchResult
    };

    return (
        <AppContext.Provider value={contextValue}>
            {children}
        </AppContext.Provider>
    );
};

