### 2. SQL de Correção (Necessário)

O erro 404 que você viu antes (`Failed to load resource ... admin_config`) é porque as tabelas do banco de dados ainda não existem.

1.  Vá ao **Supabase Dashboard** > **SQL Editor**.
2.  Cole e execute o seguinte script para criar as tabelas faltantes. Isso é seguro e não apaga dados existentes.

```sql
-- TABELA 1: Configurações Administrativas
CREATE TABLE IF NOT EXISTS public.admin_config (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    key TEXT UNIQUE NOT NULL,
    value JSONB NOT NULL,
    updated_at TIMESTAMPTZ DEFAULT NOW()
);

-- TABELA 2: Transações Consolidadas (Lista Viva)
CREATE TABLE IF NOT EXISTS public.consolidated_transactions (
    id UUID DEFAULT gen_random_uuid() PRIMARY KEY,
    created_at TIMESTAMPTZ DEFAULT NOW(),
    transaction_date DATE NOT NULL,
    amount NUMERIC(12, 2) NOT NULL,
    description TEXT NOT NULL,
    type TEXT CHECK (type IN ('income', 'expense')) NOT NULL,
    pix_key TEXT,
    source TEXT CHECK (source IN ('file', 'gmail')) NOT NULL,
    user_id UUID REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL,
    status TEXT CHECK (status IN ('pending', 'identified', 'resolved')) DEFAULT 'pending'
);

-- Índices para performance
CREATE INDEX IF NOT EXISTS idx_consolidated_user_date ON public.consolidated_transactions(user_id, transaction_date);
CREATE INDEX IF NOT EXISTS idx_consolidated_status ON public.consolidated_transactions(status);

-- Habilitar RLS (Segurança)
ALTER TABLE public.admin_config ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.consolidated_transactions ENABLE ROW LEVEL SECURITY;

-- Políticas de Segurança (Se não existirem)
DO $$ 
BEGIN
    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename = 'admin_config' AND policyname = 'Public Read Admin Config') THEN
        CREATE POLICY "Public Read Admin Config" ON public.admin_config FOR SELECT USING (true);
    END IF;

    IF NOT EXISTS (SELECT 1 FROM pg_policies WHERE tablename = 'consolidated_transactions' AND policyname = 'Users can manage their own transactions') THEN
        CREATE POLICY "Users can manage their own transactions" ON public.consolidated_transactions FOR ALL USING (auth.uid() = user_id);
    END IF;
END $$;
